-- Poems batch 448
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-3','過盧秦卿舊居','司空曙','唐','御定全唐诗','yuding','','[]','五柳茅茨楚國賢，桔槔蔬圃水涓涓。黃花寒後難逢蝶。',64,'御定全唐詩/json/293.json','["五柳茅茨楚國賢，桔槔蔬圃水涓涓。黃花寒後難逢蝶。", "紅葉晴來忽有蟬。韓康助采君臣藥，支遁同看內外篇。", "為問潛夫空著論，如何侍從賦甘泉。"]'),
('yuding-4','秋園','司空曙','唐','御定全唐诗','yuding','','[]','傷秋不是惜年華，別憶春風碧玉家。',32,'御定全唐詩/json/293.json','["傷秋不是惜年華，別憶春風碧玉家。", "強向衰叢見芳意，茱萸紅實似繁花。"]'),
('yuding-5','送王使君赴太原拜節度副使','司空曙','唐','御定全唐诗','yuding','','[]','新從劉太尉，結束向並州。絡腦青絲騎，盤囊錦帶鉤。',72,'御定全唐詩/json/293.json','["新從劉太尉，結束向並州。絡腦青絲騎，盤囊錦帶鉤。", "出關逢將校，下嶺擁戈矛。匣閉黃雲冷，山傳畫角秋。", "劍鋒將破虜，函道罷登樓。豈作書生老，當封萬戶侯。"]'),
('yuding-6','擬百勞歌','司空曙','唐','御定全唐诗','yuding','','[]','朱絲紐弦金點雜，雙蒂芙蓉共開合。誰家稚女著羅裳，',48,'御定全唐詩/json/293.json','["朱絲紐弦金點雜，雙蒂芙蓉共開合。誰家稚女著羅裳，", "玉顏年幾新上頭，回身斂笑多自羞。紅銷月落不復見，"]'),
('yuding-7','迎神','司空曙','唐','御定全唐诗','yuding','','[]','吉日兮臨水，沐青蘭兮白芷。假山鬼兮請東皇，',45,'御定全唐詩/json/293.json','["吉日兮臨水，沐青蘭兮白芷。假山鬼兮請東皇，", "鸞旌圓蓋望欲來，山雨霏霏江浪起。神既降兮我獨知，"]'),
('yuding-8','送神','司空曙','唐','御定全唐诗','yuding','','[]','神之去，回風嫋嫋雲容與。桂尊瑤席不復陳，',20,'御定全唐詩/json/293.json','["神之去，回風嫋嫋雲容與。桂尊瑤席不復陳，"]'),
('yuding-9','殘鶯百囀歌同王員外耿拾遺吉中孚李端遊慈恩各賦一物','司空曙','唐','御定全唐诗','yuding','','[]','殘鶯一何怨，百囀相尋續。始辨下將高，稍分長複促。',120,'御定全唐詩/json/293.json','["殘鶯一何怨，百囀相尋續。始辨下將高，稍分長複促。", "綿蠻巧狀語，機節終如曲。野客賞應遲，幽僧聞詎足。", "禪齋深樹夏陰清，零落空餘三兩聲。金穀箏中傳不似，", "送暖初隨柳色來，辭芳暗逐花枝盡。歌殘鶯，歌殘鶯，", "乃知眾鳥非儔比，暮噪晨鳴倦人耳。共愛奇音那可親，"]'),
('yuding-10','過終南柳處士','司空曙','唐','御定全唐诗','yuding','','[]','雲起山蒼蒼，林居蘿薜荒。幽人老深境，素發與青裳。',72,'御定全唐詩/json/293.json','["雲起山蒼蒼，林居蘿薜荒。幽人老深境，素發與青裳。", "雨滌莓苔綠，風搖松桂香。洞泉分溜淺，岩筍出叢長。", "敗屨安松砌，餘棋在石床。書名一為別，還路已堪傷。"]'),
('yuding-11','春送郭大之官','司空曙','唐','御定全唐诗','yuding','','[]','明府之官官舍春，春風辭我兩三人。',32,'御定全唐詩/json/293.json','["明府之官官舍春，春風辭我兩三人。", "可憐江縣閑無事，手板支頤獨詠貧。"]'),
('yuding-12','送鄭錫','司空曙','唐','御定全唐诗','yuding','','[]','漢陽雲樹清無極，蜀國風煙思不堪。',32,'御定全唐詩/json/293.json','["漢陽雲樹清無極，蜀國風煙思不堪。", "莫怪別君偏有淚，十年曾事晉征南。"]'),
('yuding-13','同張參軍喜李尚書寄新琴','司空曙','唐','御定全唐诗','yuding','','[]','新琴傳鳳凰，晴景稱高張。白玉連徽淨，朱絲系爪長。',72,'御定全唐詩/json/293.json','["新琴傳鳳凰，晴景稱高張。白玉連徽淨，朱絲系爪長。", "輕埃隨拂拭，雜籟滿鏗鏘。暗想山泉合，如親蘭蕙芳。", "正聲消鄭衛，古狀掩笙簧。遠識賢人意，清風願激揚。"]'),
('yuding-14','苦熱','司空曙','唐','御定全唐诗','yuding','','[]','暑氣發炎州，焦煙遠未收。嘯風兼熾焰，揮汗訝成流。',48,'御定全唐詩/json/293.json','["暑氣發炎州，焦煙遠未收。嘯風兼熾焰，揮汗訝成流。", "鸛鵲投林盡，龜魚擁石稠。漱泉齊飲酎，衣葛劇兼裘，"]'),
('yuding-15','送人歸黔府','司空曙','唐','御定全唐诗','yuding','','[]','伏波簫鼓水雲中，長戟如霜大旆紅。',32,'御定全唐詩/json/293.json','["伏波簫鼓水雲中，長戟如霜大旆紅。", "油幕曉開飛鳥絕，翩翩上將獨趨風。"]'),
('yuding-16','雜興','司空曙','唐','御定全唐诗','yuding','','[]','月沒遼城暗出師，雙龍金角曉天悲。',32,'御定全唐詩/json/293.json','["月沒遼城暗出師，雙龍金角曉天悲。", "黃塵滿目隨風散，不認將軍燕尾旗。"]'),
('yuding-17','歲暮懷崔峒耿湋','司空曙','唐','御定全唐诗','yuding','','[]','臘月江天見春色，白花青柳疑寒食。',32,'御定全唐詩/json/293.json','["臘月江天見春色，白花青柳疑寒食。", "洛陽舊社各東西，楚國遊人不相識。"]'),
('yuding-18','觀妓','司空曙','唐','御定全唐诗','yuding','','[]','翠蛾紅臉不勝情，管絕弦餘發一聲。',32,'御定全唐詩/json/293.json','["翠蛾紅臉不勝情，管絕弦餘發一聲。", "銀燭搖搖塵暗下，卻愁紅粉淚痕生。"]'),
('yuding-19','過長林湖西酒家','司空曙','唐','御定全唐诗','yuding','','[]','湖草青青三兩家，門前桃杏一般花。',32,'御定全唐詩/json/293.json','["湖草青青三兩家，門前桃杏一般花。", "遷人到處唯求醉，聞說漁翁有酒賒。"]'),
('yuding-20','過閻采病居','司空曙','唐','御定全唐诗','yuding','','[]','每逢佳節何曾坐，唯有今年不得遊。',32,'御定全唐詩/json/293.json','["每逢佳節何曾坐，唯有今年不得遊。", "張邴臥來休送客，菊花楓葉向誰秋。"]'),
('yuding-21','送程秀才','司空曙','唐','御定全唐诗','yuding','','[]','悠悠多路岐，相見又別離。東風催節換，焰焰春陽散。',72,'御定全唐詩/json/293.json','["悠悠多路岐，相見又別離。東風催節換，焰焰春陽散。", "楚草漸煙綿，江雲亦蕪漫。送子恨何窮，故關如夢中。", "遊人盡還北，旅雁辭南國。楓樹幾回青，逐臣歸不得。"]'),
('yuding-22','長林令衛象餳絲結歌','司空曙','唐','御定全唐诗','yuding','','[]','主人雕盤盤素絲，寒女眷眷墨子悲。乃言假使餳為之，',72,'御定全唐詩/json/293.json','["主人雕盤盤素絲，寒女眷眷墨子悲。乃言假使餳為之，", "仰坼重衣傾萬蕊，又如合歡交亂枝，紅茸向暮花參差。", "吳蠶絡繭抽尚絕，細縷纖毫看欲滅。雪發羞垂倭墮鬟，"]'),
('yuding-23','酬崔峒見寄','司空曙','唐','御定全唐诗','yuding','','[]','趨陪禁掖雁行隨，遷放江潭鶴發垂。素浪遙疑太液水，',40,'御定全唐詩/json/293.json','["趨陪禁掖雁行隨，遷放江潭鶴發垂。素浪遙疑太液水，", "共望漢朝多沛澤，蒼蠅早晚得先知。"]'),
('yuding-24','聞春雷','司空曙','唐','御定全唐诗','yuding','','[]','水國春雷早，闐闐若眾車。自憐遷逐者，猶滯蟄藏餘。',24,'御定全唐詩/json/293.json','["水國春雷早，闐闐若眾車。自憐遷逐者，猶滯蟄藏餘。"]'),
('yuding-25','晚秋西省寄上李韓二舍人','司空曙','唐','御定全唐诗','yuding','','[]','晝漏傳清唱，天恩禁旅秋。雁親承露掌，砧隔曝衣樓。',48,'御定全唐詩/json/293.json','["晝漏傳清唱，天恩禁旅秋。雁親承露掌，砧隔曝衣樓。", "賜膳中人送，餘香侍女收。仍聞勞上直，晚步鳳池頭。"]'),
('yuding-26','下武昌江行望涔陽','司空曙','唐','御定全唐诗','yuding','','[]','悠悠次楚鄉，楚口下涔陽。雪隱洲渚暗，沙高蘆荻黃。',48,'御定全唐詩/json/293.json','["悠悠次楚鄉，楚口下涔陽。雪隱洲渚暗，沙高蘆荻黃。", "漁人共留滯，水鳥自喧翔。懷土年空盡，春風又淼茫。"]'),
('yuding-27','送史申之峽州','司空曙','唐','御定全唐诗','yuding','','[]','峽口巴江外，無風浪亦翻。蒹葭新有雁，雲雨不離猿。',48,'御定全唐詩/json/293.json','["峽口巴江外，無風浪亦翻。蒹葭新有雁，雲雨不離猿。", "行客思鄉遠，愁人賴酒昏。檀郎好聯句，共滯謝家門。"]'),
('yuding-28','送王閏','司空曙','唐','御定全唐诗','yuding','','[]','相送臨寒水，蒼然望故關。江蕪連夢澤，楚雪入商山。',48,'御定全唐詩/json/293.json','["相送臨寒水，蒼然望故關。江蕪連夢澤，楚雪入商山。", "話我他年舊，看君此日還。因將自悲淚，一灑別離間。"]'),
('yuding-29','江園書事寄盧綸','司空曙','唐','御定全唐诗','yuding','','[]','種柳南江邊，閉門三四年。豔花那勝竹，凡鳥不如蟬。',48,'御定全唐詩/json/293.json','["種柳南江邊，閉門三四年。豔花那勝竹，凡鳥不如蟬。", "嗜酒漸嬰渴，讀書多欲眠。平生故交在，白首遠相憐。"]'),
('yuding-30','送鄭況往淮南','司空曙','唐','御定全唐诗','yuding','','[]','西楚見南關，蒼蒼落日間。雲離大雷樹，潮入秣陵山。',48,'御定全唐詩/json/293.json','["西楚見南關，蒼蒼落日間。雲離大雷樹，潮入秣陵山。", "登戍因高望，停橈放溜閑。陳公有賢榻，君去豈空還。"]'),
('yuding-31','題江陵臨沙驛樓','司空曙','唐','御定全唐诗','yuding','','[]','江天清更愁，風柳入江樓。雁惜楚山晚，蟬知秦樹秋。',48,'御定全唐詩/json/293.json','["江天清更愁，風柳入江樓。雁惜楚山晚，蟬知秦樹秋。", "淒涼多獨醉，零落半同遊。豈複平生意，蒼然蘭杜洲。"]'),
('yuding-32','新蟬','司空曙','唐','御定全唐诗','yuding','','[]','今朝蟬忽鳴，遷客若為情。便覺一年老，能令萬感生。',48,'御定全唐詩/json/293.json','["今朝蟬忽鳴，遷客若為情。便覺一年老，能令萬感生。", "微風方滿樹，落日稍沉城。為問同懷者，淒涼聽幾聲。"]'),
('yuding-33','送張弋','司空曙','唐','御定全唐诗','yuding','','[]','擁棹江天曠，蒼然下郢城。冰霜葭菼變，雲澤鷓鴣鳴。',48,'御定全唐詩/json/293.json','["擁棹江天曠，蒼然下郢城。冰霜葭菼變，雲澤鷓鴣鳴。", "酒倦臨流醉，人逢置榻迎。嘗聞藉東觀，不獨魯諸生。"]'),
('yuding-34','送僧無言歸山','司空曙','唐','御定全唐诗','yuding','','[]','袈裟出塵外，山徑幾盤緣。人到白雲樹，鶴沉青草田。',48,'御定全唐詩/json/293.json','["袈裟出塵外，山徑幾盤緣。人到白雲樹，鶴沉青草田。", "龕泉朝請盥，松籟夜和禪。自昔聞多學，逍遙注一篇。"]'),
('yuding-35','和盧校書文若早入使院書事','司空曙','唐','御定全唐诗','yuding','','[]','解帶獨裴回，秋風如水來。軒墀濕繁露，琴幾拂輕埃。',48,'御定全唐詩/json/293.json','["解帶獨裴回，秋風如水來。軒墀濕繁露，琴幾拂輕埃。", "晨鳥猶在葉，夕蟲餘□苔。蒼然發高興，相仰坐難陪。"]'),
('yuding-36','送史澤之長沙','司空曙','唐','御定全唐诗','yuding','','[]','謝脁懷西府，單車觸火雲。野蕉依戍客，廟竹映湘君。',48,'御定全唐詩/json/293.json','["謝脁懷西府，單車觸火雲。野蕉依戍客，廟竹映湘君。", "夢渚巴山斷，長沙楚路分。一杯從別後，風月不相聞。"]'),
('yuding-37','田家','司空曙','唐','御定全唐诗','yuding','','[]','田家喜雨足，鄰老相招攜。泉溢溝塍壞，麥高桑柘低。',48,'御定全唐詩/json/293.json','["田家喜雨足，鄰老相招攜。泉溢溝塍壞，麥高桑柘低。", "呼兒催放犢，宿客待烹雞。搔首蓬門下，如將軒冕齊。"]'),
('yuding-38','送盧堪','司空曙','唐','御定全唐诗','yuding','','[]','羈貧不易去，此日始西東。旅舍秋霖葉，行人寒草風。',48,'御定全唐詩/json/293.json','["羈貧不易去，此日始西東。旅舍秋霖葉，行人寒草風。", "酒醒餘恨在，野餞暫遊同。莫使禰生刺，空留懷袖中。"]'),
('yuding-39','送柳震入蜀','司空曙','唐','御定全唐诗','yuding','','[]','粉堞連青氣，喧喧雜萬家。夷人祠竹節，蜀鳥乳桐花。',48,'御定全唐詩/json/293.json','["粉堞連青氣，喧喧雜萬家。夷人祠竹節，蜀鳥乳桐花。", "酒報新豐景，琴迎抵峽斜。多聞滯遊客，不似在天涯。"]'),
('yuding-40','送李嘉佑正字括圖書兼往揚州覲省','司空曙','唐','御定全唐诗','yuding','','[]','不事蘭台貴，全多韋帶風。儒官比劉向，使者得陳農。',48,'御定全唐詩/json/293.json','["不事蘭台貴，全多韋帶風。儒官比劉向，使者得陳農。", "晚燒平蕪外，朝陽疊浪東。歸來喜調膳，寒筍出林中。"]'),
('yuding-41','送劉侍禦','司空曙','唐','御定全唐诗','yuding','','[]','獄成收夜燭，整豸出登車。黃葉辭荊楚，青山背漢初。',48,'御定全唐詩/json/293.json','["獄成收夜燭，整豸出登車。黃葉辭荊楚，青山背漢初。", "早朝新羽衛，晚下步徒胥。應念長沙謫，思鄉不食魚。"]'),
('yuding-42','送龐判官赴黔中','司空曙','唐','御定全唐诗','yuding','','[]','天遠風煙異，西南見一方。亂山來蜀道，諸水出辰陽。',48,'御定全唐詩/json/293.json','["天遠風煙異，西南見一方。亂山來蜀道，諸水出辰陽。", "堆案青油暮，看棋畫角長。論文誰可制，記室有何郎。"]'),
('yuding-43','送人游嶺南','司空曙','唐','御定全唐诗','yuding','','[]','萬里南遊客，交州見柳條。逢迎人易合，時日酒能消。',48,'御定全唐詩/json/293.json','["萬里南遊客，交州見柳條。逢迎人易合，時日酒能消。", "浪曉浮青雀，風溫解黑貂。囊金如未足，莫恨故鄉遙。"]'),
('yuding-44','送曹同椅','司空曙','唐','御定全唐诗','yuding','','[]','青春三十餘，眾藝盡無如。中散詩傳畫，將軍扇續書。',48,'御定全唐詩/json/293.json','["青春三十餘，眾藝盡無如。中散詩傳畫，將軍扇續書。", "楚田晴下雁，江日暖遊魚。惆悵空相送，歡遊自此疏。"]'),
('yuding-45','送鄂州張別駕襄陽覲省','司空曙','唐','御定全唐诗','yuding','','[]','蒼蒼峴亭路，臘月漢陽春。帶雪半山寺，行沙隔水人。',48,'御定全唐詩/json/293.json','["蒼蒼峴亭路，臘月漢陽春。帶雪半山寺，行沙隔水人。", "王祥因就宦，萊子不違親。正恨殊鄉別，千條楚柳新。"]'),
('yuding-46','送魏季羔游長沙覲兄','司空曙','唐','御定全唐诗','yuding','','[]','蘆荻湘江水，蕭蕭萬里秋。鶴高看迥野，蟬遠入中流。',48,'御定全唐詩/json/293.json','["蘆荻湘江水，蕭蕭萬里秋。鶴高看迥野，蟬遠入中流。", "訪友多成滯，攜家不厭遊。惠連仍有作，知得從兄酬。"]'),
('yuding-47','雜言','司空曙','唐','御定全唐诗','yuding','','[]','伏餘西景移，風雨灑輕絺。燕拂青蕪地，蟬鳴紅葉枝。',24,'御定全唐詩/json/293.json','["伏餘西景移，風雨灑輕絺。燕拂青蕪地，蟬鳴紅葉枝。"]'),
('yuding-48','玩花與衛象同醉','司空曙','唐','御定全唐诗','yuding','','[]','衰鬢千莖雪，他鄉一樹花。今朝與君醉，忘卻在長沙。',24,'御定全唐詩/json/293.json','["衰鬢千莖雪，他鄉一樹花。今朝與君醉，忘卻在長沙。"]'),
('yuding-49','送王尊師歸湖州','司空曙','唐','御定全唐诗','yuding','','[]','煙蕪滿洞青山繞，幢節飄空紫鳳飛。金闕乍看迎日麗，',40,'御定全唐詩/json/293.json','["煙蕪滿洞青山繞，幢節飄空紫鳳飛。金闕乍看迎日麗，", "莫學遼東華表上，千年始欲一回歸。"]'),
('yuding-50','九日洛東亭','司空曙','唐','御定全唐诗','yuding','','[]','風息斜陽盡，遊人曲落間。采花因覆酒，行草轉看山。',48,'御定全唐詩/json/293.json','["風息斜陽盡，遊人曲落間。采花因覆酒，行草轉看山。", "柳散新霜下，天晴早雁還。傷秋非騎省，玄發白成斑。"]'),
('yuding-51','九日送人','司空曙','唐','御定全唐诗','yuding','','[]','送人冠獬豸，值節佩茱萸。均賦征三壤，登車出五湖。',48,'御定全唐詩/json/293.json','["送人冠獬豸，值節佩茱萸。均賦征三壤，登車出五湖。", "水風淒落日，岸葉颯衰蕪。自恨塵中使，何因在路隅。"]'),
('yuding-52','哭王注','司空曙','唐','御定全唐诗','yuding','','[]','已歎漳濱臥，何言駐隙難。異才傷促短，諸友哭門闌。',48,'御定全唐詩/json/293.json','["已歎漳濱臥，何言駐隙難。異才傷促短，諸友哭門闌。", "古道松聲暮，荒阡草色寒。延陵今葬子，空使魯人觀。"]'),
('yuding-53','遇谷口道士','司空曙','唐','御定全唐诗','yuding','','[]','一見林中客，閑知州縣勞。白雲秋色遠，蒼嶺夕陽高。',48,'御定全唐詩/json/293.json','["一見林中客，閑知州縣勞。白雲秋色遠，蒼嶺夕陽高。", "自說名因石，誰逢手種桃。丹經倘相授，何用戀青袍。"]'),
('yuding-54','喜外弟盧綸見宿','司空曙','唐','御定全唐诗','yuding','','[]','靜夜四無鄰，荒居舊業貧。雨中黃葉樹，燈下白頭人。',48,'御定全唐詩/json/293.json','["靜夜四無鄰，荒居舊業貧。雨中黃葉樹，燈下白頭人。", "以我獨沈久，愧君相見頻。平生自有分，況是蔡家親。"]'),
('yuding-55','深上人見訪憶李端','司空曙','唐','御定全唐诗','yuding','','[]','雁稀秋色盡，落日對寒山。避事多稱疾，留僧獨閉關。',48,'御定全唐詩/json/293.json','["雁稀秋色盡，落日對寒山。避事多稱疾，留僧獨閉關。", "心歸塵俗外，道勝有無間。仍憶東林友，相期久不還。"]'),
('yuding-56','宿青龍寺故曇上人院','司空曙','唐','御定全唐诗','yuding','','[]','年深宮院在，舊客自相逢。閉戶臨寒竹，無人有夜鐘。',48,'御定全唐詩/json/293.json','["年深宮院在，舊客自相逢。閉戶臨寒竹，無人有夜鐘。", "降龍今已去，巢鶴竟何從。坐見繁星曉，淒涼識舊峰。"]'),
('yuding-57','送張煉師還峨嵋山','司空曙','唐','御定全唐诗','yuding','','[]','太一天壇天柱西，垂蘿為幌石為梯。前登靈境青霄絕，',40,'御定全唐詩/json/293.json','["太一天壇天柱西，垂蘿為幌石為梯。前登靈境青霄絕，", "春山一入尋無路，鳥響煙深水滿溪。"]'),
('yuding-58','逢江客問南中故人因以詩寄','司空曙','唐','御定全唐诗','yuding','','[]','南客何時去，相逢問故人。望鄉空淚落，嗜酒轉家貧。',72,'御定全唐詩/json/293.json','["南客何時去，相逢問故人。望鄉空淚落，嗜酒轉家貧。", "疏懶辭微祿，東西任老身。上樓多看月，臨水共傷春。", "五柳終期隱，雙鷗自可親。應憐折腰吏，冉冉在風塵。"]'),
('yuding-59','送皋法師','司空曙','唐','御定全唐诗','yuding','','[]','江草知寒柳半衰，行吟怨別獨遲遲。',32,'御定全唐詩/json/293.json','["江草知寒柳半衰，行吟怨別獨遲遲。", "何人講席投如意，唯有東林遠法師。"]'),
('yuding-60','送鄭佶歸洛陽','司空曙','唐','御定全唐诗','yuding','','[]','蒼蒼楚色水雲間，一醉春風送爾還。',32,'御定全唐詩/json/293.json','["蒼蒼楚色水雲間，一醉春風送爾還。", "何處鄉心最堪羨，汝南初見洛陽山。"]'),
('yuding-61','分流水','司空曙','唐','御定全唐诗','yuding','','[]','古時愁別淚，滴作分流水。日夜東西流，分流幾千里。',48,'御定全唐詩/json/293.json','["古時愁別淚，滴作分流水。日夜東西流，分流幾千里。", "通塞兩不見，波瀾各自起。與君相背飛，去去心如此。"]'),
('yuding-62','和耿拾遺元日觀早朝','司空曙','唐','御定全唐诗','yuding','','[]','元日爭朝闕，奔流若會溟。路塵和薄霧，騎火接低星。',120,'御定全唐詩/json/293.json','["元日爭朝闕，奔流若會溟。路塵和薄霧，騎火接低星。", "門響雙魚鑰，車喧百子鈴。冕旒當翠殿，幢戟滿彤庭。", "積歲方編瑞，乘春即省刑。大官陳禹玉，司曆獻堯蓂。", "壽酒三觴退，簫韶九奏停。太陽開物象，霈澤及生靈。", "南陌高山碧，東方曉氣青。自憐揚子賤，歸草太玄經。"]'),
('yuding-63','塞下曲','司空曙','唐','御定全唐诗','yuding','','[]','寒柳接胡桑，軍門向大荒。幕營隨月魄，兵氣長星芒。',48,'御定全唐詩/json/293.json','["寒柳接胡桑，軍門向大荒。幕營隨月魄，兵氣長星芒。", "橫吹催春酒，重裘隔夜霜。冰開不防虜，青草滿遼陽。"]'),
('yuding-64','關山月','司空曙','唐','御定全唐诗','yuding','','[]','蒼茫明月上，夜久光如積。野幕冷胡霜，關樓宿邊客。',48,'御定全唐詩/json/293.json','["蒼茫明月上，夜久光如積。野幕冷胡霜，關樓宿邊客。", "隴頭秋露暗，磧外寒沙白。唯有故鄉人，沾裳此聞笛。"]'),
('yuding-65','禦制雨後出城觀覽，敕朝臣已下屬和','司空曙','唐','御定全唐诗','yuding','','[]','上上開鶉野，師師出鳳城。因知聖主念，得遂老農情。',96,'御定全唐詩/json/293.json','["上上開鶉野，師師出鳳城。因知聖主念，得遂老農情。", "隴麥垂秋合，郊塵得雨清。時新薦玄祖，歲足富蒼生。", "卻馬川原靜，聞雞水土平。熏弦歌舜德，和鼎致堯名。", "覽物欣多稼，垂衣禦大明。史官何所錄，稱瑞滿天京。"]'),
('yuding-66','奉和常舍人晚秋集賢院即事寄徐薛二侍郎','司空曙','唐','御定全唐诗','yuding','','[]','藹藹鳳凰宮，蘭台玉署通。夜霜凝樹羽，朝日照相風。',144,'御定全唐詩/json/293.json','["藹藹鳳凰宮，蘭台玉署通。夜霜凝樹羽，朝日照相風。", "官附三台貴，儒開百氏宗。司言陳禹命，侍講發堯聰。", "香卷青編內，鉛分綠字中。綴簽從太史，鏘佩揖群公。", "池接天泉碧，林交禦果紅。寒龜登故葉，秋蝶戀疏叢。", "顏謝徵文並，鐘裴直事同。離群驚海鶴，屬思怨江楓。", "地遠姑蘇外，山長越絕東。慚當哲匠後，下曲本難工。"]'),
('yuding-67','題鮮于秋林園','司空曙','唐','御定全唐诗','yuding','','[]','雨後園林好，幽行迥野通。遠山芳草外，流水落花中。',48,'御定全唐詩/json/293.json','["雨後園林好，幽行迥野通。遠山芳草外，流水落花中。", "客醉悠悠慣，鶯啼處處同。夕陽自一望，日暮杜陵東。"]'),
('yuding-68','登秦嶺','司空曙','唐','御定全唐诗','yuding','','[]','南登秦嶺頭，回首始堪憂。漢闕青門遠，商山藍水流。',48,'御定全唐詩/json/293.json','["南登秦嶺頭，回首始堪憂。漢闕青門遠，商山藍水流。", "三湘遷客去，九陌故人游。從此思鄉淚，雙垂不復收。"]'),
('yuding-69','獨游寄衛長林','司空曙','唐','御定全唐诗','yuding','','[]','草綠春陽動，遲遲澤畔遊。戀花同野蝶，愛水劇江鷗。',48,'御定全唐詩/json/293.json','["草綠春陽動，遲遲澤畔遊。戀花同野蝶，愛水劇江鷗。", "身外唯須醉，人間儘是愁。那知鳴玉者，不羨賣瓜侯。"]'),
('yuding-70','望水','司空曙','唐','御定全唐诗','yuding','','[]','高樓晴見水，楚色靄相和。野極空如練，天遙不辨波。',48,'御定全唐詩/json/293.json','["高樓晴見水，楚色靄相和。野極空如練，天遙不辨波。", "永無人跡到，時有鳥行過。況是蒼茫外，殘陽照最多。"]'),
('yuding-71','望商山路','司空曙','唐','御定全唐诗','yuding','','[]','南見青山道，依然去國時。已甘長避地，誰料有還期。',48,'御定全唐詩/json/293.json','["南見青山道，依然去國時。已甘長避地，誰料有還期。", "雨霽殘陽薄，人愁獨望遲。空殘華髮在，前事不堪思。"]'),
('yuding-72','題落葉','司空曙','唐','御定全唐诗','yuding','','[]','霜景催危葉，今朝半樹空。蕭條故國異，零落旅人同。',48,'御定全唐詩/json/293.json','["霜景催危葉，今朝半樹空。蕭條故國異，零落旅人同。", "颯岸浮寒水，依階擁夜蟲。隨風偏可羨，得到洛陽宮。"]'),
('yuding-73','寄准上人','司空曙','唐','御定全唐诗','yuding','','[]','昨聞歸舊寺，暫別欲經年。樵客應同步，鄰僧定伴禪。',48,'御定全唐詩/json/293.json','["昨聞歸舊寺，暫別欲經年。樵客應同步，鄰僧定伴禪。", "後峰秋有雪，遠澗夜鳴泉。偶與支公論，人間自共傳。"]'),
('yuding-74','送況上人還荊州，因寄衛侍禦象','司空曙','唐','御定全唐诗','yuding','','[]','惠持遊蜀久，策杖欲西還。共別此宵月，獨歸何處山。',48,'御定全唐詩/json/293.json','["惠持遊蜀久，策杖欲西還。共別此宵月，獨歸何處山。", "對鷗沙草畔，洗足野雲間。知有玄暉會，齋心受八關。"]'),
('yuding-75','別盧綸','司空曙','唐','御定全唐诗','yuding','','[]','有月多同賞，無秋不共悲。如何與君別，又是菊黃時。',24,'御定全唐詩/json/293.json','["有月多同賞，無秋不共悲。如何與君別，又是菊黃時。"]'),
('yuding-76','雪二首','司空曙','唐','御定全唐诗','yuding','','[]','樂游春苑望鵝毛，宮殿如星樹似毫。',64,'御定全唐詩/json/293.json','["樂游春苑望鵝毛，宮殿如星樹似毫。", "漫漫一川橫渭水，太陽初出五陵高。", "王屋南崖見洛城，石龕松寺上方平。", "半山槲葉當窗下，一夜曾聞雪打聲。"]'),
('yuding-77','酬衛長林歲日見呈','司空曙','唐','御定全唐诗','yuding','','[]','地暖雪花摧，天春斗柄回。朱泥一丸藥，柏葉萬年杯。',48,'御定全唐詩/json/293.json','["地暖雪花摧，天春斗柄回。朱泥一丸藥，柏葉萬年杯。", "旅雁辭人去，繁霜滿鏡來。今朝彩盤上，神燕不須雷。"]'),
('yuding-78','杜鵑行','司空曙','唐','御定全唐诗','yuding','','[]','古時杜宇稱望帝，魂作杜鵑何微細。跳枝竄葉樹木中，',96,'御定全唐詩/json/293.json','["古時杜宇稱望帝，魂作杜鵑何微細。跳枝竄葉樹木中，", "隳形不敢棲華屋，短翮唯願巢深叢。穿皮啄朽觜欲禿，", "聲音咽噦若有謂，號啼略與嬰兒同。口幹垂血轉迫促，", "乃知變化不可窮，豈知昔日居深宮，嬪妃左右如花紅。"]'),
('yuding-79','寄胡居士','司空曙','唐','御定全唐诗','yuding','','[]','日暖風微南陌頭，青田紅樹起春愁。伯勞相逐行人別，',40,'御定全唐詩/json/293.json','["日暖風微南陌頭，青田紅樹起春愁。伯勞相逐行人別，", "為言惆悵嵩陽寺，明月高松應獨遊。"]'),
('yuding-80','寒塘','司空曙','唐','御定全唐诗','yuding','','[]','曉發梳臨水，寒塘坐見秋。鄉心正無限，一雁度南樓。',24,'御定全唐詩/json/293.json','["曉發梳臨水，寒塘坐見秋。鄉心正無限，一雁度南樓。"]'),
('yuding-81','為李魏公賦謝汧公','司空曙','唐','御定全唐诗','yuding','','[]','白雪高吟際，青霄遠望中。誰言路遐曠，宮征暗相通。',24,'御定全唐詩/json/293.json','["白雪高吟際，青霄遠望中。誰言路遐曠，宮征暗相通。"]'),
('yuding-82','梁城老人怨','司空曙','唐','御定全唐诗','yuding','','[]','朝為耕種人，暮作刀槍鬼。相看父子血，共染城壕水。',24,'御定全唐詩/json/293.json','["朝為耕種人，暮作刀槍鬼。相看父子血，共染城壕水。"]'),
('yuding-0','揚州選蒙相公賞判雪後呈上','崔峒','唐','御定全唐诗','yuding','','[]','自得山公許，休耕海上田。慚看長史傳，欲棄釣魚船。',48,'御定全唐詩/json/294.json','["自得山公許，休耕海上田。慚看長史傳，欲棄釣魚船。", "窮巷殷憂日，蕪城雨雪天。此時瞻相府，心事比旌懸。"]'),
('yuding-1','客舍書情寄趙中丞','崔峒','唐','御定全唐诗','yuding','','[]','東楚複西秦，浮雲類此身。關山勞策蹇，僮僕慣投人。',48,'御定全唐詩/json/294.json','["東楚複西秦，浮雲類此身。關山勞策蹇，僮僕慣投人。", "孤客來千里，全家托四鄰。生涯難自料，中夜問情親。"]'),
('yuding-2','客舍有懷因呈諸在事','崔峒','唐','御定全唐诗','yuding','','[]','讀書常苦節，待詔豈辭貧。暮雪猶驅馬，晡餐又寄人。',48,'御定全唐詩/json/294.json','["讀書常苦節，待詔豈辭貧。暮雪猶驅馬，晡餐又寄人。", "愁來占吉夢，老去惜良辰。延首平津閣，家山日已春。"]'),
('yuding-3','書懷寄楊郭李王判官','崔峒','唐','御定全唐诗','yuding','','[]','慣作雲林客，因成懶漫人。吏欺從政拙，妻笑理家貧。',48,'御定全唐詩/json/294.json','["慣作雲林客，因成懶漫人。吏欺從政拙，妻笑理家貧。", "李郭應時望，王楊入幕頻。從容丞相閣，知憶故園春。"]'),
('yuding-4','奉和給事寓直','崔峒','唐','御定全唐诗','yuding','','[]','桂枝家共折，雞樹代相傳。忝向鸞台下，仍看雁影連。',48,'御定全唐詩/json/294.json','["桂枝家共折，雞樹代相傳。忝向鸞台下，仍看雁影連。", "夜閑方步月，漏盡欲朝天。知去丹墀近，明王許薦賢。"]'),
('yuding-5','初入集賢院贈李獻仁','崔峒','唐','御定全唐诗','yuding','','[]','燕代官初罷，江湖路便分。九遷從命薄，四十幸人聞。',48,'御定全唐詩/json/294.json','["燕代官初罷，江湖路便分。九遷從命薄，四十幸人聞。", "跡愧趨丹禁，身曾系白雲。何由返滄海，昨日謁明君。"]'),
('yuding-6','酬李補闕雨中寄贈','崔峒','唐','御定全唐诗','yuding','','[]','十年隨馬宿，幾度受人恩。白髮還鄉井，微官有子孫。',48,'御定全唐詩/json/294.json','["十年隨馬宿，幾度受人恩。白髮還鄉井，微官有子孫。", "竹窗寒雨滴，苦砌夜蟲喧。獨愧東垣友，新詩慰旅魂。"]'),
('yuding-7','初除拾遺酬丘二十二見寄','崔峒','唐','御定全唐诗','yuding','','[]','江海久垂綸，朝衣忽掛身。丹墀初謁帝，白髮免羞人。',48,'御定全唐詩/json/294.json','["江海久垂綸，朝衣忽掛身。丹墀初謁帝，白髮免羞人。", "才愧文章士，名當諫諍臣。空餘薦賢分，不敢負交親。"]'),
('yuding-8','劉展下判官相招以詩答之','崔峒','唐','御定全唐诗','yuding','','[]','國有非常寵，家承異姓勳。背恩慚皎日，不義若浮雲。',48,'御定全唐詩/json/294.json','["國有非常寵，家承異姓勳。背恩慚皎日，不義若浮雲。", "但使忠貞在，甘從玉石焚。竄身如有地，夢寐見明君。"]'),
('yuding-9','送侯山人赴會稽','崔峒','唐','御定全唐诗','yuding','','[]','仙客辭蘿月，東來就一官。且歸滄海住，猶向白雲看。',48,'御定全唐詩/json/294.json','["仙客辭蘿月，東來就一官。且歸滄海住，猶向白雲看。", "猿叫江天暮，蟲聲野浦寒。時遊鏡湖裏，為我把魚竿。"]'),
('yuding-10','宿禪智寺上方演大師院','崔峒','唐','御定全唐诗','yuding','','[]','石林高幾許，金刹在中峰。白日空山梵，清霜後夜鐘。',48,'御定全唐詩/json/294.json','["石林高幾許，金刹在中峰。白日空山梵，清霜後夜鐘。", "竹窗回翠壁，苔徑入寒松。幸接無生法，疑心怯所從。"]'),
('yuding-11','題空山人石室','崔峒','唐','御定全唐诗','yuding','','[]','早晚悟無生，頭陀不到城。雲山知夏臘，猿鳥見修行。',48,'御定全唐詩/json/294.json','["早晚悟無生，頭陀不到城。雲山知夏臘，猿鳥見修行。", "地僻無溪路，人尋逐水聲。年年深谷裏，誰識遠公名。"]'),
('yuding-12','登蔣山開善寺','崔峒','唐','御定全唐诗','yuding','','[]','山殿秋雲裏，香煙出翠微。客尋朝磬至，僧背夕陽歸。',48,'御定全唐詩/json/294.json','["山殿秋雲裏，香煙出翠微。客尋朝磬至，僧背夕陽歸。", "下界千門見，前朝萬事非。看心兼送目，葭菼暮依依。"]'),
('yuding-13','題崇福寺禪院','崔峒','唐','御定全唐诗','yuding','','[]','僧家竟何事，掃地與焚香。清磬度山翠，閑雲來竹房。',48,'御定全唐詩/json/294.json','["僧家竟何事，掃地與焚香。清磬度山翠，閑雲來竹房。", "身心塵外遠，歲月坐中長。向晚禪堂掩，無人空夕陽。"]'),
('yuding-14','秋晚送丹徒許明府赴上國，因寄江南故人','崔峒','唐','御定全唐诗','yuding','','[]','秋暮之彭澤，籬花遠近逢。君書前日至，別後此時重。',48,'御定全唐詩/json/294.json','["秋暮之彭澤，籬花遠近逢。君書前日至，別後此時重。", "寒夜江邊月，晴天海上峰。還知南地客，招引住新豐。"]'),
('yuding-15','送薛仲方歸揚州','崔峒','唐','御定全唐诗','yuding','','[]','佳句應無敵，貞心不有猜。慚為丈人行，怯見後生才。',48,'御定全唐詩/json/294.json','["佳句應無敵，貞心不有猜。慚為丈人行，怯見後生才。", "泛舸貪斜月，浮橈值早梅。綠楊新過雨，芳草待君來。"]'),
('yuding-16','送韋員外還京','崔峒','唐','御定全唐诗','yuding','','[]','十年離亂後，此去若為情。春晚香山綠，人稀豫水清。',48,'御定全唐詩/json/294.json','["十年離亂後，此去若為情。春晚香山綠，人稀豫水清。", "野陂看獨樹，關路逐殘鶯。前殿朝明主，應憐白髮生。"]'),
('yuding-17','潤州送友人','崔峒','唐','御定全唐诗','yuding','','[]','見君還此地，灑淚向江邊。國士勞相問，家書無處傳。',48,'御定全唐詩/json/294.json','["見君還此地，灑淚向江邊。國士勞相問，家書無處傳。", "荒城胡馬跡，塞木戍人煙。一路堪愁思，孤舟何渺然。"]'),
('yuding-18','送張芬東歸','崔峒','唐','御定全唐诗','yuding','','[]','喧喧五衢上，鞍馬自驅馳。落日臨阡陌，貧交欲別離。',48,'御定全唐詩/json/294.json','["喧喧五衢上，鞍馬自驅馳。落日臨阡陌，貧交欲別離。", "早知時事異，堪與世人隨。握手將何贈，君心我獨知。"]'),
('yuding-19','送蘇修游上饒','崔峒','唐','御定全唐诗','yuding','','[]','愛爾無羈束，雲山恣意過。一身隨遠岫，孤棹任輕波。',48,'御定全唐詩/json/294.json','["愛爾無羈束，雲山恣意過。一身隨遠岫，孤棹任輕波。", "世事關情少，漁家寄宿多。蘆花淺淡處，江月奈人何。"]'),
('yuding-20','送陸明府之盱眙','崔峒','唐','御定全唐诗','yuding','','[]','陶令之官去，窮愁慘別魂。白煙橫海戍，紅葉下淮村。',48,'御定全唐詩/json/294.json','["陶令之官去，窮愁慘別魂。白煙橫海戍，紅葉下淮村。", "澹浪搖山郭，平蕪到縣門。政成堪吏隱，免負府公恩。"]'),
('yuding-21','江南回逢趙曜，因送任十一赴交城主簿','崔峒','唐','御定全唐诗','yuding','','[]','江上長相憶，因高北望看。不知攜老幼，何處度艱難。',48,'御定全唐詩/json/294.json','["江上長相憶，因高北望看。不知攜老幼，何處度艱難。", "屈指同人盡，傷心故里殘。遙憐驅匹馬，白首到微官。"]'),
('yuding-22','送薛良史往越州謁從叔','崔峒','唐','御定全唐诗','yuding','','[]','辭家年已久，與子分偏深。易得相思淚，難為欲別心。',48,'御定全唐詩/json/294.json','["辭家年已久，與子分偏深。易得相思淚，難為欲別心。", "孤雲隨浦口，幾日到山陰。遙想蘭亭下，清風滿竹林。"]'),
('yuding-23','送丘二十二之蘇州','崔峒','唐','御定全唐诗','yuding','','[]','積水與寒煙，嘉禾路幾千。孤猿啼海島，群雁起湖田。',48,'御定全唐詩/json/294.json','["積水與寒煙，嘉禾路幾千。孤猿啼海島，群雁起湖田。", "曾見長洲苑，嘗聞大雅篇。卻將封事去，知爾愛閑眠。"]'),
('yuding-24','登潤州芙蓉樓','崔峒','唐','御定全唐诗','yuding','','[]','上古人何在，東流水不歸。往來潮有信，朝暮事成非。',48,'御定全唐詩/json/294.json','["上古人何在，東流水不歸。往來潮有信，朝暮事成非。", "煙樹臨沙靜，雲帆入海稀。郡樓多逸興，良牧謝玄暉。"]'),
('yuding-25','江上書懷','崔峒','唐','御定全唐诗','yuding','','[]','骨肉天涯別，江山日落時。淚流襟上血，發變鏡中絲。',48,'御定全唐詩/json/294.json','["骨肉天涯別，江山日落時。淚流襟上血，發變鏡中絲。", "胡越書難到，存亡夢豈知。登高回首罷，形影自相隨。"]'),
('yuding-26','春日憶姚氏外甥','崔峒','唐','御定全唐诗','yuding','','[]','離亂人相失，春秋雁自飛。只緣行路遠，未必寄書稀。',48,'御定全唐詩/json/294.json','["離亂人相失，春秋雁自飛。只緣行路遠，未必寄書稀。", "二月花無數，頻年意有違。落暉看過後，獨坐淚沾衣。"]'),
('yuding-27','送真上人還蘭若','崔峒','唐','御定全唐诗','yuding','','[]','得道雲林久，年深暫一歸。出山逢世亂，乞食覺人稀。',48,'御定全唐詩/json/294.json','["得道雲林久，年深暫一歸。出山逢世亂，乞食覺人稀。", "半偈初傳法，中峰又掩扉。愛憎應不染，塵俗自依依。"]'),
('yuding-28','潤州送師弟自江夏往台州','崔峒','唐','御定全唐诗','yuding','','[]','遠客乘流去，孤帆向夜開。春風江上使，前日漢陽來。',48,'御定全唐詩/json/294.json','["遠客乘流去，孤帆向夜開。春風江上使，前日漢陽來。", "別路猶千里，離心重一杯。剡溪木未落，羨爾過天臺。"]'),
('yuding-29','送李道士歸山','崔峒','唐','御定全唐诗','yuding','','[]','秋城臨古路，城上望君還。曠野入寒草，獨行隨遠山。',48,'御定全唐詩/json/294.json','["秋城臨古路，城上望君還。曠野入寒草，獨行隨遠山。", "授人鴻寶內，將犬白雲間。早晚燒丹罷，遙知冰雪寒。"]'),
('yuding-30','宿江西竇主簿廳','崔峒','唐','御定全唐诗','yuding','','[]','廣庭方緩步，星漢話中移。月滿關山道，烏啼霜樹枝。',48,'御定全唐詩/json/294.json','["廣庭方緩步，星漢話中移。月滿關山道，烏啼霜樹枝。", "時艱難會合，年長重親知。前事成金石，淒然淚欲垂。"]'),
('yuding-31','喜逢妻弟鄭損因送入京','崔峒','唐','御定全唐诗','yuding','','[]','亂後自江城，相逢喜複驚。為經多載別，欲問小時名。',48,'御定全唐詩/json/294.json','["亂後自江城，相逢喜複驚。為經多載別，欲問小時名。", "對酒悲前事，論文畏後生。遙知盈卷軸，紙貴在江城。"]'),
('yuding-32','詠門下畫小松上元王杜三相公','崔峒','唐','御定全唐诗','yuding','','[]','昔聞生澗底，今見起毫端。眾草此時沒，何人知歲寒。',48,'御定全唐詩/json/294.json','["昔聞生澗底，今見起毫端。眾草此時沒，何人知歲寒。", "豈能裨棟宇，且貴出門闌。只在丹青意，淩雲也不難。"]'),
('yuding-33','寄上禮部李侍郎','崔峒','唐','御定全唐诗','yuding','','[]','吳楚相逢處，江湖共泛時。任風舟去遠，待月酒行遲。',72,'御定全唐詩/json/294.json','["吳楚相逢處，江湖共泛時。任風舟去遠，待月酒行遲。", "白髮常同歎，青雲本要期。貴來君卻少，秋至老偏悲。", "玉佩明朝盛，蒼苔陋巷滋。追尋恨無路，唯有夢相思。"]'),
('yuding-34','書情寄上蘇州韋使君兼呈吳縣李明府','崔峒','唐','御定全唐诗','yuding','','[]','數年湖上謝浮名，竹杖紗巾遂性情。雲外有時逢寺宿，',40,'御定全唐詩/json/294.json','["數年湖上謝浮名，竹杖紗巾遂性情。雲外有時逢寺宿，", "誰念獻書來萬里，君王深在九重城。"]'),
('yuding-35','題桐廬李明府官舍','崔峒','唐','御定全唐诗','yuding','','[]','訟堂寂寂對煙霞，五柳門前聚曉鴉。流水聲中視公事，',40,'御定全唐詩/json/294.json','["訟堂寂寂對煙霞，五柳門前聚曉鴉。流水聲中視公事，", "可惜陶潛無限酒，不逢籬菊正開花。"]'),
('yuding-36','贈竇十九','崔峒','唐','御定全唐诗','yuding','','[]','靈台暮宿意多違，木落花開羨客歸。江海幾時傳錦字，',40,'御定全唐詩/json/294.json','["靈台暮宿意多違，木落花開羨客歸。江海幾時傳錦字，", "幸得漢皇容直諫，憐君未遇覺人非。"]'),
('yuding-37','虔州見鄭表新詩因以寄贈','崔峒','唐','御定全唐诗','yuding','','[]','梅花嶺裏見新詩，感激情深過楚詞。平子四愁今莫比，',40,'御定全唐詩/json/294.json','["梅花嶺裏見新詩，感激情深過楚詞。平子四愁今莫比，", "才子風流定難見，湖南春草但相思。"]'),
('yuding-38','贈元秘書','崔峒','唐','御定全唐诗','yuding','','[]','舊書稍稍出風塵，孤客逢秋感此身。秦地謬為門下客，',40,'御定全唐詩/json/294.json','["舊書稍稍出風塵，孤客逢秋感此身。秦地謬為門下客，", "幸有故人茅屋在，更將心事問情親。"]'),
('yuding-39','送韋八少府判官歸東京','崔峒','唐','御定全唐诗','yuding','','[]','玄成世業紫真官，文似相如貌勝潘。鴻雁南飛人獨去，',40,'御定全唐詩/json/294.json','["玄成世業紫真官，文似相如貌勝潘。鴻雁南飛人獨去，", "瓊樹相思何日見，銀鉤數字莫為難。"]'),
('yuding-40','送馮八將軍奏事畢歸滑台幕府','崔峒','唐','御定全唐诗','yuding','','[]','王門別後到滄洲，帝裏相逢俱白頭。自歎馬卿常帶疾，',40,'御定全唐詩/json/294.json','["王門別後到滄洲，帝裏相逢俱白頭。自歎馬卿常帶疾，", "想到滑台桑葉落，黃河東注杏園秋。"]'),
('yuding-41','送王侍禦佐婺州','崔峒','唐','御定全唐诗','yuding','','[]','聞君作尉向江潭。吳越風煙到自諳。客路尋常經竹徑，',40,'御定全唐詩/json/294.json','["聞君作尉向江潭。吳越風煙到自諳。客路尋常經竹徑，", "惟有夜猿啼海樹，思鄉望北意難堪。"]'),
('yuding-42','越中送王使君赴江華','崔峒','唐','御定全唐诗','yuding','','[]','皂蓋春風自越溪，獨尋芳樹桂陽西。遠水浮雲隨馬去，',40,'御定全唐詩/json/294.json','["皂蓋春風自越溪，獨尋芳樹桂陽西。遠水浮雲隨馬去，", "萬里相思在何處，九疑殘雪白猿啼。"]'),
('yuding-43','送皇甫冉往白田','崔峒','唐','御定全唐诗','yuding','','[]','江邊盡日雉鳴飛，君向白田何日歸。楚地蒹葭連海迥，',40,'御定全唐詩/json/294.json','["江邊盡日雉鳴飛，君向白田何日歸。楚地蒹葭連海迥，", "試問疲人與征戰，使君雙淚定沾衣。"]'),
('yuding-44','題蘭若','崔峒','唐','御定全唐诗','yuding','','[]','絕頂茅庵老此生，寒雲孤木獨經行。',32,'御定全唐詩/json/294.json','["絕頂茅庵老此生，寒雲孤木獨經行。", "世人那得知幽徑，遙向青峰禮磬聲。"]'),
('yuding-45','送賀蘭廣赴選','崔峒','唐','御定全唐诗','yuding','','[]','而今用武爾攻文，流輩幹時獨臥雲。',32,'御定全唐詩/json/294.json','["而今用武爾攻文，流輩幹時獨臥雲。", "白髮青袍趨會府，定應衡鏡卻慚君。"]'),
('yuding-46','清江曲內一絕','崔峒','唐','御定全唐诗','yuding','','[]','八月長江去浪平，片帆一道帶風輕。',32,'御定全唐詩/json/294.json','["八月長江去浪平，片帆一道帶風輕。", "極目不分天水色，南山南是岳陽城。"]'),
('yuding-47','武康郭外望許緯先生山居','崔峒','唐','御定全唐诗','yuding','','[]','湖上千峰帶落暉，白雲開處見柴扉。',32,'御定全唐詩/json/294.json','["湖上千峰帶落暉，白雲開處見柴扉。", "松門一徑仍生草，應是仙人向郭稀。"]'),
('yuding-0','送司空曙之蘇州','苗發','唐','御定全唐诗','yuding','','[]','盤門吳舊地，蟬盡草秋時。歸國人皆久，移家君獨遲。',48,'御定全唐詩/json/295.json','["盤門吳舊地，蟬盡草秋時。歸國人皆久，移家君獨遲。", "廣陵經水宿，建鄴有僧期。若到西霞寺，應看江總碑。"]'),
('yuding-1','送孫德諭罷官往黔州','苗發','唐','御定全唐诗','yuding','','[]','中歲分符典石城，兩朝趨陛謁承明。闕下昨承歸老疏，',40,'御定全唐詩/json/295.json','["中歲分符典石城，兩朝趨陛謁承明。闕下昨承歸老疏，", "伯道暮年無嗣子，欲將家事托門生。"]'),
('yuding-2','送歸中丞使新羅冊立弔祭','吉中孚','唐','御定全唐诗','yuding','','[]','官稱漢獨坐，身是魯諸生。絕域通王制，窮天向水程。',72,'御定全唐詩/json/295.json','["官稱漢獨坐，身是魯諸生。絕域通王制，窮天向水程。", "島中分萬象，日處轉雙旌。氣積魚龍窟，濤翻水浪聲。", "路長經歲去，海盡向山行。複道殊方禮，人瞻漢使榮。"]'),
('yuding-3','詠被中繡鞋','夏侯審','唐','御定全唐诗','yuding','','[]','雲裏蟾鉤落鳳窩，玉郎沈醉也摩挲。',32,'御定全唐詩/json/295.json','["雲裏蟾鉤落鳳窩，玉郎沈醉也摩挲。", "陳王當日風流減，只向波間見襪羅。"]'),
('yuding-4','行路難','王烈','唐','御定全唐诗','yuding','','[]','行客滿長路，路長良足哀。白日持角弓，射人而取財。',60,'御定全唐詩/json/295.json','["行客滿長路，路長良足哀。白日持角弓，射人而取財。", "千金誰家子，紛紛死黃埃。見者不敢言，言者不得回。", "家人各望歸，豈知長不來。"]'),
('yuding-5','雪','王烈','唐','御定全唐诗','yuding','','[]','雪飛當夢蝶，風度幾驚人。半夜一窗曉，平明千樹春。',48,'御定全唐詩/json/295.json','["雪飛當夢蝶，風度幾驚人。半夜一窗曉，平明千樹春。", "花園應失路，白屋忽為鄰。散入仙廚裏，還如雲母塵。"]'),
('yuding-6','酬崔峒','王烈','唐','御定全唐诗','yuding','','[]','徇世甘長往，逢時忝一官。欲朝青瑣去，羞向白雲看。',48,'御定全唐詩/json/295.json','["徇世甘長往，逢時忝一官。欲朝青瑣去，羞向白雲看。", "榮寵無心易，艱危抗節難。思君寫懷抱，非敢和幽蘭。"]'),
('yuding-7','塞上曲二首','王烈','唐','御定全唐诗','yuding','','[]','紅顏歲歲老金微，砂磧年年臥鐵衣。',64,'御定全唐詩/json/295.json','["紅顏歲歲老金微，砂磧年年臥鐵衣。", "白草城中春不入，黃花戍上雁長飛。", "孤城夕對戍樓閑，回合青冥萬仞山。", "明鏡不須生白髮，風沙自解老紅顏。"]'),
('yuding-8','傷李端','衛象','唐','御定全唐诗','yuding','','[]','才子浮生促，泉台此路賒。官卑楊執戟，年少賈長沙。',48,'御定全唐詩/json/295.json','["才子浮生促，泉台此路賒。官卑楊執戟，年少賈長沙。", "人去門棲鵩，災成酒誤蛇。唯餘封禪草，留在茂陵家。"]'),
('yuding-9','古詞','衛象','唐','御定全唐诗','yuding','','[]','鵲血雕弓濕未幹，鸊鵜新淬劍光寒。',32,'御定全唐詩/json/295.json','["鵲血雕弓濕未幹，鸊鵜新淬劍光寒。", "遼東老將鬢成雪，猶向旄頭夜夜看。"]'),
('yuding-10','晴江秋望','崔季卿','唐','御定全唐诗','yuding','','[]','八月長江萬里晴，千帆一道帶風輕。',32,'御定全唐詩/json/295.json','["八月長江萬里晴，千帆一道帶風輕。", "盡日不分天水色，洞庭南是岳陽城。"]'),
('yuding-11','贈兄','何兆','唐','御定全唐诗','yuding','','[]','洛陽紙價因兄貴，蜀地紅箋為弟貧。',32,'御定全唐詩/json/295.json','["洛陽紙價因兄貴，蜀地紅箋為弟貧。", "南北東西九千里，除兄與弟更無人。"]'),
('yuding-12','玉蕊花','何兆','唐','御定全唐诗','yuding','','[]','羽車潛下玉龜山，塵世何緣睹蕣顏。',32,'御定全唐詩/json/295.json','["羽車潛下玉龜山，塵世何緣睹蕣顏。", "惟有多情天上雪，好風吹上綠雲鬟。"]'),
('yuding-13','句','何兆','唐','御定全唐诗','yuding','','[]','芙蓉十二池心漏，薝蔔三千灌頂香。。',17,'御定全唐詩/json/295.json','["芙蓉十二池心漏，薝蔔三千灌頂香。。"]'),
('yuding-14','嚴陵灘下寄常建','奚賈','唐','御定全唐诗','yuding','','[]','日入溪水靜，尋真此亦難。乃知滄洲人，道成仍釣竿。',72,'御定全唐詩/json/295.json','["日入溪水靜，尋真此亦難。乃知滄洲人，道成仍釣竿。", "漾楫乘微月，振衣生早寒。紛吾成獨往，自速耽考盤。", "已息漢陰誚，且同濠上觀。曠然心無涯，誰問容膝安。"]'),
('yuding-15','謁李尊師','奚賈','唐','御定全唐诗','yuding','','[]','萬物返常性，惟道貴自然。先生容其微，隱幾為列仙。',48,'御定全唐詩/json/295.json','["萬物返常性，惟道貴自然。先生容其微，隱幾為列仙。", "煉魄閉瓊戶，養毛飛洞天。將知逍遙久，得道無歲年。"]'),
('yuding-16','尋許山人亭子','奚賈','唐','御定全唐诗','yuding','','[]','桃源若遠近，漁子棹輕舟。川路行難盡，人家到漸幽。',48,'御定全唐詩/json/295.json','["桃源若遠近，漁子棹輕舟。川路行難盡，人家到漸幽。", "山禽拂席起，溪水入庭流。君是何年隱，如今成白頭。"]'),
('yuding-17','句','奚賈','唐','御定全唐诗','yuding','','[]','眠澗花自落，步林鳥不飛。',37,'御定全唐詩/json/295.json','["眠澗花自落，步林鳥不飛。", "溪谷何蕭條，日入人獨行。", "落日下平楚，孤煙生洞庭。。"]'),
('yuding-0','富陽南樓望浙江風起','張南史','唐','御定全唐诗','yuding','','[]','南樓渚風起，樹杪見滄波。稍覺征帆上，蕭蕭暮雨多。',48,'御定全唐詩/json/296.json','["南樓渚風起，樹杪見滄波。稍覺征帆上，蕭蕭暮雨多。", "沙洲殊未極，雲水更相和。欲問任公子，垂綸意若何。"]'),
('yuding-1','奉酬李舍人秋日寓直見寄','張南史','唐','御定全唐诗','yuding','','[]','秋日金華直，遙知玉佩清。九重門更肅，五色詔初成。',48,'御定全唐詩/json/296.json','["秋日金華直，遙知玉佩清。九重門更肅，五色詔初成。", "槐落宮中影，鴻高苑外聲。翻從魏闕下，江海寄幽情。"]'),
('yuding-2','同韓侍郎秋朝使院','張南史','唐','御定全唐诗','yuding','','[]','重門啟曙關，一葉報秋還。露井桐柯濕，風庭鶴翅閑。',48,'御定全唐詩/json/296.json','["重門啟曙關，一葉報秋還。露井桐柯濕，風庭鶴翅閑。", "忘情簪白筆，假夢入青山。惆悵只應此，難裁語默間。"]'),
('yuding-3','送朱大遊塞','張南史','唐','御定全唐诗','yuding','','[]','歲暮一為別，江湖聊自寬。且無人事處，誰謂客行難。',48,'御定全唐詩/json/296.json','["歲暮一為別，江湖聊自寬。且無人事處，誰謂客行難。", "郢曲憐公子，吳州憶伯鸞。蒼蒼遠山際，松柏獨宜寒。"]'),
('yuding-4','送鄭錄事赴太原','張南史','唐','御定全唐诗','yuding','','[]','歎息不相見，紅顏今白頭。重為西候別，方起北風愁。',48,'御定全唐詩/json/296.json','["歎息不相見，紅顏今白頭。重為西候別，方起北風愁。", "六月胡天冷，雙城汾水流。盧諶即故吏，還複向並州。"]'),
('yuding-5','送餘贊善使還赴薛尚書幕','張南史','唐','御定全唐诗','yuding','','[]','音書不可論，河塞雪紛紛。雁足期蘇武，狐裘見薛君。',48,'御定全唐詩/json/296.json','["音書不可論，河塞雪紛紛。雁足期蘇武，狐裘見薛君。", "城池通紫陌，鞍馬入黃雲。遠棹漳渠水，平流幾處分。"]'),
('yuding-6','送李侍禦入茅山采藥','張南史','唐','御定全唐诗','yuding','','[]','苦縣家風在，茅山道錄傳。聊聽驄馬使，卻就紫陽仙。',48,'御定全唐詩/json/296.json','["苦縣家風在，茅山道錄傳。聊聽驄馬使，卻就紫陽仙。", "江海生岐路，雲霞入洞天。莫令千歲鶴，飛到草堂前。"]'),
('yuding-7','寄中書李舍人','張南史','唐','御定全唐诗','yuding','','[]','昨宵淒斷處，對月與臨風。鶴病三江上，蘭衰百草中。',48,'御定全唐詩/json/296.json','["昨宵淒斷處，對月與臨風。鶴病三江上，蘭衰百草中。", "題詩隨謝客，飲酒寄黃翁。早歲心相待，還因貴賤同。"]'),
('yuding-8','和崔中丞中秋月','張南史','唐','御定全唐诗','yuding','','[]','秋夜月偏明，西樓獨有情。千家看露濕，萬里覺天清。',48,'御定全唐詩/json/296.json','["秋夜月偏明，西樓獨有情。千家看露濕，萬里覺天清。", "映水金波動，銜山桂樹生。不知飛鵲意，何用此時驚。"]'),
('yuding-9','西陵懷靈一上人兼寄朱放','張南史','唐','御定全唐诗','yuding','','[]','淮海風濤起，江關憂思長。同悲鵲繞樹，獨坐雁隨陽。',48,'御定全唐詩/json/296.json','["淮海風濤起，江關憂思長。同悲鵲繞樹，獨坐雁隨陽。", "山晚雲藏雪，汀寒月照霜。由來濯纓處，漁父愛滄浪。"]'),
('yuding-10','寄靜虛上人雲門','張南史','唐','御定全唐诗','yuding','','[]','寒日白雲裏，法侶自提攜。竹徑通城下，松門隔水西。',48,'御定全唐詩/json/296.json','["寒日白雲裏，法侶自提攜。竹徑通城下，松門隔水西。", "方同沃洲去，不自武陵迷。仿佛心疑處，高峰是會稽。"]'),
('yuding-11','送司空十四北游宋州','張南史','唐','御定全唐诗','yuding','','[]','九拒危城下，蕭條送爾歸。寒風吹畫角，暮雪犯征衣。',48,'御定全唐詩/json/296.json','["九拒危城下，蕭條送爾歸。寒風吹畫角，暮雪犯征衣。", "道裏猶成間，親朋重與違。白雲愁欲斷，看入大樑飛。"]'),
('yuding-12','殷卿宅夜宴','張南史','唐','御定全唐诗','yuding','','[]','日暗城烏宿，天寒櫪馬嘶。詞人留上客，妓女出中閨。',48,'御定全唐詩/json/296.json','["日暗城烏宿，天寒櫪馬嘶。詞人留上客，妓女出中閨。", "積雪連燈照，回廊映竹迷。太常今夜宴，誰不醉如泥。"]'),
('yuding-13','宣城雪後還望郡中寄孟侍禦','張南史','唐','御定全唐诗','yuding','','[]','臘後年華變，關西驛騎遙。塞鴻連暮雪，江柳動寒條。',48,'御定全唐詩/json/296.json','["臘後年華變，關西驛騎遙。塞鴻連暮雪，江柳動寒條。", "山水還鄣郡，圖書入漢朝。高樓非別處，故使百憂銷。"]'),
('yuding-14','獨孤常州北亭','張南史','唐','御定全唐诗','yuding','','[]','北洫敞高明，憑軒見野情。朝回五馬跡，更勝百花名。',72,'御定全唐詩/json/296.json','["北洫敞高明，憑軒見野情。朝回五馬跡，更勝百花名。", "海樹凝煙遠，湖田見鶴清。雲光侵素壁，水影蕩閑楹。", "俗賴褰帷謁，人歡倒屣迎。始能崇結構，獨有謝宣城。"]'),
('yuding-15','早春書事奉寄中書李舍人','張南史','唐','御定全唐诗','yuding','','[]','儒服山東士，衡門洛下居。風塵游上路，簡冊委空廬。',362,'御定全唐詩/json/296.json','["儒服山東士，衡門洛下居。風塵游上路，簡冊委空廬。", "戎馬生郊日，賢人避地初。竄身初浩蕩，投跡豈躊躇。", "翠羽憐窮鳥，瓊枝顧散樗。還令親道術，倒欲混樵漁。", "敝縕袍多補，飛蓬鬢少梳。誦詩陪賈誼，酌酒伴應璩。", "鶴膝兵家備，鳧茨儉歲儲。泊舟依野水，開徑接園蔬。", "暫閱柔佛巴魯澤，長懷故里閭。思賢乘朗月，覽古到荒墟。", "在竹慚充箭，為蘭倖免鋤。那堪聞相府，更遣詣公車。", "蹇足終難進，顰眉竟未舒。事從因病止，生寄負恩餘。", "不見神仙久，無由鄙吝祛。帝庭張禮樂，天閣繡簪裾。", "日色浮青瑣，香煙近玉除。神清王子敬，氣逐馬相如。", "銅漏時常靜，金門步轉徐。唯看五字表，不記八行書。", "宿昔投知己，周旋謝起予。只應高位隔，詎是故情疏。", "為報周多士，須憐楚子虛。一身從棄置，四節苦居諸。", "柳發三條陌，花飛六輔渠。靈盤浸沆瀣，龍首映儲胥。", "北海樽留客，西江水救魚。長安同日遠，不敢詠歸歟。"]'),
('yuding-16','陸勝宅秋暮雨中探韻同作','張南史','唐','御定全唐诗','yuding','','[]','同人永日自相將，深竹閑園偶辟疆。已被秋風教憶鱠，',40,'御定全唐詩/json/296.json','["同人永日自相將，深竹閑園偶辟疆。已被秋風教憶鱠，", "醉裏欲尋騎馬路，蕭條幾處有垂楊。"]'),
('yuding-17','春日道中寄孟侍禦','張南史','唐','御定全唐诗','yuding','','[]','春來遊子傍歸路，時有白雲遮獨行。水流亂赴石潭響，',40,'御定全唐詩/json/296.json','["春來遊子傍歸路，時有白雲遮獨行。水流亂赴石潭響，", "昨日已嘗村酒熟，一杯思與孟嘉傾。"]'),
('yuding-18','江北春望贈皇甫補闕','張南史','唐','御定全唐诗','yuding','','[]','閑園柳綠井桃紅，野徑荒墟左右通。清迥獨連江水北，',40,'御定全唐詩/json/296.json','["閑園柳綠井桃紅，野徑荒墟左右通。清迥獨連江水北，", "聞道金門堪避世，何須身與海鷗同。"]'),
('yuding-19','酬張二倉曹楊子閒居見寄兼呈韓郎中左補闕皇甫冉','張南史','唐','御定全唐诗','yuding','','[]','孤雲獨鶴自悠悠，別後經年尚泊舟。漁父致詞相借問，',40,'御定全唐詩/json/296.json','["孤雲獨鶴自悠悠，別後經年尚泊舟。漁父致詞相借問，", "莫怪杜門頻乞假，不堪扶病拜龍樓。"]'),
('yuding-20','秋夜聞雁寄南十五兼呈空和尚','張南史','唐','御定全唐诗','yuding','','[]','晚節聞君道趣深，結茅栽樹近東林。禪師幾度曾摩頂，',40,'御定全唐詩/json/296.json','["晚節聞君道趣深，結茅栽樹近東林。禪師幾度曾摩頂，", "不見支公與玄度，相思擁膝坐長吟。"]'),
('yuding-21','雪','張南史','唐','御定全唐诗','yuding','','[]','雪，雪。花片，玉屑。結陰風，凝暮節。高嶺虛晶，',23,'御定全唐詩/json/296.json','["雪，雪。花片，玉屑。結陰風，凝暮節。高嶺虛晶，"]'),
('yuding-22','月','張南史','唐','御定全唐诗','yuding','','[]','月，月。暫盈，還缺。上虛空，生溟渤。散彩無際，',23,'御定全唐詩/json/296.json','["月，月。暫盈，還缺。上虛空，生溟渤。散彩無際，"]'),
('yuding-23','泉','張南史','唐','御定全唐诗','yuding','','[]','泉，泉。色淨，苔鮮。石上激，雲中懸。津流竹樹，',23,'御定全唐詩/json/296.json','["泉，泉。色淨，苔鮮。石上激，雲中懸。津流竹樹，"]'),
('yuding-24','竹','張南史','唐','御定全唐诗','yuding','','[]','竹，竹。披山，連穀。出東南，殊草木。葉細枝勁，',23,'御定全唐詩/json/296.json','["竹，竹。披山，連穀。出東南，殊草木。葉細枝勁，"]'),
('yuding-25','花','張南史','唐','御定全唐诗','yuding','','[]','花，花。深淺，芬葩。凝為雪，錯為霞。鶯和蝶到，',23,'御定全唐詩/json/296.json','["花，花。深淺，芬葩。凝為雪，錯為霞。鶯和蝶到，"]'),
('yuding-26','草','張南史','唐','御定全唐诗','yuding','','[]','草，草。折宜，看好。滿地生，催人老。金殿玉砌，',23,'御定全唐詩/json/296.json','["草，草。折宜，看好。滿地生，催人老。金殿玉砌，"]'),
('yuding-0','送人','王建','唐','御定全唐诗','yuding','','[]','白日向西沒，黃河複東流。人生足著地，甯免四方遊。',144,'御定全唐詩/json/297.json','["白日向西沒，黃河複東流。人生足著地，甯免四方遊。", "我行無返顧，祝子勿回頭。當須向前去，何用起離憂。", "但恐無廣路，平地作山丘。令我車與馬，欲疾反停留。", "蜀客多積貨，邊人易封侯。男兒戀家鄉，歡樂為仇讎。", "丁寧相勸勉，苦口幸無尤。對面無相成，不如豺虎儔。", "彼遠不寄書，此寒莫寄裘。與君俱絕跡，兩念無因由。"]'),
('yuding-1','主人故亭','王建','唐','御定全唐诗','yuding','','[]','主人昔專城，城南起高亭。貴與賓客遊，工者夜不寧。',168,'御定全唐詩/json/297.json','["主人昔專城，城南起高亭。貴與賓客遊，工者夜不寧。", "酒食宴圃人，栽接望早成。經年使家僮，遠道求異英。", "郡中暫閒暇，繞樹引諸生。開泉浴山禽，為愛山中聲。", "世間事難保，一日各徂征。死生不相及，花落實方榮。", "我來至此中，守吏非本名。重君昔為主，相與下馬行。", "舊島日日摧，池水不復清。豈無後人賞，所貴手自營。", "澆酒向所思，風起如有靈。此去不重來，重來傷我形。"]'),
('yuding-2','古從軍','王建','唐','御定全唐诗','yuding','','[]','漢家逐單于，日沒處河曲。浮雲道旁起，行子車下宿。',96,'御定全唐詩/json/297.json','["漢家逐單于，日沒處河曲。浮雲道旁起，行子車下宿。", "槍城圍鼓角，氈帳依山谷。馬上懸壺漿，刀頭分頰肉。", "來時高堂上，父母親結束。回面不見家，風吹破衣服。", "金瘡在肢節，相與拔箭鏃。聞道西涼州，家家婦女哭。"]'),
('yuding-3','邯鄲主人','王建','唐','御定全唐诗','yuding','','[]','遠客無主人，夜投邯鄲市。飛蛾繞殘燭，半夜人醉起。',96,'御定全唐詩/json/297.json','["遠客無主人，夜投邯鄲市。飛蛾繞殘燭，半夜人醉起。", "壚邊酒家女，遺我緗綺被。合成雙鳳花，宛轉不相離。", "縱令顏色改，勿遣合歡異。一念始為難，萬金誰足貴。", "門前長安道，去者如流水。晨風群鳥翔，裴回別離此。"]'),
('yuding-4','泛水曲','王建','唐','御定全唐诗','yuding','','[]','載酒入煙浦，方舟泛綠波。子酌我複飲，子飲我還歌。',72,'御定全唐詩/json/297.json','["載酒入煙浦，方舟泛綠波。子酌我複飲，子飲我還歌。", "蓮深微路通，峰曲幽氣多。閱芳無留瞬，弄桂不停柯。", "水上秋日鮮，西山碧峨峨。茲歡良可貴，誰複更來過。"]'),
('yuding-5','江南雜體二首','王建','唐','御定全唐诗','yuding','','[]','江上風翛翛，竹間湘水流。日夜桂花落，行人去悠悠。',72,'御定全唐詩/json/297.json','["江上風翛翛，竹間湘水流。日夜桂花落，行人去悠悠。", "複見離別處，蟲聲陰雨秋。", "處處江草綠，行人發瀟湘。瀟湘回雁多，日夜思故鄉。", "春夢不知數，空山蘭蕙芳。"]'),
('yuding-6','遠征歸','王建','唐','御定全唐诗','yuding','','[]','萬里發遼陽，處處問家鄉。回車不淹轍，雨雪滿衣裳。',48,'御定全唐詩/json/297.json','["萬里發遼陽，處處問家鄉。回車不淹轍，雨雪滿衣裳。", "行見日月疾，坐思道路長。但令不征戍，暗鏡生重光。"]'),
('yuding-7','思遠人','王建','唐','御定全唐诗','yuding','','[]','妾思常懸懸，君行複綿綿。征途向何處，碧海與青天。',48,'御定全唐詩/json/297.json','["妾思常懸懸，君行複綿綿。征途向何處，碧海與青天。", "歲久自有念，誰令長在邊。少年若不歸，蘭室如黃泉。"]'),
('yuding-8','傷近者不見','王建','唐','御定全唐诗','yuding','','[]','離人隔中庭，幸不為遠征。雕梁下有壁，聞語亦聞行。',48,'御定全唐詩/json/297.json','["離人隔中庭，幸不為遠征。雕梁下有壁，聞語亦聞行。", "天涯尚寄信，此處不傳情。君能並照水，形影自分明。"]'),
('yuding-9','元日早朝','王建','唐','御定全唐诗','yuding','','[]','大國禮樂備，萬邦朝元正。東方色未動，冠劍門已盈。',192,'御定全唐詩/json/297.json','["大國禮樂備，萬邦朝元正。東方色未動，冠劍門已盈。", "帝居在蓬萊，肅肅鐘漏清。將軍領羽林，持戟巡宮城。", "翠華皆宿陳，雪仗羅天兵。庭燎遠煌煌，旗上日月明。", "聖人龍火衣，寢殿開璿扃。龍樓橫紫煙，宮女天中行。", "六蕃倍位次，衣服各異形。舉頭看玉牌，不識宮殿名。", "左右雉扇開，蹈舞分滿庭。朝服帶金玉，珊珊相觸聲。", "泰階備雅樂，九奏鸞鳳鳴。裴回慶雲中，竽磬寒錚錚。", "三公再獻壽，上帝錫永貞。天明告四方，群後保太平。"]'),
('yuding-10','聞故人自征戍回','王建','唐','御定全唐诗','yuding','','[]','昔聞著征戍，三年一還鄉。今來不換兵，須死在戰場。',132,'御定全唐詩/json/297.json','["昔聞著征戍，三年一還鄉。今來不換兵，須死在戰場。", "念子無氣力，徒學事戎行。少年得生還，有同墮穹蒼。", "自去報爾家，再行上高堂。爾弟修廢櫪，爾母縫新裳。", "恍恍恐不真，猶未苦承望。每日空出城，畏渴攜壺漿。", "安得縮地經，忽使在我傍。亦知遠行勞，人悴馬玄黃。", "慎莫多停留，苦我居者腸。"]'),
('yuding-11','七泉寺上方','王建','唐','御定全唐诗','yuding','','[]','長年好名山，本性今得從。回看塵跡遙，稍見麋鹿蹤。',120,'御定全唐詩/json/297.json','["長年好名山，本性今得從。回看塵跡遙，稍見麋鹿蹤。", "老僧雲中居，石門青重重。陰泉養成龜，古壁飛卻龍。", "掃石禮新經，懸幡上高峰。日夕猿鳥合，覓食聽山鐘。", "將火尋遠泉，煮茶傍寒松。晚隨收藥人，便宿南澗中。", "晨起沖露行，濕花枝茸茸。歸依向禪師，願作香火翁。"]'),
('yuding-12','從元太守夏宴西樓','王建','唐','御定全唐诗','yuding','','[]','六月晨亦熱，卑居多煩昏。五馬遊西城，几杖隨朱輪。',96,'御定全唐詩/json/297.json','["六月晨亦熱，卑居多煩昏。五馬遊西城，几杖隨朱輪。", "西樓臨方塘，嘉木當華軒。鳧鷖滿中流，有酒複盈尊。", "山東地無山，平視大海垠。高風涼氣來，灝景沈清源。", "青衿儼坐傍，禮容益敦敦。願為顏氏徒，歌詠夫子門。"]'),
('yuding-13','酬柏侍禦聞與韋處士同遊靈台寺見寄','王建','唐','御定全唐诗','yuding','','[]','西域傳中說，靈臺屬雍州。有泉皆聖跡，有石皆佛頭。',240,'御定全唐詩/json/297.json','["西域傳中說，靈臺屬雍州。有泉皆聖跡，有石皆佛頭。", "所出薝蔔香，外國俗來求。毒蛇護其下，樵者不可偷。", "古碑在雲巔，備載置寺由。魏家移下來，後人始增修。", "近與韋處士，愛此山之幽。各自具所須，竹籠盛茶甌。", "牽馬過危棧，襞衣涉奔流。草開平路盡，林下大石稠。", "過郭轉經峰，忽見東西樓。瀑布當寺門，迸落衣裳秋。", "石苔鋪紫花，溪葉裁碧油。松根載殿高，飄颻仙山浮。", "縣中賢大夫，一月前此遊。賽神賀得雨，豈暇多停留。", "二十韻新詩，遠寄尋山儔。清泠玉澗泣，冷切石磬愁。", "君名高難閑，餘身愚終休。相將長無因，從今生離憂。"]'),
('yuding-14','荊南贈別李肇著作轉韻詩','王建','唐','御定全唐诗','yuding','','[]','輝天複耀地，再為歌詠始。素傳學道徒，清門有君子。',288,'御定全唐詩/json/297.json','["輝天複耀地，再為歌詠始。素傳學道徒，清門有君子。", "文澗瀉潺潺，德峰來壘壘。兩京二十年，投食公卿間。", "封章既不下，故舊多慚顏。賣馬市耕牛，卻歸湘浦山。", "麥收蠶上簇，衣食應豐足。碧澗伴僧禪，秋山對雨宿。", "且歡身體適，倖免纓組束。上宰鎮荊州，敬重同歲遊。", "歡逢通世友，簡授畫戎籌。遲遲就公食，愴愴別野裘。", "主人開宴席，禮數無形跡。醉笑或顛吟，發談皆損益。", "臨甃理芳鮮，升堂引賓客。早歲慕嘉名，遠思今始平。", "孔門忝同轍，潘館幸諸甥。自知再婚娶，豈望為親情。", "欣欣還切切，又二千里別。楚筆防寄書，蜀茶憂遠熱。", "關山足重疊，會合何時節。莫歎各從軍，且愁岐路分。", "美人停玉指，離瑟不中聞。爭向巴山夜，猿聲滿碧雲。"]'),
('yuding-15','早發金堤驛','王建','唐','御定全唐诗','yuding','','[]','蟲聲四野合，月色滿城白。家家閉戶眠，行人發孤驛。',96,'御定全唐詩/json/297.json','["蟲聲四野合，月色滿城白。家家閉戶眠，行人發孤驛。", "離家尚苦熱，衣服唯輕綌。時節忽複遷，秋風徹經脈。", "人睡落塹轍，馬驚入蘆荻。慰遠時問程，驚昏忽搖策。", "從軍豈雲樂，憂患常縈積。唯願在貧家，團圓過朝夕。"]'),
('yuding-16','和裴相公道中贈別張相公','王建','唐','御定全唐诗','yuding','','[]','雲間雙鳳鳴，一去一歸城。鞍馬朝天色，封章戀闕情。',48,'御定全唐詩/json/297.json','["雲間雙鳳鳴，一去一歸城。鞍馬朝天色，封章戀闕情。", "日臨宮樹高，煙蓋沙草平。會當戎事息，聯影繞池行。"]'),
('yuding-17','和錢舍人水植詩','王建','唐','御定全唐诗','yuding','','[]','盆裏盛野泉，晚鮮幽更好。初活草根浮，重生荷葉小。',48,'御定全唐詩/json/297.json','["盆裏盛野泉，晚鮮幽更好。初活草根浮，重生荷葉小。", "多時水馬出，盡日蜻蜓繞。朝早獨來看，冷星沈碧曉。"]'),
('yuding-18','題壽安南館','王建','唐','御定全唐诗','yuding','','[]','明蒙竹間亭，天暖幽桂碧。雲生四面山，水接當階石。',48,'御定全唐詩/json/297.json','["明蒙竹間亭，天暖幽桂碧。雲生四面山，水接當階石。", "濕樹浴鳥痕，破苔臥鹿跡。不緣塵駕觸，堪作商皓宅。"]'),
('yuding-19','送張籍歸江東','王建','唐','御定全唐诗','yuding','','[]','清泉浣塵緇，靈藥釋昏狂。君詩發大雅，正氣回我腸。',204,'御定全唐詩/json/297.json','["清泉浣塵緇，靈藥釋昏狂。君詩發大雅，正氣回我腸。", "複令五彩姿，潔白歸天常。昔歲同講道，青襟在師傍。", "出處兩相因，如彼衣與裳。行行成此歸，離我適咸陽。", "失意未還家，馬蹄盡四方。訪余詠新文，不倦道路長。", "僮僕懷昔念，亦如還故鄉。相親惜晝夜，寢息不異床。", "猶將在遠道，忽忽起思量。黃金未為罍，無以挹酒漿。", "所念俱貧賤，安得相發揚。回車遠歸省，舊宅江南廂。", "歸鄉非得意，但貴情義彰。五月天氣熱，波濤毒于湯。", "慎勿多飲酒，藥膳願自強。"]'),
('yuding-20','勵學','王建','唐','御定全唐诗','yuding','','[]','買地不肥實，其繁系耕鑿。良田少鋤理，蘭焦香亦薄。',96,'御定全唐詩/json/297.json','["買地不肥實，其繁系耕鑿。良田少鋤理，蘭焦香亦薄。", "勿以聽者迷，故使宮征錯。誰言三歲童，還能分善惡。", "孜孜日求益，猶恐業未博。況我性頑蒙，複不勤修學。", "有如朝暮食，暫虧憂隕獲。若使無六經，賢愚何所托。"]'),
('yuding-21','山中寄及第故人','王建','唐','御定全唐诗','yuding','','[]','長長南山松，短短北澗楊。俱承日月照，倖免斤斧傷。',168,'御定全唐詩/json/297.json','["長長南山松，短短北澗楊。俱承日月照，倖免斤斧傷。", "去年與子別，誠言暫還鄉。如何棄我去，天路忽騰驤。", "誰謂有雙目，識貌不識腸。豈知心內乖，著我薜蘿裳。", "尋君向前事，不歎今異翔。往往空室中，寤寐說珪璋。", "十年居此溪，松桂日蒼蒼。自從無佳人，山中不輝光。", "盡棄所留藥，亦焚舊草堂。還君誓已書，歸我學仙方。", "既為參與辰，各願不相望。始終名利途，慎勿罹咎殃。"]'),
('yuding-22','求友','王建','唐','御定全唐诗','yuding','','[]','鑒形須明鏡，療疾須良醫。若無傍人見，形疾安自知。',168,'御定全唐詩/json/297.json','["鑒形須明鏡，療疾須良醫。若無傍人見，形疾安自知。", "世路薄言行，學成棄其師。每懷一飯恩，不重勸勉詞。", "斅學既不誠，朋友道日虧。遂作名利交，四海爭賓士。", "常慕正直人，生死不相離。苟能成我身，甘與僮僕隨。", "我言彼當信，彼道我無疑。針藥及病源，以石投深池。", "終朝舉善道，敬愛當行之。縱令誤所見，亦貴本相規。", "不求立名聲，所貴去瑕玼。各願貽子孫，永為後世資。"]'),
('yuding-23','寄李益少監兼送張實游幽州','王建','唐','御定全唐诗','yuding','','[]','大雅廢已久，人倫失其常。天若不生君，誰複為文綱。',192,'御定全唐詩/json/297.json','["大雅廢已久，人倫失其常。天若不生君，誰複為文綱。", "迷者得道路，溺者遇舟航。國風人已變，山澤增輝光。", "星辰有其位，豈合離帝傍。賢人既遐征，鳳鳥安來翔。", "少小慕高名，所念隔山岡。集卷新紙封，每讀常焚香。", "古來難自達，取鑒在賢良。未為知音故，徒恨名不彰。", "諒無金石堅，性命豈能長。常恐一世中，不上君子堂。", "偉哉清河子，少年志堅強。篋中有素文，千里求發揚。", "自顧音韻乖，無因合宮商。幸君達精誠，為我求回章。"]'),
('yuding-24','寄崔列中丞','王建','唐','御定全唐诗','yuding','','[]','火山無冷地，濁流無清源。人生在艱世，何處避讒言。',156,'御定全唐詩/json/297.json','["火山無冷地，濁流無清源。人生在艱世，何處避讒言。", "諸侯鎮九州，天子開四門。尚有忠義士，不得申其冤。", "嘉木移遠植，為我當行軒。君子居要途，易失主人恩。", "我愛古人道，師君直且溫。貪泉誓不飲，邪路誓不奔。", "如何非岡阪，故使車輪翻。妓妾隨他人，家事幸獲存。", "當時門前客，默默空冤煩。從今遇明代，善惡亦須論。", "莫以曾見疑，直道遂不敦。"]'),
('yuding-25','喻時','王建','唐','御定全唐诗','yuding','','[]','去者如弊帷，來者如新衣。鮮華非久長，色落還棄遺。',84,'御定全唐詩/json/297.json','["去者如弊帷，來者如新衣。鮮華非久長，色落還棄遺。", "詎知行者夭，豈悟壯者衰。區區未死間，回面相是非。", "好聞苦不樂，好視忽生疵。乃明萬物情，皆逐人心移。", "古今盡如此，達士將何為。"]'),
('yuding-26','贈王侍禦','王建','唐','御定全唐诗','yuding','','[]','愚者昧邪正，貴將平道行。君子抱仁義，不懼天地傾。',168,'御定全唐詩/json/297.json','["愚者昧邪正，貴將平道行。君子抱仁義，不懼天地傾。", "三受主人辟，方出咸陽城。遲疑匪自崇，將顯求賢名。", "自來掌軍書，無不盡臣誠。何必操白刃，始致海內平。", "恭事四海人，甚於敬公卿。有惡如己辱，聞善如己榮。", "或人居饑寒，進退陳中情。徹晏聽苦辛，坐臥身不寧。", "以心應所求，盡家猶為輕。衣食有親疏，但恐逾禮經。", "我今願求益，詎敢為友生。幸君揚素風，永作來者程。"]'),
('yuding-27','宋氏五女','王建','唐','御定全唐诗','yuding','','[]','五女誓終養，貞孝內自持。兔絲自縈紆，不上青松枝。',120,'御定全唐詩/json/297.json','["五女誓終養，貞孝內自持。兔絲自縈紆，不上青松枝。", "晨昏在親傍，閑則讀書詩。自得聖人心，不因儒者知。", "少年絕音華，貴絕父母詞。素釵垂兩髦，短窄古時衣。", "行成聞四方，征詔環佩隨。同時入皇宮，聯影步玉墀。", "鄉中尚其風，重為修茅茨。聖朝有良史，將此為女師。"]'),
('yuding-28','送於丹移家洺州','王建','唐','御定全唐诗','yuding','','[]','憶昔門館前，君當童子年。今來見成長，俱過遠所傳。',216,'御定全唐詩/json/297.json','["憶昔門館前，君當童子年。今來見成長，俱過遠所傳。", "詩禮不外學，兄弟相攻研。如彼販海翁，豈種溪中田。", "四方尚爾文，獨我敬爾賢。但愛金玉聲，不貴金玉堅。", "孤遺一室中，寢食不相捐。飽如腸胃同，疾苦膚體連。", "耕者求沃土，漚者求深源。彼邦君子居，一日可徂遷。", "念此居處近，各為衣食牽。從今不見面，猶勝異山川。", "既乖歡會期，鬱鬱兩難宣。素琴苦無徽，安得宮商全。", "他皆緩別日，我願促行軒。送人莫長歌，長歌離恨延。", "羸馬不知去，過門常盤旋。會當為爾鄰，有地容一泉。"]'),
('yuding-29','留別舍弟','王建','唐','御定全唐诗','yuding','','[]','孤賤相長育，未曾為遠遊。誰不重歡愛，晨昏闕珍羞。',144,'御定全唐詩/json/297.json','["孤賤相長育，未曾為遠遊。誰不重歡愛，晨昏闕珍羞。", "出門念衣單，草木當窮秋。非疾有憂歎，實為人子尤。", "世情本難合，對面隔山丘。況複干戈地，懦夫何所投。", "與爾俱長成，尚為溝壑憂。豈非輕歲月，少小不勤修。", "從今解思量，勉力謀善猷。但得成爾身，衣食寧我求。", "固合受此訓，墮慢為身羞。歲暮當歸來，慎莫懷遠遊。"]'),
('yuding-30','壞屋','王建','唐','御定全唐诗','yuding','','[]','官家有壞屋，居者願離得。苟或幸其遷，回循任傾側。',96,'御定全唐詩/json/297.json','["官家有壞屋，居者願離得。苟或幸其遷，回循任傾側。", "若當君子住，一日還修飾。必使換榱楹，先須木端直。", "永令雀與鼠，無處求棲息。堅固傳後人，從今勉勞力。", "以茲喻臣下，亦可成邦國。雖曰愚者詞，將來幸無惑。"]'),
('yuding-31','送薛蔓應舉','王建','唐','御定全唐诗','yuding','','[]','四海重貢獻，珠贐稱至珍。聖朝開禮闈，所貴集嘉賓。',168,'御定全唐詩/json/297.json','["四海重貢獻，珠贐稱至珍。聖朝開禮闈，所貴集嘉賓。", "若生在世間，此路出常倫。一士登甲科，九族光彩新。", "憧憧車馬徒，爭路長安塵。萬目視高天，升者得苦辛。", "況子當少年，丈人在咸秦。出門見宮闕，獻賦侍朱輪。", "有賢大國豐，無子一家貧。男兒富邦家，豈為榮其身。", "煌煌文明代，俱幸生此辰。自顧非國風，難以合聖人。", "子去東堂上，我歸南澗濱。願君勤作書，與我山中鄰。"]'),
('yuding-32','將歸故山留別杜侍禦','王建','唐','御定全唐诗','yuding','','[]','有川不得涉，有路不得行。沉沉百憂中，一日如一生。',96,'御定全唐詩/json/297.json','["有川不得涉，有路不得行。沉沉百憂中，一日如一生。", "錯來幹諸侯，石田廢春耕。虎戟衛重門，何因達中誠。", "日月俱照輝，山川異陰晴。如何百里間，開目不見明。", "我今歸故山，誓與草木並。願君去丘阪，長使道路平。"]'),
('yuding-33','送韋處士老舅','王建','唐','御定全唐诗','yuding','','[]','憶昨癡小年，不知有經籍。常隨童子游，多向外家劇。',168,'御定全唐詩/json/297.json','["憶昨癡小年，不知有經籍。常隨童子游，多向外家劇。", "偷花入鄰里，弄筆書牆壁。照水學梳頭，應門未穿幘。", "人前賞文性，梨果蒙不惜。賦字詠新泉，探題得幽石。", "自從出關輔，三十年作客。風雨一飄颻，親情多阻隔。", "如何二千里，塵土驅蹇瘠。良久陳苦辛，從頭歎衰白。", "既來今又去，暫笑還成戚。落日動征車，春風卷離席。", "雲台觀西路，華岳祠前柏。會得過帝鄉，重尋舊行跡。"]'),
('yuding-34','送同學故人','王建','唐','御定全唐诗','yuding','','[]','各為四方人，此地同事師。業成有先後，不得長相隨。',72,'御定全唐詩/json/297.json','["各為四方人，此地同事師。業成有先後，不得長相隨。", "出林多道路，緣岡複繞陂。念君辛苦行，令我形體疲。", "黃葉墮車前，四散當此時。亭上夜蕭索，山風水離離。"]'),
('yuding-35','幽州送申稷評事歸平盧','王建','唐','御定全唐诗','yuding','','[]','行子繞天北，山高塞複深。升堂展客禮，臨水濯纓襟。',72,'御定全唐詩/json/297.json','["行子繞天北，山高塞複深。升堂展客禮，臨水濯纓襟。", "驅馳戎地馬，聚散林間禽。一杯瀉東流，各願無異心。", "薊亭雖苦寒，春夕勿重衾。從軍任白頭，莫賣故山岑。"]'),
('yuding-36','溫門山','王建','唐','御定全唐诗','yuding','','[]','早入溫門山，群峰亂如戟。崩崖欲相觸，呀豁斷行跡。',120,'御定全唐詩/json/297.json','["早入溫門山，群峰亂如戟。崩崖欲相觸，呀豁斷行跡。", "脫屐尋淺流，定足畏欹石。路盡十裏溪，地多千歲柏。", "洞門晝陰黑，深處惟石壁。似見丹砂光，亦聞鐘乳滴。", "靈池出山底，沸水沖地脈。暖氣成濕煙，濛濛窗中白。", "隨僧入古寺，便是雲外客。月出天氣涼，夜鐘山寂寂。"]'),
('yuding-37','代故人新姬侍疾','王建','唐','御定全唐诗','yuding','','[]','雙轂不回轍，子疾已在旁。侍坐長搖扇，迎醫漸下床。',48,'御定全唐詩/json/297.json','["雙轂不回轍，子疾已在旁。侍坐長搖扇，迎醫漸下床。", "新施箱中幔，未洗來時妝。奉君纏綿意，幸願莫相忘。"]'),
('yuding-38','采桑','王建','唐','御定全唐诗','yuding','','[]','鳥鳴桑葉間，綠條複柔柔。攀看去手近，放下長長鉤。',48,'御定全唐詩/json/297.json','["鳥鳴桑葉間，綠條複柔柔。攀看去手近，放下長長鉤。", "黃花蓋野田，白馬少年游。所念豈回顧，良人在高樓。"]'),
('yuding-39','曉思','王建','唐','御定全唐诗','yuding','','[]','曉氣生綠水，春條露霏霏。林間棲鳥散，遠念征人起。',48,'御定全唐詩/json/297.json','["曉氣生綠水，春條露霏霏。林間棲鳥散，遠念征人起。", "幽花宿含彩，早蝶寒弄翅。君行非晨風，詎能從門至。"]'),
('yuding-40','早起','王建','唐','御定全唐诗','yuding','','[]','回燈正衣裳，出戶星未稀。堂前候姑起，環佩生晨輝。',49,'御定全唐詩/json/297.json','["回燈正衣裳，出戶星未稀。堂前候姑起，環佩生晨輝。", "暗池光冪zx，密樹花葳蕤。九城鐘漏絕，遙聽直郎歸。"]'),
('yuding-41','酬張十八病中寄詩','王建','唐','御定全唐诗','yuding','','[]','本性慵遠行，綿綿病自生。見君綢繆思，慰我寂寞情。',48,'御定全唐詩/json/297.json','["本性慵遠行，綿綿病自生。見君綢繆思，慰我寂寞情。", "風幌夜不掩，秋燈照雨明。彼愁此又憶，一夕兩盈盈。"]'),
('yuding-0','涼州行','王建','唐','御定全唐诗','yuding','','[]','涼州四邊沙皓皓，漢家無人開舊道。邊頭州縣盡胡兵，',72,'御定全唐詩/json/298.json','["涼州四邊沙皓皓，漢家無人開舊道。邊頭州縣盡胡兵，", "多來中國收婦女，一半生男為漢語。蕃人舊日不耕犁，", "養蠶繰繭成匹帛，那堪繞帳作旌旗。城頭山雞鳴角角，"]'),
('yuding-1','寒食行','王建','唐','御定全唐诗','yuding','','[]','寒食家家出古城，老人看屋少年行。丘壟年年無舊道，',48,'御定全唐詩/json/298.json','["寒食家家出古城，老人看屋少年行。丘壟年年無舊道，", "遠人無墳水頭祭，還引婦姑望鄉拜。三日無火燒紙錢，"]'),
('yuding-2','促刺詞','王建','唐','御定全唐诗','yuding','','[]','促刺複促刺，水中無魚山無石。少年雖嫁不得歸，',46,'御定全唐詩/json/298.json','["促刺複促刺，水中無魚山無石。少年雖嫁不得歸，", "出門若有歸死處，猛虎當衢向前去。百年不遣踏君門，"]'),
('yuding-3','壟頭水','王建','唐','御定全唐诗','yuding','','[]','壟水何年壟頭別，不在山中亦嗚咽。征人塞耳馬不行，',48,'御定全唐詩/json/298.json','["壟水何年壟頭別，不在山中亦嗚咽。征人塞耳馬不行，", "壟東壟西多屈曲，野麋飲水長簇簇。胡兵夜回水旁住，"]'),
('yuding-4','北邙行','王建','唐','御定全唐诗','yuding','','[]','北邙山頭少閑土，儘是洛陽人舊墓。舊墓人家歸葬多，',72,'御定全唐詩/json/298.json','["北邙山頭少閑土，儘是洛陽人舊墓。舊墓人家歸葬多，", "高張素幕繞銘旌，夜唱挽歌山下宿。洛陽城北複城東，", "澗底盤陀石漸稀，盡向墳前作羊虎。誰家石碑文字滅，"]'),
('yuding-5','溫泉宮行','王建','唐','御定全唐诗','yuding','','[]','十月一日天子來，青繩禦路無塵埃。宮前內裏湯各別，',72,'御定全唐詩/json/298.json','["十月一日天子來，青繩禦路無塵埃。宮前內裏湯各別，", "夜開金殿看星河，宮女知更月明裏。武皇得仙王母去，", "禁兵去盡無射獵，日西麋鹿登城頭。梨園弟子偷曲譜，"]'),
('yuding-6','春詞','王建','唐','御定全唐诗','yuding','','[]','紅煙滿戶日照梁，天絲軟弱蟲飛揚。菱花霍霍繞帷光，',24,'御定全唐詩/json/298.json','["紅煙滿戶日照梁，天絲軟弱蟲飛揚。菱花霍霍繞帷光，"]'),
('yuding-7','遼東行','王建','唐','御定全唐诗','yuding','','[]','遼東萬里遼水曲，古戍無城複無屋。黃雲蓋地雪作山，',48,'御定全唐詩/json/298.json','["遼東萬里遼水曲，古戍無城複無屋。黃雲蓋地雪作山，", "年年郡縣送征人，將與遼東作丘阪。寧為草木鄉中生，"]'),
('yuding-8','塞上梅','王建','唐','御定全唐诗','yuding','','[]','天山路傍一株梅，年年花發黃雲下。昭君已歿漢使回，',40,'御定全唐詩/json/298.json','["天山路傍一株梅，年年花發黃雲下。昭君已歿漢使回，", "此花若近長安路，九衢年少無攀處。"]'),
('yuding-9','戴勝詞','王建','唐','御定全唐诗','yuding','','[]','戴勝誰與爾為名，木中作窠牆上鳴。聲聲催我急種穀，',40,'御定全唐詩/json/298.json','["戴勝誰與爾為名，木中作窠牆上鳴。聲聲催我急種穀，", "可憐白鷺滿綠池，不如戴勝知天時。"]'),
('yuding-10','秋千詞','王建','唐','御定全唐诗','yuding','','[]','長長絲繩紫複碧，嫋嫋橫枝高百尺。少年兒女重秋千，',64,'御定全唐詩/json/298.json','["長長絲繩紫複碧，嫋嫋橫枝高百尺。少年兒女重秋千，", "下來立定重系衣，複畏斜風高不得。傍人送上那足貴，", "眼前爭勝難為休，足踏平地看始愁。"]'),
('yuding-11','開池得古釵','王建','唐','御定全唐诗','yuding','','[]','美人開池北堂下，拾得寶釵金未化。鳳凰半在雙股齊，',48,'御定全唐詩/json/298.json','["美人開池北堂下，拾得寶釵金未化。鳳凰半在雙股齊，", "可知將來對夫婿，鏡前學梳古時髻。莫言至死亦不遺，"]'),
('yuding-12','賽神曲','王建','唐','御定全唐诗','yuding','','[]','男抱琵琶女作舞，主人再拜聽神語。新婦上酒勿辭勤，',48,'御定全唐詩/json/298.json','["男抱琵琶女作舞，主人再拜聽神語。新婦上酒勿辭勤，", "但願牛羊滿家宅，十月報賽南山神。青天無風水複碧，"]'),
('yuding-13','田家留客','王建','唐','御定全唐诗','yuding','','[]','人家少能留我屋，客有新漿馬有粟。遠行僮僕應苦饑，',48,'御定全唐詩/json/298.json','["人家少能留我屋，客有新漿馬有粟。遠行僮僕應苦饑，", "行人但飲莫畏貧。明府上來何苦辛。丁甯回語屋中妻，"]'),
('yuding-14','精衛詞','王建','唐','御定全唐诗','yuding','','[]','精衛誰教爾填海，海邊石子青磊磊。但得海水作枯池，',48,'御定全唐詩/json/298.json','["精衛誰教爾填海，海邊石子青磊磊。但得海水作枯池，", "朝在樹頭暮海裏，飛多羽折時墮水。高山未盡海未平，"]'),
('yuding-15','老婦歎鏡','王建','唐','御定全唐诗','yuding','','[]','嫁時明鏡老猶在，黃金鏤畫雙鳳背。憶昔咸陽初買來，',40,'御定全唐詩/json/298.json','["嫁時明鏡老猶在，黃金鏤畫雙鳳背。憶昔咸陽初買來，", "今日後床重照看，生死終當此長別。"]'),
('yuding-16','望夫石','王建','唐','御定全唐诗','yuding','','[]','望夫處，江悠悠。化為石，不回頭。',32,'御定全唐詩/json/298.json','["望夫處，江悠悠。化為石，不回頭。", "上頭日日風複雨，行人歸來石應語。"]'),
('yuding-17','別鶴曲','王建','唐','御定全唐诗','yuding','','[]','主人一去池水絕，池鶴散飛不相別。青天漫漫碧水重，',40,'御定全唐詩/json/298.json','["主人一去池水絕，池鶴散飛不相別。青天漫漫碧水重，", "池邊巢破松樹死，樹頭年年烏生子。"]'),
('yuding-18','烏棲曲','王建','唐','御定全唐诗','yuding','','[]','章華宮人夜上樓，君王望月西山頭。',32,'御定全唐詩/json/298.json','["章華宮人夜上樓，君王望月西山頭。", "夜深宮殿門不鎖，白露滿山山葉墮。"]'),
('yuding-19','雉將雛','王建','唐','御定全唐诗','yuding','','[]','雉咿喔，雛出ob。毛斑斑，觜啄啄。學飛未得一尺高，',41,'御定全唐詩/json/298.json','["雉咿喔，雛出ob。毛斑斑，觜啄啄。學飛未得一尺高，", "時時土中鼓兩翅，引雛拾蟲不相離。"]'),
('yuding-20','白紵歌二首','王建','唐','御定全唐诗','yuding','','[]','天河漫漫北斗璨，宮中烏啼知夜半。新縫白紵舞衣成，',96,'御定全唐詩/json/298.json','["天河漫漫北斗璨，宮中烏啼知夜半。新縫白紵舞衣成，", "酒多夜長夜未曉，月明燈光兩相照。後庭歌聲更窈窕。", "館娃宮中春日暮，荔枝木瓜花滿樹。城頭烏棲休擊鼓，", "美人醉起無次第，墮釵遺佩滿中庭。此時但願可君意，"]'),
('yuding-21','短歌行','王建','唐','御定全唐诗','yuding','','[]','人初生，日初出。上山遲，下山疾。百年三萬六千朝，',48,'御定全唐詩/json/298.json','["人初生，日初出。上山遲，下山疾。百年三萬六千朝，", "人家見生男女好，不知男女催人老。短歌行，無樂聲。"]'),
('yuding-22','飲馬長城窟','王建','唐','御定全唐诗','yuding','','[]','長城窟，長城窟邊多馬骨。古來此地無井泉，',44,'御定全唐詩/json/298.json','["長城窟，長城窟邊多馬骨。古來此地無井泉，", "蹄蹤未幹人去近，續後馬來泥汙盡。枕弓睡著待水生，"]'),
('yuding-23','烏夜啼','王建','唐','御定全唐诗','yuding','','[]','庭樹烏，爾何不向別處棲，夜夜夜半當戶啼。',84,'御定全唐詩/json/298.json','["庭樹烏，爾何不向別處棲，夜夜夜半當戶啼。", "家人把燭出洞戶，驚棲失群飛落樹。一飛直欲飛上天。", "回回不離舊棲處。未明重繞主人屋，欲下空中黑相觸。", "風飄雨濕亦不移，君家樹頭多好枝。"]'),
('yuding-24','簇蠶辭','王建','唐','御定全唐诗','yuding','','[]','蠶欲老，箔頭作繭絲皓皓。場寬地高風日多，',60,'御定全唐詩/json/298.json','["蠶欲老，箔頭作繭絲皓皓。場寬地高風日多，", "但得青天不下雨，上無蒼蠅下無鼠。新婦拜簇願繭稠，", "已聞鄉里催織作，去與誰人身上著。"]'),
('yuding-25','渡遼水','王建','唐','御定全唐诗','yuding','','[]','渡遼水，此去咸陽五千里。來時父母知隔生，',36,'御定全唐詩/json/298.json','["渡遼水，此去咸陽五千里。來時父母知隔生，", "身在應無回渡日，駐馬相看遼水傍。"]'),
('yuding-26','空城雀','王建','唐','御定全唐诗','yuding','','[]','空城雀，何不飛來人家住，空城無人種禾黍。',68,'御定全唐詩/json/298.json','["空城雀，何不飛來人家住，空城無人種禾黍。", "土間生子草間長，滿地蓬蒿幸無主。近村雖有高樹枝，", "但能不出空城裏，秋時百草皆有子。報言黃口莫啾啾，"]'),
('yuding-27','水運行','王建','唐','御定全唐诗','yuding','','[]','西江運船立紅幟，萬棹千帆繞江水。去年六月無稻苗，',72,'御定全唐詩/json/298.json','["西江運船立紅幟，萬棹千帆繞江水。去年六月無稻苗，", "在生有樂當有苦，三年作官一年行。壞舟畏鼠複畏漏，", "用盡百金不為費，但得一金即為利。遠征海稻供邊食，"]'),
('yuding-28','當窗織','王建','唐','御定全唐诗','yuding','','[]','歎息複歎息，園中有棗行人食。貧家女為富家織。',70,'御定全唐詩/json/298.json','["歎息複歎息，園中有棗行人食。貧家女為富家織。", "翁母隔牆不得力。水寒手澀絲脆斷，續來續去心腸爛。", "草蟲促促機下啼，兩日催成一匹半。輸官上頂有零落，"]'),
('yuding-29','失釵怨','王建','唐','御定全唐诗','yuding','','[]','貧女銅釵惜於玉，失卻來尋一日哭。嫁時女伴與作妝，',48,'御定全唐詩/json/298.json','["貧女銅釵惜於玉，失卻來尋一日哭。嫁時女伴與作妝，", "鏡中乍無失髻樣，初起猶疑在床上。高樓翠鈿飄舞塵，"]'),
('yuding-30','春燕詞','王建','唐','御定全唐诗','yuding','','[]','新燕新燕何不定，東家綠池西家井。飛鳴當戶影悠揚，',48,'御定全唐詩/json/298.json','["新燕新燕何不定，東家綠池西家井。飛鳴當戶影悠揚，", "已能辭山複過海，幸我堂前故巢在。求食慎勿愛高飛，"]'),
('yuding-31','主人故池','王建','唐','御定全唐诗','yuding','','[]','高池高閣上連起，荷葉團團蓋秋水。',32,'御定全唐詩/json/298.json','["高池高閣上連起，荷葉團團蓋秋水。", "主人已遠涼風生，舊客不來芙蓉死。"]'),
('yuding-32','古宮怨','王建','唐','御定全唐诗','yuding','','[]','乳烏啞啞飛複啼，城頭晨夕宮中棲。',32,'御定全唐詩/json/298.json','["乳烏啞啞飛複啼，城頭晨夕宮中棲。", "吳王別殿繞江水，後宮不開美人死。"]'),
('yuding-33','關山月','王建','唐','御定全唐诗','yuding','','[]','關山月，營開道白前軍發。凍輪當磧光悠悠，',20,'御定全唐詩/json/298.json','["關山月，營開道白前軍發。凍輪當磧光悠悠，"]'),
('yuding-34','贈離曲','王建','唐','御定全唐诗','yuding','','[]','合歡葉墮梧桐秋，鴛鴦背飛水分流。少年使我忽相棄。',72,'御定全唐詩/json/298.json','["合歡葉墮梧桐秋，鴛鴦背飛水分流。少年使我忽相棄。", "雌號雄鳴夜悠悠。夜長月沒蟲切切，冷風入房燈焰滅。", "若知中路各西東，彼此不忘同心結。收取頭邊蛟龍枕，"]'),
('yuding-35','宛轉詞','王建','唐','御定全唐诗','yuding','','[]','宛宛轉轉勝上紗，紅紅綠綠苑中花。',32,'御定全唐詩/json/298.json','["宛宛轉轉勝上紗，紅紅綠綠苑中花。", "紛紛泊泊夜飛鴉，寂寂寞寞離人家。"]'),
('yuding-36','水夫謠','王建','唐','御定全唐诗','yuding','','[]','苦哉生長當驛邊，官家使我牽驛船。辛苦日多樂日少，',72,'御定全唐詩/json/298.json','["苦哉生長當驛邊，官家使我牽驛船。辛苦日多樂日少，", "半夜緣堤雪和雨，受他驅遣還複去。衣寒衣濕披短蓑，", "一間茆屋何所直，父母之鄉去不得。我願此水作平田，"]'),
('yuding-37','田家行','王建','唐','御定全唐诗','yuding','','[]','男聲欣欣女顏悅，人家不怨言語別。五月雖熱麥風清，',48,'御定全唐詩/json/298.json','["男聲欣欣女顏悅，人家不怨言語別。五月雖熱麥風清，", "麥收上場絹在軸，的知輸得官家足。不望入口複上身，"]'),
('yuding-38','去婦','王建','唐','御定全唐诗','yuding','','[]','新婦去年胼手足，衣不暇縫蠶廢簇。白頭使我憂家事，',40,'御定全唐詩/json/298.json','["新婦去年胼手足，衣不暇縫蠶廢簇。白頭使我憂家事，", "在時縱嫌織絹遲，有絲不上鄰家機。"]'),
('yuding-39','神樹詞','王建','唐','御定全唐诗','yuding','','[]','我家家西老棠樹，須晴即晴雨即雨。四時八節上杯盤，',40,'御定全唐詩/json/298.json','["我家家西老棠樹，須晴即晴雨即雨。四時八節上杯盤，", "老身長健樹婆娑，萬歲千年作神主。"]'),
('yuding-40','祝鵲','王建','唐','御定全唐诗','yuding','','[]','神鵲神鵲好言語，行人早回多利賂。',32,'御定全唐詩/json/298.json','["神鵲神鵲好言語，行人早回多利賂。", "我今庭中栽好樹，與汝作巢當報汝。"]'),
('yuding-41','古謠','王建','唐','御定全唐诗','yuding','','[]','一東一西壟頭水，一聚一散天邊霞。',32,'御定全唐詩/json/298.json','["一東一西壟頭水，一聚一散天邊霞。", "一來一去道上客，一顛一倒池中麻。"]'),
('yuding-42','公無渡河','王建','唐','御定全唐诗','yuding','','[]','渡頭惡天兩岸遠，波濤塞川如疊阪。幸無白刃驅向前，',48,'御定全唐詩/json/298.json','["渡頭惡天兩岸遠，波濤塞川如疊阪。幸無白刃驅向前，", "男兒縱輕婦人語，惜君性命還須取。婦人無力挽斷衣，"]'),
('yuding-43','海人謠','王建','唐','御定全唐诗','yuding','','[]','海人無家海裏住，采珠役象為歲賦。',32,'御定全唐詩/json/298.json','["海人無家海裏住，采珠役象為歲賦。", "惡波橫天山塞路，未央宮中常滿庫。"]'),
('yuding-44','行見月','王建','唐','御定全唐诗','yuding','','[]','月初生，居人見月一月行。行行一年十二月，',44,'御定全唐詩/json/298.json','["月初生，居人見月一月行。行行一年十二月，", "不緣衣食相驅遣，此身誰願長奔波。篋中有帛倉有粟，"]'),
('yuding-45','七夕曲','王建','唐','御定全唐诗','yuding','','[]','河邊獨自看星宿，夜織天絲難接續。拋梭振鑷動明璫，',80,'御定全唐詩/json/298.json','["河邊獨自看星宿，夜織天絲難接續。拋梭振鑷動明璫，", "流蘇翠帳星渚間，環佩無聲燈寂寂。兩情纏綿忽如故。", "複畏秋風生曉路。幸回郎意且斯須，一年中別今始初。", "明星未出少停車。"]'),
('yuding-46','兩頭纖纖','王建','唐','御定全唐诗','yuding','','[]','兩頭纖纖青玉玦，半白半黑頭上發。',32,'御定全唐詩/json/298.json','["兩頭纖纖青玉玦，半白半黑頭上發。", "逼逼僕僕春冰裂，磊磊落落桃花結。"]'),
('yuding-47','獨漉歌','王建','唐','御定全唐诗','yuding','','[]','獨獨漉漉，鼠食貓肉。烏日中，鶴露宿。黃河水直人心曲。',26,'御定全唐詩/json/298.json','["獨獨漉漉，鼠食貓肉。烏日中，鶴露宿。黃河水直人心曲。"]'),
('yuding-48','寄遠曲','王建','唐','御定全唐诗','yuding','','[]','美人別來無處所，巫山月明湘江雨。千回相見不分明，',24,'御定全唐詩/json/298.json','["美人別來無處所，巫山月明湘江雨。千回相見不分明，"]'),
('yuding-49','傷韋令孔雀詞','王建','唐','御定全唐诗','yuding','','[]','可憐孔雀初得時，美人為爾別開池。池邊鳳凰作伴侶，',48,'御定全唐詩/json/298.json','["可憐孔雀初得時，美人為爾別開池。池邊鳳凰作伴侶，", "如今憔悴人見惡，萬里更求新孔雀。熱眠雨水饑拾蟲，"]'),
('yuding-50','傷鄰家鸚鵡詞','王建','唐','御定全唐诗','yuding','','[]','東家小女不惜錢，買得鸚鵡獨自憐。自從死卻家中女，',48,'御定全唐詩/json/298.json','["東家小女不惜錢，買得鸚鵡獨自憐。自從死卻家中女，", "舌關啞咽畜哀怨，開籠放飛離人眼。短聲亦絕翠臆翻，"]'),
('yuding-51','春來曲','王建','唐','御定全唐诗','yuding','','[]','春欲來，每日望春門早開。黃衫白馬帶塵土，',60,'御定全唐詩/json/298.json','["春欲來，每日望春門早開。黃衫白馬帶塵土，", "青帝少女染桃花，露妝初出紅猶濕。光風暾暾蝶宛宛，", "少年即見春好處，似我白頭無好樹。"]'),
('yuding-52','春去曲','王建','唐','御定全唐诗','yuding','','[]','春已去，花亦不知春去處。緣岡繞澗卻歸來，',36,'御定全唐詩/json/298.json','["春已去，花亦不知春去處。緣岡繞澗卻歸來，", "老夫不比少年兒，不中數與春別離。"]'),
('yuding-53','東征行','王建','唐','御定全唐诗','yuding','','[]','桐柏水西賊星落，梟雛夜飛林木惡。相國刻日波濤清，',72,'御定全唐詩/json/298.json','["桐柏水西賊星落，梟雛夜飛林木惡。相國刻日波濤清，", "玉階舞蹈謝旌節，生死向前山可穴。同時賜馬並賜衣，", "司庖常膳皆得對，好事將軍封爾身。男兒生殺在手裏，"]'),
('yuding-54','荊門行','王建','唐','御定全唐诗','yuding','','[]','江邊行人暮悠悠，山頭殊未見荊州。峴亭西南路多曲，',144,'御定全唐詩/json/298.json','["江邊行人暮悠悠，山頭殊未見荊州。峴亭西南路多曲，", "南中三月蚊蚋生，黃昏不聞人語聲。生紗帷疏薄如霧，", "女兒停客茆屋新，開門掃地桐花裏。犬聲撲撲寒溪煙，", "大蛇過處一山腥，野牛驚跳雙角折。斜分漢水橫千山，", "誰家丹旐已南來，逢著流人從此去。月明山鳥多不棲，", "紅燭交橫各自歸，酒醒還是他鄉客。壯年留滯尚思家，"]'),
('yuding-55','鏡聽詞','王建','唐','御定全唐诗','yuding','','[]','重重摩挲嫁時鏡，夫婿遠行憑鏡聽。回身不遣別人知，',73,'御定全唐詩/json/298.json','["重重摩挲嫁時鏡，夫婿遠行憑鏡聽。回身不遣別人知，", "嗟嗟eP々下堂階，獨自灶前來跪拜。出門願不聞悲哀，", "卷帷上床喜不定。與郎裁衣失翻正。可中三日得相見，"]'),
('yuding-56','行宮詞','王建','唐','御定全唐诗','yuding','','[]','上陽宮到蓬萊殿，行宮岩岩遙相見。向前天子行幸多，',72,'御定全唐詩/json/298.json','["上陽宮到蓬萊殿，行宮岩岩遙相見。向前天子行幸多，", "禁兵奪得明堂後，長閉桃源與綺繡。開元歌舞古草頭，", "兩邊仗屋半崩摧，夜火入林燒殿柱。休封中嶽六十年，"]'),
('yuding-57','羽林行','王建','唐','御定全唐诗','yuding','','[]','長安惡少出名字，樓下劫商樓上醉。天明下直明光宮，',48,'御定全唐詩/json/298.json','["長安惡少出名字，樓下劫商樓上醉。天明下直明光宮，", "九衢一日消息定，鄉吏籍中重改姓。出來依舊屬羽林，"]'),
('yuding-58','射虎行','王建','唐','御定全唐诗','yuding','','[]','自去射虎得虎歸，官差射虎得虎遲。獨行以死當虎命，',48,'御定全唐詩/json/298.json','["自去射虎得虎歸，官差射虎得虎遲。獨行以死當虎命，", "遠立不敢汙箭鏃，聞死還來分虎肉。惜留猛虎著深山，"]'),
('yuding-59','遠將歸','王建','唐','御定全唐诗','yuding','','[]','遠將歸，勝未別離時。在家相見熟，新歸歡不足。',42,'御定全唐詩/json/298.json','["遠將歸，勝未別離時。在家相見熟，新歸歡不足。", "去願車輪遲，回思馬蹄速。但令在舍相對貧，"]'),
('yuding-60','尋橦歌','王建','唐','御定全唐诗','yuding','','[]','人間百戲皆可學，尋橦不比諸餘樂。重梳短髻下金鈿，',96,'御定全唐詩/json/298.json','["人間百戲皆可學，尋橦不比諸餘樂。重梳短髻下金鈿，", "習多倚附欹竿滑，上下蹁躚皆著襪。翻身垂頸欲落地，", "纖腰女兒不動容，戴行直舞一曲終。回頭但覺人眼見，", "小垂一手當舞盤，斜慘雙蛾看落日。斯須改變曲解新，"]'),
('yuding-61','銅雀台','王建','唐','御定全唐诗','yuding','','[]','嬌愛更何日，高臺空數層。含啼映雙袖，不忍看西陵。',64,'御定全唐詩/json/298.json','["嬌愛更何日，高臺空數層。含啼映雙袖，不忍看西陵。", "漳水東流無複來，百花輦路為蒼苔。青樓月夜長寂寞，", "宮中歌舞已浮雲，空指行人往來處。"]'),
('yuding-62','雞鳴曲','王建','唐','御定全唐诗','yuding','','[]','雞初鳴，明星照東屋；雞再鳴，紅霞生海腹。',68,'御定全唐詩/json/298.json','["雞初鳴，明星照東屋；雞再鳴，紅霞生海腹。", "百官待漏雙闕前，聖人亦掛山龍服。寶釵命婦燈下起，", "金吾衛裏直郎妻，到明不睡聽晨雞。天頭日月相送迎，"]'),
('yuding-63','送衣曲','王建','唐','御定全唐诗','yuding','','[]','去秋送衣渡黃河，今秋送衣上隴阪。婦人不知道徑處，',48,'御定全唐詩/json/298.json','["去秋送衣渡黃河，今秋送衣上隴阪。婦人不知道徑處，", "舊來十月初點衣，與郎著向營中集。絮時厚厚綿纂纂，"]'),
('yuding-64','斜路行','王建','唐','御定全唐诗','yuding','','[]','世間娶容非娶婦，中庭牡丹勝松樹。九衢大道人不行，',64,'御定全唐詩/json/298.json','["世間娶容非娶婦，中庭牡丹勝松樹。九衢大道人不行，", "南樓彈弦北戶舞，行人到此多回徨。頭白如絲面如繭，", "誰將古曲換斜音，回取行人斜路心。"]'),
('yuding-65','織錦曲','王建','唐','御定全唐诗','yuding','','[]','大女身為織錦戶，名在縣家供進簿。長頭起樣呈作官，',88,'御定全唐詩/json/298.json','["大女身為織錦戶，名在縣家供進簿。長頭起樣呈作官，", "紅縷葳蕤紫茸軟，蝶飛參差花宛轉。一梭聲盡重一梭，", "合衣臥時參沒後，停燈起在雞鳴前。一匹千金亦不賣，", "莫言山積無盡日，百尺高樓一曲歌。"]'),
('yuding-66','擣衣曲','王建','唐','御定全唐诗','yuding','','[]','月明中庭擣衣石，掩帷下堂來搗帛。婦姑相對神力生，',64,'御定全唐詩/json/298.json','["月明中庭擣衣石，掩帷下堂來搗帛。婦姑相對神力生，", "秋天丁丁複凍凍，玉釵低昂衣帶動。夜深月落冷如刀，", "重燒熨斗帖兩頭，與郎裁作迎寒裘。"]'),
('yuding-67','秋夜曲二首','王建','唐','御定全唐诗','yuding','','[]','天清漏長霜泊泊，蘭綠收榮桂膏涸。高樓雲鬟弄嬋娟，',80,'御定全唐詩/json/298.json','["天清漏長霜泊泊，蘭綠收榮桂膏涸。高樓雲鬟弄嬋娟，", "香囊火死香氣少，向帷合眼何時曉。城烏作營啼野月，", "秋燈向壁掩洞房，良人此夜直明光。", "天河悠悠漏水長，南樓北斗兩相當。"]'),
('yuding-68','題台州隱靜寺','王建','唐','御定全唐诗','yuding','','[]','隱靜靈仙寺天鑿，杯度飛來建岩壑。五峰直上插銀河，',40,'御定全唐詩/json/298.json','["隱靜靈仙寺天鑿，杯度飛來建岩壑。五峰直上插銀河，", "不知勢壓天幾重，鐘聲常聞月中落。"]'),
('yuding-0','送人游塞','王建','唐','御定全唐诗','yuding','','[]','初晴天墮絲，晚色上春枝。城下路分處，邊頭人去時。',48,'御定全唐詩/json/299.json','["初晴天墮絲，晚色上春枝。城下路分處，邊頭人去時。", "停車數行日，勸酒問回期。亦是茫茫客，還從此別離。"]'),
('yuding-1','塞上逢故人','王建','唐','御定全唐诗','yuding','','[]','百戰一身在，相逢白髮生。何時得鄉信，每日算歸程。',48,'御定全唐詩/json/299.json','["百戰一身在，相逢白髮生。何時得鄉信，每日算歸程。", "走馬登寒壟，驅羊入廢城。羌笳三兩曲，人醉海西營。"]'),
('yuding-2','南中','王建','唐','御定全唐诗','yuding','','[]','天南多鳥聲，州縣半無城。野市依蠻姓，山村逐水名。',48,'御定全唐詩/json/299.json','["天南多鳥聲，州縣半無城。野市依蠻姓，山村逐水名。", "瘴煙沙上起，陰火雨中生。獨有求珠客，年年入海行。"]'),
('yuding-3','汴路水驛','王建','唐','御定全唐诗','yuding','','[]','晚泊水邊驛，柳塘初起風。蛙鳴蒲葉下，魚入稻花中。',48,'御定全唐詩/json/299.json','["晚泊水邊驛，柳塘初起風。蛙鳴蒲葉下，魚入稻花中。", "去舍已雲遠，問程猶向東。近來多怨別，不與少年同。"]'),
('yuding-4','淮南使回留別竇侍禦','王建','唐','御定全唐诗','yuding','','[]','戀戀春恨結，綿綿淮草深。病身愁至夜，遠道畏逢陰。',48,'御定全唐詩/json/299.json','["戀戀春恨結，綿綿淮草深。病身愁至夜，遠道畏逢陰。", "忽逐酒杯會，暫同風景心。從今一分散，還是曉枝禽。"]'),
('yuding-5','汴路即事','王建','唐','御定全唐诗','yuding','','[]','千里河煙直，青槐夾岸長。天涯同此路，人語各殊方。',48,'御定全唐詩/json/299.json','["千里河煙直，青槐夾岸長。天涯同此路，人語各殊方。", "草市迎江貨，津橋稅海商。回看故宮柳，憔悴不成行。"]'),
('yuding-6','山居','王建','唐','御定全唐诗','yuding','','[]','屋在瀑泉西，茅簷下有溪。閉門留野鹿，分食養山雞。',48,'御定全唐詩/json/299.json','["屋在瀑泉西，茅簷下有溪。閉門留野鹿，分食養山雞。", "桂熟長收子，蘭生不作畦。初開洞中路，深處轉松梯。"]'),
('yuding-7','醉後憶山中故人','王建','唐','御定全唐诗','yuding','','[]','花開草複秋，雲水自悠悠。因醉暫無事，在山難免愁。',48,'御定全唐詩/json/299.json','["花開草複秋，雲水自悠悠。因醉暫無事，在山難免愁。", "遇晴須看月，鬥健且登樓。暗想山中伴，如今盡白頭。"]'),
('yuding-8','送流人','王建','唐','御定全唐诗','yuding','','[]','見說長沙去，無親亦共愁。陰雲鬼門夜，寒雨瘴江秋。',48,'御定全唐詩/json/299.json','["見說長沙去，無親亦共愁。陰雲鬼門夜，寒雨瘴江秋。", "水國山魈引，蠻鄉洞主留。漸看歸處遠，垂白住炎州。"]'),
('yuding-9','貧居','王建','唐','御定全唐诗','yuding','','[]','眼底貧家計，多時總莫嫌。蠹生騰藥紙，字暗換書簽。',48,'御定全唐詩/json/299.json','["眼底貧家計，多時總莫嫌。蠹生騰藥紙，字暗換書簽。", "避雨拾黃葉，遮風下黑簾。近來身不健，時就六壬占。"]'),
('yuding-10','過趙居士擬置草堂處所','王建','唐','御定全唐诗','yuding','','[]','休師竹林北，空可兩三間。雖愛獨居好，終來相伴閑。',48,'御定全唐詩/json/299.json','["休師竹林北，空可兩三間。雖愛獨居好，終來相伴閑。", "猶嫌近前樹，為礙看南山。的有深耕處，春初須早還。"]'),
('yuding-11','新開望山處','王建','唐','御定全唐诗','yuding','','[]','新開望山處，今朝減病眠。應移千里道，猶自數峰偏。',48,'御定全唐詩/json/299.json','["新開望山處，今朝減病眠。應移千里道，猶自數峰偏。", "故欲遮春巷，還來繞暮天。老夫行步弱，免到寺門前。"]'),
('yuding-12','題東華觀','王建','唐','御定全唐诗','yuding','','[]','路盡煙水外，院門題上清。鶴雛靈解語，瓊葉軟無聲。',48,'御定全唐詩/json/299.json','["路盡煙水外，院門題上清。鶴雛靈解語，瓊葉軟無聲。", "白髮道心熟，黃衣仙骨輕。寂寥虛境裏，何處覓長生。"]'),
('yuding-13','飯僧','王建','唐','御定全唐诗','yuding','','[]','別屋炊香飯，熏辛不入家。溫泉調葛面，淨手摘藤花。',48,'御定全唐詩/json/299.json','["別屋炊香飯，熏辛不入家。溫泉調葛面，淨手摘藤花。", "蒲鮓除青葉，芹齏帶紫芽。願師常伴食，消氣有薑茶。"]'),
('yuding-14','照鏡','王建','唐','御定全唐诗','yuding','','[]','忽自見憔悴，壯年人亦疑。發緣多病落，力為不行衰。',48,'御定全唐詩/json/299.json','["忽自見憔悴，壯年人亦疑。發緣多病落，力為不行衰。", "暖手揉雙目，看圖引四肢。老來真愛道，所恨覺還遲。"]'),
('yuding-15','歸昭應留別城中','王建','唐','御定全唐诗','yuding','','[]','喜得近京城，官卑意亦榮。並床歡未定，離室思還生。',48,'御定全唐詩/json/299.json','["喜得近京城，官卑意亦榮。並床歡未定，離室思還生。", "計拙偷閒住，經過買日行。如無自來分，一驛是遙程。"]'),
('yuding-16','答寄芙蓉冠子','王建','唐','御定全唐诗','yuding','','[]','一學芙蓉葉，初開映水幽。雖經小兒手，不稱老夫頭。',48,'御定全唐詩/json/299.json','["一學芙蓉葉，初開映水幽。雖經小兒手，不稱老夫頭。", "枕上眠常戴，風前醉恐柔。明年有閨閣，此樣必難求。"]'),
('yuding-17','長安春遊','王建','唐','御定全唐诗','yuding','','[]','騎馬傍閑坊，新衣著雨香。桃花紅粉醉，柳樹白雲狂。',48,'御定全唐詩/json/299.json','["騎馬傍閑坊，新衣著雨香。桃花紅粉醉，柳樹白雲狂。", "不覺愁春去，何曾得日長。牡丹相次發，城裏又須忙。"]'),
('yuding-18','冬夜感懷','王建','唐','御定全唐诗','yuding','','[]','晚年恩愛少，耳目靜於僧。竟夜不聞語，空房唯有燈。',48,'御定全唐詩/json/299.json','["晚年恩愛少，耳目靜於僧。竟夜不聞語，空房唯有燈。", "氣噓寒被濕，霜入破窗凝。斷得人間事，長如此亦能。"]'),
('yuding-19','初到昭應呈同僚','王建','唐','御定全唐诗','yuding','','[]','白髮初為吏，有慚年少郎。自知身上拙，不稱世間忙。',48,'御定全唐詩/json/299.json','["白髮初為吏，有慚年少郎。自知身上拙，不稱世間忙。", "秋雨懸牆綠，暮山宮樹黃。同官若容許，長借老僧房。"]'),
('yuding-20','縣丞廳即事','王建','唐','御定全唐诗','yuding','','[]','宮殿半山上，人家高下居。古廳眠受魘，老吏語多虛。',48,'御定全唐詩/json/299.json','["宮殿半山上，人家高下居。古廳眠受魘，老吏語多虛。", "雨水洗荒竹，溪沙填廢渠。聖朝收外府，皆自九天除。"]'),
('yuding-21','閒居即事','王建','唐','御定全唐诗','yuding','','[]','老病貪光景，尋常不下簾。妻愁耽酒僻，人怪考詩嚴。',48,'御定全唐詩/json/299.json','["老病貪光景，尋常不下簾。妻愁耽酒僻，人怪考詩嚴。", "小婢偷紅紙，嬌兒弄白髯。有時看舊卷，未免意中嫌。"]'),
('yuding-22','林居','王建','唐','御定全唐诗','yuding','','[]','荒林四面通，門在野田中。頑僕長如客，貧居未勝蓬。',48,'御定全唐詩/json/299.json','["荒林四面通，門在野田中。頑僕長如客，貧居未勝蓬。", "舊綿衣不暖，新草屋多風。唯去山南近，閑親販藥翁。"]'),
('yuding-23','原上新居十三首','王建','唐','御定全唐诗','yuding','','[]','新占原頭地，本無山可歸。荒藤生葉晚，老杏著花稀。',576,'御定全唐詩/json/299.json','["新占原頭地，本無山可歸。荒藤生葉晚，老杏著花稀。", "廚舍近泥灶，家人初飽薇。弟兄今四散，何日更相依。", "一家榆柳新，四面遠無鄰。人少愁聞病，莊孤幸得貧。", "耕牛長願飽，樵僕每憐勤。終日憂衣食，何由脫此身。", "長安無舊識，百里是天涯。寂寞思逢客，荒涼喜見花。", "訪僧求賤藥，將馬中豪家。乍得新蔬菜，朝盤忽覺奢。", "雞鳴村舍遙，花發亦蕭條。野竹初生筍，溪田未得苗。", "家貧僮僕瘦，春冷菜蔬焦。甘分長如此，無名在聖朝。", "春來梨棗盡，啼哭小兒饑。鄰富雞常去，莊貧客漸稀。", "借牛耕地晚，賣樹納錢遲。牆下當官路，依山補竹籬。", "自掃一間房，唯鋪獨臥床。野羹溪菜滑，山紙水苔香。", "陳藥初和白，新經未入黃。近來心力少，休讀養生方。", "擬作讀經人，空房置淨巾。鎖茶藤篋密，曝藥竹床新。", "老病應隨業，因緣不離身。焚香向居士，無計出諸塵。", "移家近住村，貧苦自安存。細問梨果植，遠求花藥根。", "倩人開廢井，趁犢入新園。長愛當山立，黃昏不閉門。", "和暖繞林行，新貧足喜聲。掃渠憂竹旱，澆地引蘭生。", "山客憑栽樹，家僮使入城。門前粉壁上，書著縣官名。", "住處鐘鼓外，免爭當路橋。身閒時卻困，兒病可來嬌。", "雞睡日陽暖，蜂狂花豔燒。長安足門戶，疊疊看登朝。", "近來年紀到，世事總無心。古碣憑人拓，閑詩任客吟。", "送經還野苑，移石入幽林。谷口春風惡，梨花蓋地深。", "懶更學諸餘，林中掃地居。膩衣穿不洗，白髮短慵梳。", "苦相常多淚，勞生自悟虛。閑行人事絕，親故亦無書。"]'),
('yuding-24','送李評事使蜀','王建','唐','御定全唐诗','yuding','','[]','勸酒不依巡，明朝萬里人。轉江雲棧細，近驛板橋新。',48,'御定全唐詩/json/299.json','["勸酒不依巡，明朝萬里人。轉江雲棧細，近驛板橋新。", "石冷啼猿影，松昏戲鹿塵。少年為客好，況是益州春。"]'),
('yuding-25','新修道居','王建','唐','御定全唐诗','yuding','','[]','世間無所入，學道處新成。兩面有山色，六時聞磬聲。',48,'御定全唐詩/json/299.json','["世間無所入，學道處新成。兩面有山色，六時聞磬聲。", "閑加經遍數，老愛字分明。若得離煩惱，焚香過一生。"]'),
('yuding-26','贈洪誓師','王建','唐','御定全唐诗','yuding','','[]','老僧真古畫，閑坐語中聽。識病方書聖，諳山草木靈。',48,'御定全唐詩/json/299.json','["老僧真古畫，閑坐語中聽。識病方書聖，諳山草木靈。", "人來多施藥，願滿不持經。相伴尋溪竹，秋苔襪履青。"]'),
('yuding-27','題法雲禪院僧','王建','唐','御定全唐诗','yuding','','[]','不剃頭多日，禪來白髮長。合村迎住寺，同學乞修房。',48,'御定全唐詩/json/299.json','["不剃頭多日，禪來白髮長。合村迎住寺，同學乞修房。", "覺少持經力，憂無養病糧。上山猶得在，自解衲衣裳。"]'),
('yuding-28','贈溪翁','王建','唐','御定全唐诗','yuding','','[]','溪田借四鄰，不省解憂身。看日和仙藥，書符救病人。',48,'御定全唐詩/json/299.json','["溪田借四鄰，不省解憂身。看日和仙藥，書符救病人。", "伴僧齋過夏，中酒臥經旬。應得丹砂力，春來黑髮新。"]'),
('yuding-29','謝李續主簿','王建','唐','御定全唐诗','yuding','','[]','館舍幸相近，因風及病身。一官雖隔水，四韻是同人。',48,'御定全唐詩/json/299.json','["館舍幸相近，因風及病身。一官雖隔水，四韻是同人。", "衰臥朦朧曉，貧居冷落春。少年無不好，莫恨滿頭塵。"]'),
('yuding-30','寒食','王建','唐','御定全唐诗','yuding','','[]','田舍清明日，家家出火遲。白衫眠古巷，紅索搭高枝。',48,'御定全唐詩/json/299.json','["田舍清明日，家家出火遲。白衫眠古巷，紅索搭高枝。", "紗帶生難結，銅釵重欲垂。斬新衣踏盡，還似去年時。"]'),
('yuding-31','貽小尼師','王建','唐','御定全唐诗','yuding','','[]','新剃青頭髮，生來未掃眉。身輕禮拜穩，心慢記經遲。',48,'御定全唐詩/json/299.json','["新剃青頭髮，生來未掃眉。身輕禮拜穩，心慢記經遲。", "喚起猶侵曉，催齋已過時。春晴階下立，私地弄花枝。"]'),
('yuding-32','惜歡','王建','唐','御定全唐诗','yuding','','[]','當歡須且歡，過後買應難。歲去停燈守，花開把火看。',48,'御定全唐詩/json/299.json','["當歡須且歡，過後買應難。歲去停燈守，花開把火看。", "狂來欺酒淺，愁盡覺天寬。次第頭皆白，齊年人已殘。"]'),
('yuding-33','山中惜花','王建','唐','御定全唐诗','yuding','','[]','忽看花漸稀，罪過酒醒時。尋覓風來處，驚張夜落時。',48,'御定全唐詩/json/299.json','["忽看花漸稀，罪過酒醒時。尋覓風來處，驚張夜落時。", "遊絲纏故蕊，宿夜守空枝。開取當軒地，年年樹底期。"]'),
('yuding-34','和武門下傷韋令孔雀','王建','唐','御定全唐诗','yuding','','[]','孤號秋閣陰，韋令在時禽。覓伴海山黑，思鄉橘柚深。',48,'御定全唐詩/json/299.json','["孤號秋閣陰，韋令在時禽。覓伴海山黑，思鄉橘柚深。", "舉頭聞舊曲，顧尾惜殘金。憔悴不飛去，重君池上心。"]'),
('yuding-35','題所賃宅牡丹花','王建','唐','御定全唐诗','yuding','','[]','賃宅得花饒，初開恐是妖。粉光深紫膩，肉色退紅嬌。',48,'御定全唐詩/json/299.json','["賃宅得花饒，初開恐是妖。粉光深紫膩，肉色退紅嬌。", "且願風留著，惟愁日炙燋。可憐零落蕊，收取作香燒。"]'),
('yuding-36','隱者居','王建','唐','御定全唐诗','yuding','','[]','山人住處高，看日上蟠桃。雪縷青山脈，雲生白鶴毛。',48,'御定全唐詩/json/299.json','["山人住處高，看日上蟠桃。雪縷青山脈，雲生白鶴毛。", "朱書護身咒，水噀斷邪刀。何物中長食，胡麻慢火熬。"]'),
('yuding-37','昭應官舍','王建','唐','御定全唐诗','yuding','','[]','繞廳春草合，知道縣家閑。行見雨遮院，臥看人上山。',48,'御定全唐詩/json/299.json','["繞廳春草合，知道縣家閑。行見雨遮院，臥看人上山。", "避風新浴後，請假未醒間。朝客輕卑吏，從他不往還。"]'),
('yuding-38','送嚴大夫赴桂州','王建','唐','御定全唐诗','yuding','','[]','嶺頭分界候，一半屬湘潭。水驛門旗出，山戀洞主參。',48,'御定全唐詩/json/299.json','["嶺頭分界候，一半屬湘潭。水驛門旗出，山戀洞主參。", "辟邪犀角重，解酒荔枝甘。莫歎京華遠，安南更有南。"]'),
('yuding-39','望行人','王建','唐','御定全唐诗','yuding','','[]','自從江樹秋，日日望江樓。夢見離珠浦，書來在桂州。',48,'御定全唐詩/json/299.json','["自從江樹秋，日日望江樓。夢見離珠浦，書來在桂州。", "不同魚比目，終恨水分流。久不開明鏡，多應是白頭。"]'),
('yuding-40','塞上','王建','唐','御定全唐诗','yuding','','[]','漫漫複淒淒，黃沙暮漸迷。人當故鄉立，馬過舊營嘶。',48,'御定全唐詩/json/299.json','["漫漫複淒淒，黃沙暮漸迷。人當故鄉立，馬過舊營嘶。", "斷雁逢冰磧，回軍占雪溪。夜來山下哭，應是送降奚。"]'),
('yuding-41','杜中丞書院新移小竹','王建','唐','御定全唐诗','yuding','','[]','此地本無竹，遠從山寺移。經年求養法，隔日記澆時。',72,'御定全唐詩/json/299.json','["此地本無竹，遠從山寺移。經年求養法，隔日記澆時。", "嫩綠卷新葉，殘黃收故枝。色經寒不動，聲與靜相宜。", "愛護出常數，稀稠看自知。貧來緣未有，客散獨行遲。"]'),
('yuding-42','同於汝錫賞白牡丹','王建','唐','御定全唐诗','yuding','','[]','曉日花初吐，春寒白未凝。月光裁不得，蘇合點難勝。',96,'御定全唐詩/json/299.json','["曉日花初吐，春寒白未凝。月光裁不得，蘇合點難勝。", "柔膩于雲葉，新鮮掩鶴膺。統心黃倒暈，側莖紫重棱。", "乍斂看如睡，初開問欲應。並香幽蕙死，比豔美人憎。", "價數千金貴，形相兩眼疼。自知顏色好，愁被彩光淩。"]'),
('yuding-43','送吳郎中赴忠州','王建','唐','御定全唐诗','yuding','','[]','西台複南省，清白上天知。家每因窮散，官多為直移。',72,'御定全唐詩/json/299.json','["西台複南省，清白上天知。家每因窮散，官多為直移。", "遙邊過驛近，買藥出城遲。朝野憑人別，親情伴酒悲。", "故園愁去後，白髮想回時。何處忠州界，山頭卓望旗。"]'),
('yuding-44','照鏡','王建','唐','御定全唐诗','yuding','','[]','終日自纏繞，此身無適緣。萬愁生旅夜，百病湊衰年。',72,'御定全唐詩/json/299.json','["終日自纏繞，此身無適緣。萬愁生旅夜，百病湊衰年。", "少睡憎明屋，慵行待暖天。癢頭梳有虱，風耳炙聞蟬。", "搖白方多錯，回金法不全。家貧何所戀，時在老僧邊。"]'),
('yuding-45','秋日送杜虔州','王建','唐','御定全唐诗','yuding','','[]','憶得宿新宅，別來餘蕙香。初聞守郡遠，一日臥空床。',72,'御定全唐詩/json/299.json','["憶得宿新宅，別來餘蕙香。初聞守郡遠，一日臥空床。", "野驛煙火濕，路人消息狂。山樓添鼓角，村柵立旗槍。", "晚渚露荷敗，早衙風桂涼。謝家章句出，江月少輝光。"]'),
('yuding-46','送鄭權尚書南海','王建','唐','御定全唐诗','yuding','','[]','七郡雙旌貴，人皆不憶回。戍頭龍腦鋪，關口象牙堆。',72,'御定全唐詩/json/299.json','["七郡雙旌貴，人皆不憶回。戍頭龍腦鋪，關口象牙堆。", "敕設熏爐出，蠻辭咒節開。市喧山賊破，金賤海船來。", "白氎家家織，紅蕉處處栽。已將身報國，莫起望鄉台。"]'),
('yuding-47','題別遺愛草堂兼呈李十使君','王建','唐','御定全唐诗','yuding','','[]','曾住爐峰下，書堂對藥台。斬新蘿徑合，依舊竹窗開。',72,'御定全唐詩/json/299.json','["曾住爐峰下，書堂對藥台。斬新蘿徑合，依舊竹窗開。", "砌水親看決，池荷手自栽。五年方暫至，一宿又須回。", "縱未長歸得，猶勝不到來。君家白鹿洞，聞道亦生苔。"]'),
('yuding-48','賞牡丹','王建','唐','御定全唐诗','yuding','','[]','此花名價別，開豔益皇都。香遍苓菱死，紅燒躑躅枯。',96,'御定全唐詩/json/299.json','["此花名價別，開豔益皇都。香遍苓菱死，紅燒躑躅枯。", "軟光籠細脈，妖色暖鮮膚。滿蕊攢黃粉，含棱縷絳蘇。", "好和熏禦服，堪畫入宮圖。晚態愁新婦，殘妝望病夫。", "教人知個數，留客賞斯須。一夜輕風起，千金買亦無。"]'),
('yuding-0','贈王樞密','王建','唐','御定全唐诗','yuding','','[]','三朝行坐鎮相隨，今上春宮見小時。脫下禦衣先賜著，',40,'御定全唐詩/json/300.json','["三朝行坐鎮相隨，今上春宮見小時。脫下禦衣先賜著，", "自是姓同親向說，九重爭得外人知。"]'),
('yuding-1','早秋過龍武李將軍書齋','王建','唐','御定全唐诗','yuding','','[]','高樹蟬聲秋巷裏，朱門冷靜似閒居。重裝墨畫數莖竹，',40,'御定全唐詩/json/300.json','["高樹蟬聲秋巷裏，朱門冷靜似閒居。重裝墨畫數莖竹，", "就中愛讀英雄傳，欲立功勳恐不如。"]'),
('yuding-2','江陵即事','王建','唐','御定全唐诗','yuding','','[]','瘴雲梅雨不成泥，十裏津樓壓大堤。蜀女下沙迎水客，',40,'御定全唐詩/json/300.json','["瘴雲梅雨不成泥，十裏津樓壓大堤。蜀女下沙迎水客，", "夜半獨眠愁在遠，北看歸路隔蠻溪。"]'),
('yuding-3','題花子贈渭州陳判官','王建','唐','御定全唐诗','yuding','','[]','膩如雲母輕如粉，豔勝香黃薄勝蟬。點綠斜蒿新葉嫩，',40,'御定全唐詩/json/300.json','["膩如雲母輕如粉，豔勝香黃薄勝蟬。點綠斜蒿新葉嫩，", "況複蕭郎有情思，可憐春日鏡臺前。"]'),
('yuding-4','送從侄擬赴江陵少尹','王建','唐','御定全唐诗','yuding','','[]','江陵少尹好閑官，親故皆來勸自寬。無事日長貧不易，',40,'御定全唐詩/json/300.json','["江陵少尹好閑官，親故皆來勸自寬。無事日長貧不易，", "應向章華台下醉，莫沖雲雨夜深寒。"]'),
('yuding-5','華清宮感舊','王建','唐','御定全唐诗','yuding','','[]','塵到朝元邊使急，千官夜發六龍回。輦前月照羅衫淚，',40,'御定全唐詩/json/300.json','["塵到朝元邊使急，千官夜發六龍回。輦前月照羅衫淚，", "有時雲外聞天樂，知是先皇沐浴來。"]'),
('yuding-6','九仙公主舊莊','王建','唐','御定全唐诗','yuding','','[]','仙居五裏外門西，石路親回禦馬蹄。天使來栽宮裏樹，',40,'御定全唐詩/json/300.json','["仙居五裏外門西，石路親回禦馬蹄。天使來栽宮裏樹，", "樓上鳳凰飛去後，白雲紅葉屬山雞。"]'),
('yuding-7','郭家溪亭','王建','唐','御定全唐诗','yuding','','[]','高亭望見長安樹，春草岡西舊院斜。光動綠煙遮岸竹，',40,'御定全唐詩/json/300.json','["高亭望見長安樹，春草岡西舊院斜。光動綠煙遮岸竹，", "妝閣書樓傾側盡，雲山新賣與官家。"]'),
('yuding-8','題金家竹溪','王建','唐','御定全唐诗','yuding','','[]','少年因病離天仗，乞得歸家自養身。買斷竹溪無別主，',40,'御定全唐詩/json/300.json','["少年因病離天仗，乞得歸家自養身。買斷竹溪無別主，", "鄉使到來常款語，還聞世上有功臣。"]'),
('yuding-9','題應聖觀','王建','唐','御定全唐诗','yuding','','[]','精思堂上畫三身，回作仙宮度美人。賜額禦書金字貴，',40,'御定全唐詩/json/300.json','["精思堂上畫三身，回作仙宮度美人。賜額禦書金字貴，", "頭白女冠猶說得，薔薇不似已前春。"]'),
('yuding-10','同于汝錫遊降聖觀','王建','唐','御定全唐诗','yuding','','[]','秦時桃樹滿山坡，騎鹿先生降大羅。路盡溪頭逢地少，',40,'御定全唐詩/json/300.json','["秦時桃樹滿山坡，騎鹿先生降大羅。路盡溪頭逢地少，", "聞說開元齋醮日，曉移行漏帝親過。"]'),
('yuding-11','逍遙翁溪亭','王建','唐','御定全唐诗','yuding','','[]','逍遙翁在此裴回，帝改溪名起石台。車馬到春常借問，',40,'御定全唐詩/json/300.json','["逍遙翁在此裴回，帝改溪名起石台。車馬到春常借問，", "無主青山何所直，賣供官稅不如灰。"]'),
('yuding-12','尋李山人不遇','王建','唐','御定全唐诗','yuding','','[]','山客長須少在時，溪中放鶴洞中棋。生金有氣尋還遠，',40,'御定全唐詩/json/300.json','["山客長須少在時，溪中放鶴洞中棋。生金有氣尋還遠，", "從頭石上留名去，獨向南峰問老師。"]'),
('yuding-13','題石甕寺','王建','唐','御定全唐诗','yuding','','[]','青崖白石夾城東，泉脈鐘聲內裏通。地壓龍蛇山色別，',40,'御定全唐詩/json/300.json','["青崖白石夾城東，泉脈鐘聲內裏通。地壓龍蛇山色別，", "天子親題詩總在，畫扉長鎖碧龕中。"]'),
('yuding-14','早登西禪寺閣','王建','唐','御定全唐诗','yuding','','[]','上方台殿第三層，朝壁紅窗日氣凝。煙霧開時分遠寺，',40,'御定全唐詩/json/300.json','["上方台殿第三層，朝壁紅窗日氣凝。煙霧開時分遠寺，", "莫說城南月燈閣，自諸樓看總難勝。"]'),
('yuding-15','題江寺兼求藥子','王建','唐','御定全唐诗','yuding','','[]','隋朝舊寺楚江頭，深謝師僧引客遊。空賞野花無過夜，',40,'御定全唐詩/json/300.json','["隋朝舊寺楚江頭，深謝師僧引客遊。空賞野花無過夜，", "願乞野人三兩粒，歸家將助小庭幽。"]'),
('yuding-16','題詵法師院','王建','唐','御定全唐诗','yuding','','[]','三年說戒龍宮裏，巡禮還來向水行。多愛貧窮人遠請，',40,'御定全唐詩/json/300.json','["三年說戒龍宮裏，巡禮還來向水行。多愛貧窮人遠請，", "僧院不求諸處好，轉經唯有一窗明。"]'),
('yuding-17','酬於汝錫曉雪見寄','王建','唐','御定全唐诗','yuding','','[]','欲明天色白漫漫，打葉穿簾雪未幹。薄落階前人踏盡，',40,'御定全唐詩/json/300.json','["欲明天色白漫漫，打葉穿簾雪未幹。薄落階前人踏盡，", "勞動更裁新樣綺，紅燈一夜剪刀寒。"]'),
('yuding-18','從軍後寄山中友人','王建','唐','御定全唐诗','yuding','','[]','愛仙無藥住溪貧，脫卻山衣事漢臣。夜半聽雞梳白髮，',40,'御定全唐詩/json/300.json','["愛仙無藥住溪貧，脫卻山衣事漢臣。夜半聽雞梳白髮，", "勞動先生遠相示，別來弓箭不離身。"]'),
('yuding-19','寄汴州令狐相公','王建','唐','御定全唐诗','yuding','','[]','三軍江口擁雙旌，虎帳長開自教兵。機鎖惡徒狂寇盡，',40,'御定全唐詩/json/300.json','["三軍江口擁雙旌，虎帳長開自教兵。機鎖惡徒狂寇盡，", "秋日梁王池閣好，新歌散入管弦聲。"]'),
('yuding-20','別李贊侍禦','王建','唐','御定全唐诗','yuding','','[]','同受艱難驃騎營，半年中聽揭槍聲。草頭送酒驅村樂，',40,'御定全唐詩/json/300.json','["同受艱難驃騎營，半年中聽揭槍聲。草頭送酒驅村樂，", "薦書自入無消息，賣盡寒衣卻出城。"]'),
('yuding-21','和蔣學士新授章服','王建','唐','御定全唐诗','yuding','','[]','五色箱中絳服春，笏花成就白魚新。看宣賜處驚回眼，',40,'御定全唐詩/json/300.json','["五色箱中絳服春，笏花成就白魚新。看宣賜處驚回眼，", "翰林同賀文章出，驚動茫茫下界人。"]'),
('yuding-22','歲晚自感','王建','唐','御定全唐诗','yuding','','[]','人皆欲得長年少，無那排門白髮催。一向破除愁不盡，',40,'御定全唐詩/json/300.json','["人皆欲得長年少，無那排門白髮催。一向破除愁不盡，", "瀝酒願從今日後，更逢二十度花開。"]'),
('yuding-23','昭應官舍','王建','唐','御定全唐诗','yuding','','[]','癡頑終日羨人閑，卻喜因官得近山。斜對寺樓分寂寂，',40,'御定全唐詩/json/300.json','["癡頑終日羨人閑，卻喜因官得近山。斜對寺樓分寂寂，", "文案把來看未會，雖書一字甚慚顏。"]'),
('yuding-24','寄舊山僧','王建','唐','御定全唐诗','yuding','','[]','因依老宿發心初，半學修心半讀書。雪後每常同席臥，',40,'御定全唐詩/json/300.json','["因依老宿發心初，半學修心半讀書。雪後每常同席臥，", "一向風塵取煩惱，不知衰病日難除。"]'),
('yuding-25','武陵春日','王建','唐','御定全唐诗','yuding','','[]','尋春何事卻悲涼，春到他鄉憶故鄉。秦女洞桃欹澗碧，',40,'御定全唐詩/json/300.json','["尋春何事卻悲涼，春到他鄉憶故鄉。秦女洞桃欹澗碧，", "不似冥心叩塵寂，玉編金軸有仙方。"]'),
('yuding-26','寄分司張郎中','王建','唐','御定全唐诗','yuding','','[]','一別京華年歲久，卷中多見嶺南詩。聲名已壓眾人上，',40,'御定全唐詩/json/300.json','["一別京華年歲久，卷中多見嶺南詩。聲名已壓眾人上，", "青天白日當頭上，會有求閑不得時。"]'),
('yuding-27','上武元衡相公','王建','唐','御定全唐诗','yuding','','[]','旌旗坐鎮蜀江雄，帝命重開舊合崇。褒貶唐書天曆上，',40,'御定全唐詩/json/300.json','["旌旗坐鎮蜀江雄，帝命重開舊合崇。褒貶唐書天曆上，", "長得蕭何為國相，自西流水盡朝宗。"]'),
('yuding-28','上張弘靖相公','王建','唐','御定全唐诗','yuding','','[]','傳封三世盡河東，家占中條第一峰。旱歲天教作霖雨，',40,'御定全唐詩/json/300.json','["傳封三世盡河東，家占中條第一峰。旱歲天教作霖雨，", "卑散自知霄漢隔，若為門下賜從容。"]'),
('yuding-29','上裴度舍人','王建','唐','御定全唐诗','yuding','','[]','小松雙對鳳池開，履跡衣香逼上臺。天意皆從彩毫出，',40,'御定全唐詩/json/300.json','["小松雙對鳳池開，履跡衣香逼上臺。天意皆從彩毫出，", "仙侶何因記名姓，縣丞頭白走塵埃。"]'),
('yuding-30','上杜元穎相公','王建','唐','御定全唐诗','yuding','','[]','學士金鑾殿后居，天中行坐侍龍輿。承恩不許離床謝，',40,'御定全唐詩/json/300.json','["學士金鑾殿后居，天中行坐侍龍輿。承恩不許離床謝，", "閑曹散吏無相識，猶記荊州拜謁初。"]'),
('yuding-31','贈盧汀諫議','王建','唐','御定全唐诗','yuding','','[]','青蛾不得在床前，空室焚香獨自眠。功證詩篇離景象，',40,'御定全唐詩/json/300.json','["青蛾不得在床前，空室焚香獨自眠。功證詩篇離景象，", "近見蘭台諸吏說，禦詩新集未教傳。"]'),
('yuding-32','賀楊巨源博士拜虞部員外','王建','唐','御定全唐诗','yuding','','[]','合歸蘭署已多時，上得金梯亦未遲。兩省郎官開道路，',40,'御定全唐詩/json/300.json','["合歸蘭署已多時，上得金梯亦未遲。兩省郎官開道路，", "殘著幾丸仙藥在，分張還遣病夫知。"]'),
('yuding-33','贈郭將軍','王建','唐','御定全唐诗','yuding','','[]','承恩新拜上將軍，當直巡更近五雲。天下表章經院過，',40,'御定全唐詩/json/300.json','["承恩新拜上將軍，當直巡更近五雲。天下表章經院過，", "向晚臨階看號簿，眼前風景任支分。"]'),
('yuding-34','贈田將軍','王建','唐','御定全唐诗','yuding','','[]','初從學院別先生，便領偏師得戰名。大小獨當三百陣，',40,'御定全唐詩/json/300.json','["初從學院別先生，便領偏師得戰名。大小獨當三百陣，", "自執金吾長上直，蓬萊宮裏夜巡更。"]'),
('yuding-35','贈胡泟將軍','王建','唐','御定全唐诗','yuding','','[]','書生難得是金吾，近日登科記總無。半夜進儺當玉殿，',40,'御定全唐詩/json/300.json','["書生難得是金吾，近日登科記總無。半夜進儺當玉殿，", "恐要蕃中新道路，指揮重畫五城圖。"]'),
('yuding-36','留別田尚書','王建','唐','御定全唐诗','yuding','','[]','擬報平生未殺身，難離門館起居頻。不看匣裏釵頭古，',40,'御定全唐詩/json/300.json','["擬報平生未殺身，難離門館起居頻。不看匣裏釵頭古，", "朝天路在驪山下，專望紅旗拜舊塵。"]'),
('yuding-37','送唐大夫罷節歸山','王建','唐','御定全唐诗','yuding','','[]','年少平戎老學仙，表求骸骨乞生全。不堪腰下懸金印，',40,'御定全唐詩/json/300.json','["年少平戎老學仙，表求骸骨乞生全。不堪腰下懸金印，", "人間雞犬同時去，遙聽笙歌隔水煙。"]'),
('yuding-38','送司空神童','王建','唐','御定全唐诗','yuding','','[]','杏花壇上授書時，不廢中庭趁蝶飛。暗寫五經收部秩，',40,'御定全唐詩/json/300.json','["杏花壇上授書時，不廢中庭趁蝶飛。暗寫五經收部秩，", "獨向鳳城持薦表，萬人叢裏有光輝。"]'),
('yuding-39','送振武張尚書','王建','唐','御定全唐诗','yuding','','[]','回天轉地是將軍，扶助春宮上五雲。撫背恩雖同骨肉，',40,'御定全唐詩/json/300.json','["回天轉地是將軍，扶助春宮上五雲。撫背恩雖同骨肉，", "閑即單于台下獵，威聲直到海西聞。"]'),
('yuding-40','送吳諫議上饒州','王建','唐','御定全唐诗','yuding','','[]','鄱陽太守是真人，琴在床頭籙在身。曾向先皇邊諫事，',40,'御定全唐詩/json/300.json','["鄱陽太守是真人，琴在床頭籙在身。曾向先皇邊諫事，", "淨掃水堂無侍女，下街唯共鶴殷勤。"]'),
('yuding-41','贈閻少保','王建','唐','御定全唐诗','yuding','','[]','髭須雖白體輕健，九十三來卻少年。問事愛知天寶裏，',40,'御定全唐詩/json/300.json','["髭須雖白體輕健，九十三來卻少年。問事愛知天寶裏，", "侍女常時教合藥，亦聞私地學求仙。"]'),
('yuding-42','送魏州李相公','王建','唐','御定全唐诗','yuding','','[]','百代功勳一日成，三年五度換雙旌。閑來不對人論戰，',40,'御定全唐詩/json/300.json','["百代功勳一日成，三年五度換雙旌。閑來不對人論戰，", "當朝面受新恩去，算料妖星不敢生。"]'),
('yuding-43','贈索暹將軍','王建','唐','御定全唐诗','yuding','','[]','渾身著箭瘢猶在，萬槊千刀總過來。輪劍直沖生馬隊，',40,'御定全唐詩/json/300.json','["渾身著箭瘢猶在，萬槊千刀總過來。輪劍直沖生馬隊，", "淚滴先皇階下土，南衙班裏趁朝回。"]'),
('yuding-44','贈王屋道士赴詔','王建','唐','御定全唐诗','yuding','','[]','玉皇符詔下天壇，玳瑁頭簪白角冠。鶴遣院中童子養，',40,'御定全唐詩/json/300.json','["玉皇符詔下天壇，玳瑁頭簪白角冠。鶴遣院中童子養，", "能斷世間腥血味，長生只要一丸丹。"]'),
('yuding-45','贈王處士','王建','唐','御定全唐诗','yuding','','[]','松樹當軒雪滿池，青山掩障碧紗幮。鼠來案上常偷水，',40,'御定全唐詩/json/300.json','["松樹當軒雪滿池，青山掩障碧紗幮。鼠來案上常偷水，", "世間有似君應少，便乞從今作我師。"]'),
('yuding-46','洛中張籍新居','王建','唐','御定全唐诗','yuding','','[]','最是城中閒靜處，更回門向寺前開。雲山且喜重重見，',40,'御定全唐詩/json/300.json','["最是城中閒靜處，更回門向寺前開。雲山且喜重重見，", "自君移到無多日，牆上人名滿綠苔。"]'),
('yuding-47','題裴處士碧虛溪居','王建','唐','御定全唐诗','yuding','','[]','鳥聲真似深山裏，平地人間自不同。春圃紫芹長卓卓，',40,'御定全唐詩/json/300.json','["鳥聲真似深山裏，平地人間自不同。春圃紫芹長卓卓，", "細問來時從近遠，溪名載入縣圖中。"]'),
('yuding-48','送阿史那將軍安西迎舊使靈櫬','王建','唐','御定全唐诗','yuding','','[]','漢家都護邊頭沒，舊將麻衣萬里迎。陰地背行山下火，',40,'御定全唐詩/json/300.json','["漢家都護邊頭沒，舊將麻衣萬里迎。陰地背行山下火，", "卻入杜陵秋巷裏，路人來去讀銘旌。"]'),
('yuding-49','贈崔禮駙馬','王建','唐','御定全唐诗','yuding','','[]','鳳凰樓閣連宮樹，天子崔郎自愛貧。金埒減添栽藥地，',40,'御定全唐詩/json/300.json','["鳳凰樓閣連宮樹，天子崔郎自愛貧。金埒減添栽藥地，", "一月一回陪內宴，馬蹄猶厭踏香塵。"]'),
('yuding-50','贈太清盧道士','王建','唐','御定全唐诗','yuding','','[]','上清道士未升天，南嶽中華作散仙。書賣八分通字學，',40,'御定全唐詩/json/300.json','["上清道士未升天，南嶽中華作散仙。書賣八分通字學，", "想向諸山尋禮遍，卻回還守老君前。"]'),
('yuding-51','送宮人入道','王建','唐','御定全唐诗','yuding','','[]','休梳叢鬢洗紅妝，頭戴芙蓉出未央。弟子抄將歌遍疊，',40,'御定全唐詩/json/300.json','["休梳叢鬢洗紅妝，頭戴芙蓉出未央。弟子抄將歌遍疊，", "發願蓬萊見王母，卻歸人世施仙方。"]'),
('yuding-52','上李吉甫相公','王建','唐','御定全唐诗','yuding','','[]','聖朝齊賀說逢殷，霄漢無雲日月真。金鼎調和天膳美，',40,'御定全唐詩/json/300.json','["聖朝齊賀說逢殷，霄漢無雲日月真。金鼎調和天膳美，", "曾向山東為散吏，當今竇憲是賢臣。"]'),
('yuding-53','上李益庶子','王建','唐','御定全唐诗','yuding','','[]','紫煙樓閣碧紗亭，上界詩仙獨自行。奇險驅回還寂寞，',40,'御定全唐詩/json/300.json','["紫煙樓閣碧紗亭，上界詩仙獨自行。奇險驅回還寂寞，", "昏思願因秋露洗，幸容階下禮先生。"]'),
('yuding-54','題元郎中新宅','王建','唐','御定全唐诗','yuding','','[]','近移松樹初栽藥，經帙書簽一切新。鋪設暖房迎道士，',40,'御定全唐詩/json/300.json','["近移松樹初栽藥，經帙書簽一切新。鋪設暖房迎道士，", "惟有好詩名字出，倍教年少損心神。"]'),
('yuding-55','初授太府丞言懷','王建','唐','御定全唐诗','yuding','','[]','除書亦下屬微班，喚作官曹便不閑。檢案事多關市井，',40,'御定全唐詩/json/300.json','["除書亦下屬微班，喚作官曹便不閑。檢案事多關市井，", "此去仙宮無一裏，遙看松樹眾家攀。"]'),
('yuding-56','贈李愬僕射','王建','唐','御定全唐诗','yuding','','[]','唐州將士死生同，盡逐雙旌舊鎮空。獨破淮西功業大，',40,'御定全唐詩/json/300.json','["唐州將士死生同，盡逐雙旌舊鎮空。獨破淮西功業大，", "次第各分茅土貴，殊勳並在一門中。"]'),
('yuding-57','書贈舊渾二曹長','王建','唐','御定全唐诗','yuding','','[]','二年同在華清下，入縣門中最近鄰。替飲觥籌知戶小，',40,'御定全唐詩/json/300.json','["二年同在華清下，入縣門中最近鄰。替飲觥籌知戶小，", "僮僕使來傳語熟，至今行酒校殷勤。"]'),
('yuding-58','上崔相公','王建','唐','御定全唐诗','yuding','','[]','枯桂衰蘭一遍春，唯將道德定君臣。施行聖澤山川潤，',40,'御定全唐詩/json/300.json','["枯桂衰蘭一遍春，唯將道德定君臣。施行聖澤山川潤，", "應憐老病無知己，自別溪中滿鬢塵。"]'),
('yuding-59','寄楊十二秘書','王建','唐','御定全唐诗','yuding','','[]','初移古寺正南方，靜是浮山遠是莊。人定猶行背街鼓，',40,'御定全唐詩/json/300.json','["初移古寺正南方，靜是浮山遠是莊。人定猶行背街鼓，", "閑出天門醉騎馬，可憐蓬閣秘書郎。"]'),
('yuding-60','謝田贊善見寄','王建','唐','御定全唐诗','yuding','','[]','五侯三任未相稱，頭白如絲作縣丞。錯判符曹群吏笑，',40,'御定全唐詩/json/300.json','["五侯三任未相稱，頭白如絲作縣丞。錯判符曹群吏笑，", "年少力生猶不敵，況加憔悴悶騰騰。"]'),
('yuding-61','晚秋病中','王建','唐','御定全唐诗','yuding','','[]','萬事風吹過耳輪，貧兒活計亦曾聞。偶逢新語書紅葉，',40,'御定全唐詩/json/300.json','["萬事風吹過耳輪，貧兒活計亦曾聞。偶逢新語書紅葉，", "病多體痛無心力，更被頭邊藥氣熏。"]'),
('yuding-62','薛二十池亭','王建','唐','御定全唐诗','yuding','','[]','每個樹邊消一日，繞池行匝又須行。異花多是非時有，',40,'御定全唐詩/json/300.json','["每個樹邊消一日，繞池行匝又須行。異花多是非時有，", "浮萍著岸風吹歇，水面無塵晚更清。"]'),
('yuding-63','故梁國公主池亭','王建','唐','御定全唐诗','yuding','','[]','平陽池館枕秦川，門鎖南山一朵煙。素柰花開西子面，',40,'御定全唐詩/json/300.json','["平陽池館枕秦川，門鎖南山一朵煙。素柰花開西子面，", "寂寞空餘歌舞地，玉簫聲絕鳳歸天。"]'),
('yuding-64','題柱國寺','王建','唐','御定全唐诗','yuding','','[]','皇帝施錢修此院，半居天上半人間。丹梯暗出三重閣，',40,'御定全唐詩/json/300.json','["皇帝施錢修此院，半居天上半人間。丹梯暗出三重閣，", "行香天使長相續，早起離城日午還。"]'),
('yuding-65','昭應官舍書事','王建','唐','御定全唐诗','yuding','','[]','縣在華清宮北面，曉看樓殿正相當。慶雲出處依時報，',40,'御定全唐詩/json/300.json','["縣在華清宮北面，曉看樓殿正相當。慶雲出處依時報，", "兩衙早被官拘束，登閣巡溪亦屬忙。"]'),
('yuding-66','昭應李郎中見貽佳作次韻奉酬','王建','唐','御定全唐诗','yuding','','[]','窗戶風涼四面開，陶公愛晚上高臺。中庭不熱青山入，',40,'御定全唐詩/json/300.json','["窗戶風涼四面開，陶公愛晚上高臺。中庭不熱青山入，", "諸生圍繞新篇讀，玉闕仙官少此才。"]'),
('yuding-67','閑說','王建','唐','御定全唐诗','yuding','','[]','桃花百葉不成春，鶴壽千年也未神。秦隴州緣鸚鵡貴，',40,'御定全唐詩/json/300.json','["桃花百葉不成春，鶴壽千年也未神。秦隴州緣鸚鵡貴，", "鼓動六街騎馬出，相逢總是學狂人。"]'),
('yuding-68','自傷','王建','唐','御定全唐诗','yuding','','[]','衰門海內幾多人，滿眼公卿總不親。四授官資元七品，',40,'御定全唐詩/json/300.json','["衰門海內幾多人，滿眼公卿總不親。四授官資元七品，", "獨自在家長似客，黃昏哭向野田春。"]'),
('yuding-69','田侍中宴席','王建','唐','御定全唐诗','yuding','','[]','香熏羅幕暖成煙，火照中庭燭滿筵。整頓舞衣呈玉腕，',40,'御定全唐詩/json/300.json','["香熏羅幕暖成煙，火照中庭燭滿筵。整頓舞衣呈玉腕，", "雖是沂公門下客，爭將肉眼看雲天。"]'),
('yuding-70','寒食日看花','王建','唐','御定全唐诗','yuding','','[]','早入公門到夜歸，不因寒食少閒時。顛狂繞樹猿離鎖，',40,'御定全唐詩/json/300.json','["早入公門到夜歸，不因寒食少閒時。顛狂繞樹猿離鎖，", "老來自喜身無事，仰面西園得詠詩。"]'),
('yuding-71','和少府崔卿微雪早朝','王建','唐','御定全唐诗','yuding','','[]','蓬萊春雪曉猶殘，點地成花繞百官。已傍祥鸞迷殿角，',40,'御定全唐詩/json/300.json','["蓬萊春雪曉猶殘，點地成花繞百官。已傍祥鸞迷殿角，", "粉畫南山棱郭出，初晴一半隔雲看。"]'),
('yuding-72','和胡將軍寓直','王建','唐','御定全唐诗','yuding','','[]','宮鴉棲定禁槍攢，樓殿深嚴月色寒。進狀直穿金戟槊，',40,'御定全唐詩/json/300.json','["宮鴉棲定禁槍攢，樓殿深嚴月色寒。進狀直穿金戟槊，", "遙見正南宣不坐，新栽松樹喚人看。"]'),
('yuding-73','春日五門西望','王建','唐','御定全唐诗','yuding','','[]','百官朝下五門西。塵起春風過玉堤。黃帕蓋鞍呈了馬，',40,'御定全唐詩/json/300.json','["百官朝下五門西。塵起春風過玉堤。黃帕蓋鞍呈了馬，", "唯有教坊南草綠，古苔陰地冷淒淒。"]'),
('yuding-74','長安早春','王建','唐','御定全唐诗','yuding','','[]','霏霏漠漠繞皇州，銷雪欺寒不自由。先向紅妝添曉夢，',40,'御定全唐詩/json/300.json','["霏霏漠漠繞皇州，銷雪欺寒不自由。先向紅妝添曉夢，", "每度暗來還暗去，今年須遣蝶遲留。"]'),
('yuding-75','早春病中','王建','唐','御定全唐诗','yuding','','[]','日日春風階下起，不吹光彩上寒株。師教絳服禳衰月，',40,'御定全唐詩/json/300.json','["日日春風階下起，不吹光彩上寒株。師教絳服禳衰月，", "世間方法從誰問，臥處還看藥草圖。"]'),
('yuding-76','上陽宮','王建','唐','御定全唐诗','yuding','','[]','上陽花木不曾秋，洛水穿宮處處流。畫閣紅樓宮女笑，',40,'御定全唐詩/json/300.json','["上陽花木不曾秋，洛水穿宮處處流。畫閣紅樓宮女笑，", "曾讀列仙王母傳，九天未勝此中游。"]'),
('yuding-77','李處士故居','王建','唐','御定全唐诗','yuding','','[]','露濃煙重草萋萋，樹映闌幹柳拂堤。一院落花無客醉，',40,'御定全唐詩/json/300.json','["露濃煙重草萋萋，樹映闌幹柳拂堤。一院落花無客醉，", "風景宛然人自改，卻經門外馬頻嘶。"]'),
('yuding-78','寄賈島','王建','唐','御定全唐诗','yuding','','[]','盡日吟詩坐忍饑，萬人中覓似君稀。僮眠冷榻朝猶臥。',64,'御定全唐詩/json/300.json','["盡日吟詩坐忍饑，萬人中覓似君稀。僮眠冷榻朝猶臥。", "驢放秋田夜不歸。傍暖旋收紅落葉，覺寒猶著舊生衣。", "曲江池畔時時到，為愛鸕鷀雨後飛。"]'),
('yuding-79','村居即事','王建','唐','御定全唐诗','yuding','','[]','休看小字大書名，向日持經眼卻明。時過無心求富貴，',40,'御定全唐詩/json/300.json','["休看小字大書名，向日持經眼卻明。時過無心求富貴，", "斜月照房新睡覺，西峰半夜鶴來聲。"]'),
('yuding-80','維揚冬末寄幕中二從事','王建','唐','御定全唐诗','yuding','','[]','江上數株桑棗樹，自從離亂更荒涼。那堪旅館經殘臘，',40,'御定全唐詩/json/300.json','["江上數株桑棗樹，自從離亂更荒涼。那堪旅館經殘臘，", "故人多在芙蓉幕，應笑孜孜道未光。"]'),
('yuding-81','寄杜侍禦','王建','唐','御定全唐诗','yuding','','[]','何須服藥覓升天，粉閣為郎即是仙。買宅但幽從索價，',72,'御定全唐詩/json/300.json','["何須服藥覓升天，粉閣為郎即是仙。買宅但幽從索價，", "道氣清凝分曉爽，詩情冷瘦滴秋鮮。學通儒釋三千卷，", "破除心力緣書癖，傷瘦花枝為酒顛。今日總來歸聖代，"]'),
('yuding-82','寄上韓愈侍郎','王建','唐','御定全唐诗','yuding','','[]','重登大學領儒流，學浪詞鋒壓九州。不以雄名疏野賤，',72,'御定全唐詩/json/300.json','["重登大學領儒流，學浪詞鋒壓九州。不以雄名疏野賤，", "敘述異篇經總別，鞭驅險句最先投。碑文合遣貞魂謝，", "參來擬設官人禮，朝退多逢月閣遊。見說雲泉求住處，"]'),
('yuding-83','贈華州鄭大夫','王建','唐','御定全唐诗','yuding','','[]','此官出入鳳池頭，通化門前第一州。少華山雲當驛起，',48,'御定全唐詩/json/300.json','["此官出入鳳池頭，通化門前第一州。少華山雲當驛起，", "報狀拆開知足雨，赦書宣過喜無囚。自來不說雙旌貴，"]'),
('yuding-84','寄賀田侍中東平功成','王建','唐','御定全唐诗','yuding','','[]','使回高品滿城傳，親見沂公在陣前。百里旗幡沖即斷，',88,'御定全唐詩/json/300.json','["使回高品滿城傳，親見沂公在陣前。百里旗幡沖即斷，", "營被數驚乘勢破，將經頻敗遂生全。密招殘寇防人覺，", "開通州縣斜連海，交割山河直到燕。戰馬散驅還逐草，", "唐史上頭功第一，春風雙節好朝天。"]'),
('yuding-85','送裴相公上太原','王建','唐','御定全唐诗','yuding','','[]','還攜堂印向並州，將相兼權是武侯。時難獨當天下事，',72,'御定全唐詩/json/300.json','["還攜堂印向並州，將相兼權是武侯。時難獨當天下事，", "朱架早朝立劍戟，綠槐殘雨看張油。遙知塞雁從今好，", "千群白刃兵迎節，十對紅妝妓打球。聖主分明交暫去，"]'),
('yuding-0','題柏岩禪師影堂','王建','唐','御定全唐诗','yuding','','[]','山中磚塔閉，松下影堂新。恨不生前識，今朝禮畫身。',24,'御定全唐詩/json/301.json','["山中磚塔閉，松下影堂新。恨不生前識，今朝禮畫身。"]'),
('yuding-1','送人','王建','唐','御定全唐诗','yuding','','[]','河亭收酒器，語盡各西東。回首不相見，行車秋雨中。',24,'御定全唐詩/json/301.json','["河亭收酒器，語盡各西東。回首不相見，行車秋雨中。"]'),
('yuding-2','春意二首','王建','唐','御定全唐诗','yuding','','[]','去日丁寧別，情知寒食歸。緣逢好天氣，教熨看花衣。',48,'御定全唐詩/json/301.json','["去日丁寧別，情知寒食歸。緣逢好天氣，教熨看花衣。", "誰是杏園主，一枝臨古岐。從傷早春意，乞取欲開枝。"]'),
('yuding-3','夜聞子規','王建','唐','御定全唐诗','yuding','','[]','子規啼不歇，到曉口應穿。況是不眠夜，聲聲在耳邊。',24,'御定全唐詩/json/301.json','["子規啼不歇，到曉口應穿。況是不眠夜，聲聲在耳邊。"]'),
('yuding-4','四望驛松','王建','唐','御定全唐诗','yuding','','[]','當初北澗別，直至此庭中。何意聞鞞耳，聽君枝上風。',24,'御定全唐詩/json/301.json','["當初北澗別，直至此庭中。何意聞鞞耳，聽君枝上風。"]'),
('yuding-5','江館','王建','唐','御定全唐诗','yuding','','[]','水面細風生，菱歌慢慢聲。客亭臨小市，燈火夜妝明。',24,'御定全唐詩/json/301.json','["水面細風生，菱歌慢慢聲。客亭臨小市，燈火夜妝明。"]'),
('yuding-6','題江台驛','王建','唐','御定全唐诗','yuding','','[]','水北金台路，年年行客稀。近聞天子使，多取雁門歸。',24,'御定全唐詩/json/301.json','["水北金台路，年年行客稀。近聞天子使，多取雁門歸。"]'),
('yuding-7','贈謫者','王建','唐','御定全唐诗','yuding','','[]','何罪過長沙，年年北望家。重封嶺頭信，一樹海邊花。',24,'御定全唐詩/json/301.json','["何罪過長沙，年年北望家。重封嶺頭信，一樹海邊花。"]'),
('yuding-8','戲酬盧秘書','王建','唐','御定全唐诗','yuding','','[]','芸香閣裏人，採摘禦園春。取此和仙藥，猶治老病身。',24,'御定全唐詩/json/301.json','["芸香閣裏人，採摘禦園春。取此和仙藥，猶治老病身。"]'),
('yuding-9','小松','王建','唐','御定全唐诗','yuding','','[]','小松初數尺，未有直生枝。閑即傍邊立，看多長卻遲。',24,'御定全唐詩/json/301.json','["小松初數尺，未有直生枝。閑即傍邊立，看多長卻遲。"]'),
('yuding-10','秋夜','王建','唐','御定全唐诗','yuding','','[]','夜久葉露滴，秋蟲入戶飛。臥多骨髓冷，起覆舊綿衣。',24,'御定全唐詩/json/301.json','["夜久葉露滴，秋蟲入戶飛。臥多骨髓冷，起覆舊綿衣。"]'),
('yuding-11','水精','王建','唐','御定全唐诗','yuding','','[]','映水色不別，向月光還度。傾在荷葉中，有時看是露。',24,'御定全唐詩/json/301.json','["映水色不別，向月光還度。傾在荷葉中，有時看是露。"]'),
('yuding-12','香印','王建','唐','御定全唐诗','yuding','','[]','閑坐燒印香，滿戶松柏氣。火盡轉分明，青苔碑上字。',24,'御定全唐詩/json/301.json','["閑坐燒印香，滿戶松柏氣。火盡轉分明，青苔碑上字。"]'),
('yuding-13','秋燈','王建','唐','御定全唐诗','yuding','','[]','向壁暖悠悠，羅幃寒寂寂。斜照碧山圖，松間一片石。',24,'御定全唐詩/json/301.json','["向壁暖悠悠，羅幃寒寂寂。斜照碧山圖，松間一片石。"]'),
('yuding-14','落葉','王建','唐','御定全唐诗','yuding','','[]','陳綠向參差，初紅已重疊。中庭初掃地，繞樹三兩葉。',24,'御定全唐詩/json/301.json','["陳綠向參差，初紅已重疊。中庭初掃地，繞樹三兩葉。"]'),
('yuding-15','園果','王建','唐','御定全唐诗','yuding','','[]','雨中梨果病，每樹無數個。小兒出入看，一半鳥啄破。',24,'御定全唐詩/json/301.json','["雨中梨果病，每樹無數個。小兒出入看，一半鳥啄破。"]'),
('yuding-16','野菊','王建','唐','御定全唐诗','yuding','','[]','晚豔出荒籬，冷香著秋水。憶向山中見，伴蛩石壁裏。',24,'御定全唐詩/json/301.json','["晚豔出荒籬，冷香著秋水。憶向山中見，伴蛩石壁裏。"]'),
('yuding-17','荒園','王建','唐','御定全唐诗','yuding','','[]','朝日滿園霜，牛沖籬落壞。掃掠黃葉中，時時一窠薤。',24,'御定全唐詩/json/301.json','["朝日滿園霜，牛沖籬落壞。掃掠黃葉中，時時一窠薤。"]'),
('yuding-18','南澗','王建','唐','御定全唐诗','yuding','','[]','野桂香滿溪，石莎寒覆水。愛此南澗頭，終日潺湲裏。',24,'御定全唐詩/json/301.json','["野桂香滿溪，石莎寒覆水。愛此南澗頭，終日潺湲裏。"]'),
('yuding-19','晚蝶','王建','唐','御定全唐诗','yuding','','[]','粉翅嫩如水，繞砌乍依風。日高山露解，飛入菊花中。',24,'御定全唐詩/json/301.json','["粉翅嫩如水，繞砌乍依風。日高山露解，飛入菊花中。"]'),
('yuding-20','田家','王建','唐','御定全唐诗','yuding','','[]','啾啾雀滿樹，靄靄東坡雨。田家夜無食，水中摘禾黍。',24,'御定全唐詩/json/301.json','["啾啾雀滿樹，靄靄東坡雨。田家夜無食，水中摘禾黍。"]'),
('yuding-21','新嫁娘詞三首','王建','唐','御定全唐诗','yuding','','[]','鄰家人未識，床上坐堆堆。郎來傍門戶，滿口索錢財。',72,'御定全唐詩/json/301.json','["鄰家人未識，床上坐堆堆。郎來傍門戶，滿口索錢財。", "錦幛兩邊橫，遮掩侍娘行。遣郎鋪簟席，相並拜親情。", "三日入廚下，洗手作羹湯。未諳姑食性，先遣小姑嘗。"]'),
('yuding-22','故行宮','王建','唐','御定全唐诗','yuding','','[]','寥落古行宮，宮花寂寞紅。白頭宮女在，閑坐說玄宗。',24,'御定全唐詩/json/301.json','["寥落古行宮，宮花寂寞紅。白頭宮女在，閑坐說玄宗。"]'),
('yuding-23','酬從侄再看詩本','王建','唐','御定全唐诗','yuding','','[]','眼暗沒功夫，慵來剪刻粗。自看花樣古，稱得少年無。',24,'御定全唐詩/json/301.json','["眼暗沒功夫，慵來剪刻粗。自看花樣古，稱得少年無。"]'),
('yuding-24','別自栽小樹','王建','唐','御定全唐诗','yuding','','[]','去年今日栽，臨去見花開。好住守空院，夜間人不來。',24,'御定全唐詩/json/301.json','["去年今日栽，臨去見花開。好住守空院，夜間人不來。"]'),
('yuding-25','早發汾南','王建','唐','御定全唐诗','yuding','','[]','橋上車馬發，橋南煙樹開。青山斜不斷，迢遞故鄉來。',24,'御定全唐詩/json/301.json','["橋上車馬發，橋南煙樹開。青山斜不斷，迢遞故鄉來。"]'),
('yuding-26','宮中三臺詞二首','王建','唐','御定全唐诗','yuding','','[]','魚藻池邊射鴨，芙蓉園裏看花。',56,'御定全唐詩/json/301.json','["魚藻池邊射鴨，芙蓉園裏看花。", "日色柘袍相似，不著紅鸞扇遮。", "池北池南草綠，殿前殿后花紅。", "天子千年萬歲，未央明月清風。"]'),
('yuding-27','江南三臺詞四首','王建','唐','御定全唐诗','yuding','','[]','揚州橋邊少婦，長安城裏商人。',112,'御定全唐詩/json/301.json','["揚州橋邊少婦，長安城裏商人。", "二年不得消息，各自拜鬼求神。", "青草湖邊草色，飛猿嶺上猿聲。", "萬里湘江客到，有風有雨人行。", "樹頭花落花開，道上人去人來。", "朝愁暮愁即老，百年幾度三台。", "聞身強健且為，頭白齒落難追。", "准擬百年千歲，能得幾許多時。"]'),
('yuding-28','禦獵','王建','唐','御定全唐诗','yuding','','[]','青山直繞鳳城頭，滻水斜分入禦溝。',32,'御定全唐詩/json/301.json','["青山直繞鳳城頭，滻水斜分入禦溝。", "新教內人唯射鴨，長隨天子苑東游。"]'),
('yuding-29','長門燭','王建','唐','御定全唐诗','yuding','','[]','秋夜床前蠟燭微，銅壺滴盡曉鐘遲。',32,'御定全唐詩/json/301.json','["秋夜床前蠟燭微，銅壺滴盡曉鐘遲。", "殘光欲滅還吹著，年少宮人未睡時。"]'),
('yuding-30','過綺岫宮','王建','唐','御定全唐诗','yuding','','[]','玉樓傾倒粉牆空，重疊青山繞故宮。',32,'御定全唐詩/json/301.json','["玉樓傾倒粉牆空，重疊青山繞故宮。", "武帝去來羅袖盡，野花黃蝶領春風。"]'),
('yuding-31','朝天詞十首寄上魏博田侍中','王建','唐','御定全唐诗','yuding','','[]','山川初展國圖寬，未識龍顏坐不安。',320,'御定全唐詩/json/301.json','["山川初展國圖寬，未識龍顏坐不安。", "風動白髯旌節下，過時天子禦樓看。", "相感君臣總淚流，恩深舞蹈不知休。", "初從戰地來無物，唯奏新添十八州。", "催修水殿宴沂公，與別諸侯總不同。", "隔月太常先習樂，金書牌纛彩雲中。", "無人敢奪在先籌，天子門邊送與球。", "遙索彩箱新樣錦，內人舁出馬前頭。", "禦馬牽來親自試，珠球到處玉蹄知。", "殿頭宣賜連催上，未解紅纓不敢騎。", "老作三公經獻壽，臨時猶自語差池。", "私從班裏來長跪，捧上金杯便合儀。", "四海無波乞放閑，三封手疏犯龍顏。", "他時若有邊塵動，不待天書自出山。", "胡馬悠悠未盡歸，玉關猶隔吐蕃旗。", "老臣一表求高臥，邊事從今欲問誰。", "威容難畫改頻頻，眉目分毫恐不真。", "有詔別圖書閣上，先教粉本定風神。", "重賜弓刀內宴回，看人城外滿樓臺。", "君臣不作多時別，收盡邊旗當日來。"]'),
('yuding-32','霓裳詞十首','王建','唐','御定全唐诗','yuding','','[]','弟子部中留一色，聽風聽水作霓裳。',320,'御定全唐詩/json/301.json','["弟子部中留一色，聽風聽水作霓裳。", "散聲未足重來授，直到床前見上皇。", "中管五弦初半曲，遙教合上隔簾聽。", "一聲聲向天頭落，效得仙人夜唱經。", "自直梨園得出稀，更番上曲不教歸。", "一時跪拜霓裳徹，立地階前賜紫衣。", "旋翻新譜聲初足，除卻梨園未教人。", "宣與書家分手寫，中官走馬賜功臣。", "伴教霓裳有貴妃，從初直到曲成時。", "日長耳裏聞聲熟，拍數分毫錯總知。", "弦索摐摐隔彩雲，五更初發一山聞。", "武皇自送西王母，新換霓裳月色裙。", "敕賜宮人澡浴回，遙看美女院門開。", "一山星月霓裳動，好字先從殿裏來。", "傳呼法部按霓裳，新得承恩別作行。", "應是貴妃樓上看，內人舁下彩羅箱。", "朝元閣上山風起，夜聽霓裳玉露寒。", "宮女月中更替立，黃金梯滑並行難。", "知向華清年月滿，山頭山底種長生。", "去時留下霓裳曲，總是離宮別館聲。"]'),
('yuding-33','宮前早春','王建','唐','御定全唐诗','yuding','','[]','酒幔高樓一百家，宮前楊柳寺前花。',32,'御定全唐詩/json/301.json','["酒幔高樓一百家，宮前楊柳寺前花。", "內園分得溫湯水，二月中旬已進瓜。"]'),
('yuding-34','奉同曾郎中題石甕寺得嵌韻','王建','唐','御定全唐诗','yuding','','[]','寺門連內繞丹岩，下界雲開數過帆。',32,'御定全唐詩/json/301.json','["寺門連內繞丹岩，下界雲開數過帆。", "遙指上皇翻曲處，百官題字滿西嵌。"]'),
('yuding-35','舊宮人','王建','唐','御定全唐诗','yuding','','[]','先帝舊宮宮女在，亂絲猶掛鳳凰釵。',32,'御定全唐詩/json/301.json','["先帝舊宮宮女在，亂絲猶掛鳳凰釵。", "霓裳法曲渾拋卻，獨自花間掃玉階。"]'),
('yuding-36','新授戒尼師','王建','唐','御定全唐诗','yuding','','[]','新短方裙疊作棱，聽鐘洗缽繞青蠅。',32,'御定全唐詩/json/301.json','["新短方裙疊作棱，聽鐘洗缽繞青蠅。", "自知戒相分明後，先出壇場禮大僧。"]'),
('yuding-37','太和公主和蕃','王建','唐','御定全唐诗','yuding','','[]','塞黑雲黃欲渡河，風沙眯眼雪相和。',32,'御定全唐詩/json/301.json','["塞黑雲黃欲渡河，風沙眯眼雪相和。", "琵琶淚濕行聲小，斷得人腸不在多。"]'),
