('yuding-91','寄劉蕡問疾','王建','唐','御定全唐诗','yuding','','[]','年少病多應為酒，誰家將息過今春。',32,'御定全唐詩/json/301.json','["年少病多應為酒，誰家將息過今春。", "賒來半夏重熏盡，投著山中舊主人。"]'),
('yuding-92','聽雨','王建','唐','御定全唐诗','yuding','','[]','半夜思家睡裏愁，雨聲落落屋簷頭。',32,'御定全唐詩/json/301.json','["半夜思家睡裏愁，雨聲落落屋簷頭。", "照泥星出依前黑，淹爛庭花不肯休。"]'),
('yuding-93','新晴','王建','唐','御定全唐诗','yuding','','[]','夏夜新晴星校少，雨收殘水入天河。',32,'御定全唐詩/json/301.json','["夏夜新晴星校少，雨收殘水入天河。", "簷前熟著衣裳坐，風冷渾無撲火蛾。"]'),
('yuding-94','秋日後','王建','唐','御定全唐诗','yuding','','[]','住處近山常足雨，聞晴z4曝舊芳茵。',33,'御定全唐詩/json/301.json','["住處近山常足雨，聞晴z4曝舊芳茵。", "立秋日後無多熱，漸覺生衣不著身。"]'),
('yuding-95','哭孟東野二首','王建','唐','御定全唐诗','yuding','','[]','吟損秋天月不明，蘭無香氣鶴無聲。',64,'御定全唐詩/json/301.json','["吟損秋天月不明，蘭無香氣鶴無聲。", "自從東野先生死，側近雲山得散行。", "老松臨死不生枝，東野先生早哭兒。", "但是洛陽城裏客，家傳一本杏殤詩。"]'),
('yuding-96','寄蜀中薛濤校書','王建','唐','御定全唐诗','yuding','','[]','萬里橋邊女校書，枇杷花裏閉門居。',32,'御定全唐詩/json/301.json','["萬里橋邊女校書，枇杷花裏閉門居。", "掃眉才子於今少，管領春風總不如。"]'),
('yuding-97','路中上田尚書','王建','唐','御定全唐诗','yuding','','[]','去路何詞見六親，手中刀尺不如人。',32,'御定全唐詩/json/301.json','["去路何詞見六親，手中刀尺不如人。", "可憐池閣秋風夜，愁綠嬌紅一遍新。"]'),
('yuding-98','於主簿廳看花','王建','唐','御定全唐诗','yuding','','[]','小葉稠枝粉壓摧，暖風吹動鶴翎開。',32,'御定全唐詩/json/301.json','["小葉稠枝粉壓摧，暖風吹動鶴翎開。", "若無別事為留滯，應便拋家宿看來。"]'),
('yuding-99','江樓對雨寄杜書記','王建','唐','御定全唐诗','yuding','','[]','竹煙花雨細相和，看著閒書睡更多。',32,'御定全唐詩/json/301.json','["竹煙花雨細相和，看著閒書睡更多。", "好是主人無事日，應持小酒按新歌。"]'),
('yuding-100','觀蠻妓','王建','唐','御定全唐诗','yuding','','[]','欲說昭君斂翠蛾，清聲委曲怨於歌。',32,'御定全唐詩/json/301.json','["欲說昭君斂翠蛾，清聲委曲怨於歌。", "誰家年少春風裏，拋與金錢唱好多。"]'),
('yuding-101','送顧非熊秀才歸丹陽','王建','唐','御定全唐诗','yuding','','[]','江城柳色海門煙，欲到茅山始下船。',32,'御定全唐詩/json/301.json','["江城柳色海門煙，欲到茅山始下船。", "知道君家當瀑布，菖蒲潭在草堂前。"]'),
('yuding-102','老人歌','王建','唐','御定全唐诗','yuding','','[]','白髮老人垂淚行，上皇生日出京城。',32,'御定全唐詩/json/301.json','["白髮老人垂淚行，上皇生日出京城。", "如今供奉多新意，錯唱當時一半聲。"]'),
('yuding-103','和元郎中從八月十二至十五夜玩月五首','王建','唐','御定全唐诗','yuding','','[]','半秋初入中旬夜，已向階前守月明。',160,'御定全唐詩/json/301.json','["半秋初入中旬夜，已向階前守月明。", "從未圓時看卻好，一分分見傍輪生。", "亂雲遮卻台東月，不許教依次第看。", "莫為詩家先見鏡，被他籠與作艱難。", "今夜月明勝昨夜，新添桂樹近東枝。", "立多地濕舁床坐，看過牆西寸寸遲。", "月似圓來色漸凝，玉盆盛水欲侵棱。", "夜深盡放家人睡，直到天明不炷燈。", "合望月時常望月，分明不得似今年。", "仰頭五夜風中立，從未圓時直到圓。"]'),
('yuding-104','對酒','王建','唐','御定全唐诗','yuding','','[]','為病比來渾斷絕，緣花不免卻知聞。',32,'御定全唐詩/json/301.json','["為病比來渾斷絕，緣花不免卻知聞。", "從來事事關身少，主領春風只在君。"]'),
('yuding-105','曉望華清宮','王建','唐','御定全唐诗','yuding','','[]','曉來樓閣更鮮明，日出闌幹見鹿行。',32,'御定全唐詩/json/301.json','["曉來樓閣更鮮明，日出闌幹見鹿行。", "武帝自知身不死，看修玉殿號長生。"]'),
('yuding-106','贈李愬僕射二首','王建','唐','御定全唐诗','yuding','','[]','和雪翻營一夜行，神旗凍定馬無聲。',64,'御定全唐詩/json/301.json','["和雪翻營一夜行，神旗凍定馬無聲。", "遙看火號連營赤，知是先鋒已上城。", "旗幡四面下營稠，手詔頻來老將憂。", "每日城南空挑戰，不知生縛入唐州。"]'),
('yuding-107','秋夜對雨寄石甕寺二秀才','王建','唐','御定全唐诗','yuding','','[]','夜山秋雨滴空廊，燈照堂前樹葉光。',32,'御定全唐詩/json/301.json','["夜山秋雨滴空廊，燈照堂前樹葉光。", "對坐讀書終卷後，自披衣被掃僧房。"]'),
('yuding-108','華清宮前柳','王建','唐','御定全唐诗','yuding','','[]','楊柳宮前忽地春，在先驚動探春人。',32,'御定全唐詩/json/301.json','["楊柳宮前忽地春，在先驚動探春人。", "曉來唯欠驪山雨，洗卻枝頭綠上塵。"]'),
('yuding-109','別楊校書','王建','唐','御定全唐诗','yuding','','[]','從軍秣馬十三年，白髮營中聽早蟬。',32,'御定全唐詩/json/301.json','["從軍秣馬十三年，白髮營中聽早蟬。", "故作老丞身不避，縣名昭應管山泉。"]'),
('yuding-110','和門下武相公春曉聞鶯','王建','唐','御定全唐诗','yuding','','[]','侵黑行飛一兩聲，春寒囀小未分明。',32,'御定全唐詩/json/301.json','["侵黑行飛一兩聲，春寒囀小未分明。", "若教更解諸餘語，應向宮花不惜情。"]'),
('yuding-111','田侍郎歸鎮','王建','唐','御定全唐诗','yuding','','[]','去處長將決勝籌，回回身在陣前頭。',256,'御定全唐詩/json/301.json','["去處長將決勝籌，回回身在陣前頭。", "賊城破後先鋒入，看著紅妝不敢收。", "熨帖朝衣拋戰袍，夔龍班裏侍中高。", "對時先奏牙間將，次第天恩與節旄。", "踏著家鄉馬腳輕，暮山秋色眼前明。", "老人上酒齊頭拜，得侍中來盡再生。", "功成誰不擁藩方，富貴還須是本鄉。", "萬里雙旌汾水上，玉鞭遙指白雲莊。", "鼓吹幡旗道兩邊，行男走女喜駢闐。", "舊交省得當時別，指點如今卻少年。", "廣場破陣樂初休，彩纛高於百尺樓。", "老將氣雄爭起舞，管弦回作大纏頭。", "笳聲萬里動燕山，草白天清塞馬閑。", "觸處不如別處樂，可憐秋月照江關。", "將士請衣忘卻貧，綠窗紅燭酒樓新。", "家家盡踏還鄉曲，明月街中不絕人。"]'),
('yuding-112','寄廣文張博士','王建','唐','御定全唐诗','yuding','','[]','春明門外作卑官，病友經年不得看。',32,'御定全唐詩/json/301.json','["春明門外作卑官，病友經年不得看。", "莫道長安近於日，升天卻易到城難。"]'),
('yuding-113','早春書情','王建','唐','御定全唐诗','yuding','','[]','漸老風光不著人，花溪柳陌早逢春。',32,'御定全唐詩/json/301.json','["漸老風光不著人，花溪柳陌早逢春。", "近來行到門前少，趁暖閑眠似病人。"]'),
('yuding-114','唐昌觀玉蕊花','王建','唐','御定全唐诗','yuding','','[]','一樹籠松玉刻成，飄廊點地色輕輕。',32,'御定全唐詩/json/301.json','["一樹籠松玉刻成，飄廊點地色輕輕。", "女冠夜覓香來處，唯見階前碎月明。"]'),
('yuding-115','眼病寄同官','王建','唐','御定全唐诗','yuding','','[]','天寒眼痛少心情，隔霧看人夜裏行。',32,'御定全唐詩/json/301.json','["天寒眼痛少心情，隔霧看人夜裏行。", "年少往來常不住，牆西凍地馬蹄聲。"]'),
('yuding-116','九日登叢台','王建','唐','御定全唐诗','yuding','','[]','平原池閣在誰家，雙塔叢台野菊花。',32,'御定全唐詩/json/301.json','["平原池閣在誰家，雙塔叢台野菊花。", "零落故宮無入路，西來澗水繞城斜。"]'),
('yuding-117','題酸棗縣蔡中郎碑','王建','唐','御定全唐诗','yuding','','[]','蒼苔滿字土埋龜，風雨銷磨絕妙詞。',32,'御定全唐詩/json/301.json','["蒼苔滿字土埋龜，風雨銷磨絕妙詞。", "不向圖經中舊見，無人知是蔡邕碑。"]'),
('yuding-118','江陵使至汝州','王建','唐','御定全唐诗','yuding','','[]','回看巴路在雲間，寒食離家麥熟還。',32,'御定全唐詩/json/301.json','["回看巴路在雲間，寒食離家麥熟還。", "日暮數峰青似染，商人說是汝州山。"]'),
('yuding-119','十五夜望月寄杜郎中','王建','唐','御定全唐诗','yuding','','[]','中庭地白樹棲鴉，冷露無聲濕桂花。',32,'御定全唐詩/json/301.json','["中庭地白樹棲鴉，冷露無聲濕桂花。", "今夜月明人盡望，不知秋思在誰家。"]'),
('yuding-120','寄同州田長史','王建','唐','御定全唐诗','yuding','','[]','除聽好語耳常聾，不見詩人眼底空。',32,'御定全唐詩/json/301.json','["除聽好語耳常聾，不見詩人眼底空。", "莫怪出城為長史，總緣山在白雲中。"]'),
('yuding-121','外按','王建','唐','御定全唐诗','yuding','','[]','夾城門向野田開，白鹿非時出洞來。',32,'御定全唐詩/json/301.json','["夾城門向野田開，白鹿非時出洞來。", "日暮秦陵塵土起，從東外按使初回。"]'),
('yuding-0','宮詞一百首','王建','唐','御定全唐诗','yuding','','[]','蓬萊正殿壓金鼇，紅日初生碧海濤。',384,'御定全唐詩/json/302.json','["蓬萊正殿壓金鼇，紅日初生碧海濤。", "閑著五門遙北望，柘黃新帕禦床高。", "殿前傳點各依班，召對西來八詔蠻。", "上得青花龍尾道，側身偷覷正南山。", "龍煙日暖紫曈曈，宣政門當玉殿風。", "五刻閣前卿相出，下簾聲在半天中。", "白玉窗前起草臣，櫻桃初赤賜嘗新。", "殿頭傳語金階遠，只進詞來謝聖人。", "內人對禦疊花箋，繡坐移來玉案邊。", "紅蠟燭前呈草本，平明舁出閣門宣。", "千牛仗下放朝初，玉案傍邊立起居。", "每日進來金鳳紙，殿頭無事不多書。", "延英引對碧衣郎，江硯宣毫各別床。", "天子下簾親考試，宮人手裏過茶湯。", "未明開著九重關，金畫黃龍五色幡。", "直到銀台排仗合，聖人三殿對西番。", "少年天子重邊功，親到淩煙畫閣中。", "教覓勳臣寫圖本，長將殿裏作屏風。", "丹鳳樓門把火開，五雲金輅下天來。", "階前走馬人宣尉，天子南郊一宿回。", "樓前立仗看宣赦，萬歲聲長拜舞齊。", "日照彩盤高百尺，飛仙爭上取金雞。", "集賢殿裏圖書滿，點勘頭邊禦印同。", "真跡進來依數字，別收鎖在玉函中。"]'),
('yuding-1','句','王建','唐','御定全唐诗','yuding','','[]','單于不向南牧馬，席萁遍滿天山下。',84,'御定全唐詩/json/302.json','["單于不向南牧馬，席萁遍滿天山下。", "卻公不易勝，莫著外家欺。", "錦江詩弟子，時寄五花箋。", "花燒落第眼，雨破到家程。", "一朝金鳳庭前下，當是虛皇詔沈曦。", "宣城四面水茫茫，草蓋江城竹夾牆。"]'),
('yuding-0','銅雀妓','劉商','唐','御定全唐诗','yuding','','[]','魏主矜蛾眉，美人美于玉。高臺無晝夜，歌舞竟未足。',132,'御定全唐詩/json/303.json','["魏主矜蛾眉，美人美于玉。高臺無晝夜，歌舞竟未足。", "盛色如轉圜，夕陽落深谷。仍令身歿後，尚縱平生欲。", "紅粉淚縱橫，調弦向空屋。舉頭君不在，惟見西陵木。", "玉輦豈再來，嬌鬟為誰綠。那堪秋風裏，更舞陽春曲。", "曲罷情不勝，憑闌向西哭。台邊生野草，來去罥羅縠。", "況複陵寢間，雙雙見麋鹿。"]'),
('yuding-1','哭韓淮端公兼上崔中丞','劉商','唐','御定全唐诗','yuding','','[]','堅貞與和璧，利用歸幹將。金玉徒自寶，高賢無比方。',216,'御定全唐詩/json/303.json','["堅貞與和璧，利用歸幹將。金玉徒自寶，高賢無比方。", "挺生岩松姿，孤直淩雪霜。亭亭結清陰，不競桃李芳。", "讀書哂霸業，翊贊思皇王。千載有疑議，一言能否臧。", "儒風久淪弊，顏閔壽不長。邦國豈殄瘁，斯人今又亡。", "別離長春草，存沒隔楚鄉。聞問尚書慟，淚凝向日黃。", "奄忽薤露晞，杳冥泉夜長。賢愚自修短，天色空蒼蒼。", "銘旌斂歸魂，荊棘生路傍。門柳日蕭索，繐帷掩空堂。", "燈孤晦處明，高節歿後彰。芳蘭已灰燼，幕府留餘香。", "常愛獨坐尊，繡衣如雁行。至今虛左位，言發淚沾裳。"]'),
('yuding-2','秋夜聽嚴紳巴童唱竹枝歌','劉商','唐','御定全唐诗','yuding','','[]','巴人遠從荊山客，回首荊山楚雲隔。思歸夜唱竹枝歌，',72,'御定全唐詩/json/303.json','["巴人遠從荊山客，回首荊山楚雲隔。思歸夜唱竹枝歌，", "身騎吳牛不畏虎，手提蓑笠欺風雨。猿啼日暮江岸邊，", "鴻雁南飛報鄰伍，在家歡樂辭家苦。天晴露白鐘漏遲，"]'),
('yuding-3','烏夜啼','劉商','唐','御定全唐诗','yuding','','[]','繞樹啞啞驚複棲，含煙碧樹高枝齊。月明露濕枝亦滑，',48,'御定全唐詩/json/303.json','["繞樹啞啞驚複棲，含煙碧樹高枝齊。月明露濕枝亦滑，", "月中有桂樹，日中有伴侶。何不上天去，一聲啼到曙。"]'),
('yuding-4','隨陽雁歌送兄南游','劉商','唐','御定全唐诗','yuding','','[]','塞鴻聲聲飛不住，終日南征向何處。大漠窮陰多冱寒，',48,'御定全唐詩/json/303.json','["塞鴻聲聲飛不住，終日南征向何處。大漠窮陰多冱寒，", "寒飛萬里胡天雪。夜度千門漢家月。去住應多兩地情，"]'),
('yuding-5','賦得射雉歌送楊協律表弟赴婚期','劉商','唐','御定全唐诗','yuding','','[]','昔日才高容貌古，相敬如賓不相睹。手奉蘋蘩喜盛門，',96,'御定全唐詩/json/303.json','["昔日才高容貌古，相敬如賓不相睹。手奉蘋蘩喜盛門，", "結束車輿強游往，和風霽日東皋上。鸞鳳參差陌上行，", "六藝從師得機要，百發穿楊含絕妙。白羽風馳碎錦毛，", "聽調琴弄能和室，更解彎弧足自防。秋深為爾持圓扇，"]'),
('yuding-6','泛舒城南溪賦得沙鶴歌奉餞張侍御赴河南元博士赴揚州拜覲僕射','劉商','唐','御定全唐诗','yuding','','[]','終日閭閻逐群雞，喜逢野鶴臨清溪。綠苔春水水中影，',72,'御定全唐詩/json/303.json','["終日閭閻逐群雞，喜逢野鶴臨清溪。綠苔春水水中影，", "紫頂昂藏肯狎人，一聲嘹亮沖天闕。素質翩翩帶落暉，", "皇華地仙如鶴馭，乘駕飄飄留不住。延望乘虛入紫霞，"]'),
('yuding-7','姑蘇懷古送秀才下第歸江南','劉商','唐','御定全唐诗','yuding','','[]','姑蘇台枕吳江水，層級鱗差向天倚。秋高露白萬林空，',168,'御定全唐詩/json/303.json','["姑蘇台枕吳江水，層級鱗差向天倚。秋高露白萬林空，", "台前夾月吹玉鸞，臺上迎涼撼金翠。銀河倒瀉君王醉，", "伍員結舌長噓嚱，忠諫無因到君耳。城烏啼盡海霞銷，", "會稽勾踐擁長矛，萬馬鳴蹄掃空壘。瓦解冰銷真可恥，", "君懷逸氣還東吳，吟狂日日游姑蘇。興來下筆到奇景，", "海潮秋打羅刹石，月魄夜當彭蠡湖。有時凝思家虛無，", "君聲日下聞來久，清贍何人敢敵手。我逃名跡遁西林，"]'),
('yuding-8','金井歌','劉商','唐','御定全唐诗','yuding','','[]','文明化洽天地清，和氣氤氳孕至靈。瑞雪不散抱層嶺，',72,'御定全唐詩/json/303.json','["文明化洽天地清，和氣氤氳孕至靈。瑞雪不散抱層嶺，", "虞衡相賀為禎祥，畏人采攫持殳戕。羊馳馬走塵滿道，", "山澤藏金與萬人，宣言郡邑無專利。閭閻少長競奔湊，"]'),
('yuding-9','柳條歌送客','劉商','唐','御定全唐诗','yuding','','[]','露井夭桃春未到，遲日猶寒柳開早。高枝低枝飛鸝黃，',48,'御定全唐詩/json/303.json','["露井夭桃春未到，遲日猶寒柳開早。高枝低枝飛鸝黃，", "毿毿拂人行不進，依依送君無遠近。青春去住隨柳條，"]'),
('yuding-10','胡笳十八拍：第一拍','劉商','唐','御定全唐诗','yuding','','[]','漢室將衰兮四夷不賓，動干戈兮征戰頻。',58,'御定全唐詩/json/303.json','["漢室將衰兮四夷不賓，動干戈兮征戰頻。", "哀哀父母生育我，見離亂兮當此辰。紗窗對鏡未經事，", "忽將薄命委鋒鏑，可惜紅顏隨虜塵。"]'),
('yuding-11','胡笳十八拍：第二拍','劉商','唐','御定全唐诗','yuding','','[]','馬上將余向絕域，厭生求死死不得。戎羯腥膻豈是人，',40,'御定全唐詩/json/303.json','["馬上將余向絕域，厭生求死死不得。戎羯腥膻豈是人，", "萬里重陰鳥不飛，寒沙莽莽無南北。"]'),
('yuding-12','胡笳十八拍：第三拍','劉商','唐','御定全唐诗','yuding','','[]','如羈囚兮在縲絏，憂慮萬端無處說。使余刀兮剪餘發，',40,'御定全唐詩/json/303.json','["如羈囚兮在縲絏，憂慮萬端無處說。使余刀兮剪餘發，", "早被蛾眉累此身，空悲弱質柔如水。"]'),
('yuding-13','胡笳十八拍：第四拍','劉商','唐','御定全唐诗','yuding','','[]','山川路長誰記得，何處天涯是鄉國。自從驚怖少精神，',40,'御定全唐詩/json/303.json','["山川路長誰記得，何處天涯是鄉國。自從驚怖少精神，", "漫漫胡天叫不聞，明明漢月應相識。"]'),
('yuding-14','胡笳十八拍：第五拍','劉商','唐','御定全唐诗','yuding','','[]','水頭宿兮草頭坐，風吹漢地衣裳破。羊脂沐發長不梳，',40,'御定全唐詩/json/303.json','["水頭宿兮草頭坐，風吹漢地衣裳破。羊脂沐發長不梳，", "氈帳時移無定居，日月長兮不可過。"]'),
('yuding-15','胡笳十八拍：第六拍','劉商','唐','御定全唐诗','yuding','','[]','怪得春光不來久，胡中風土無花柳。天翻地覆誰得知，',40,'御定全唐詩/json/303.json','["怪得春光不來久，胡中風土無花柳。天翻地覆誰得知，", "是非取與在指撝，言語傳情不如手。"]'),
('yuding-16','胡笳十八拍：第七拍','劉商','唐','御定全唐诗','yuding','','[]','男兒婦人帶弓箭，塞馬蕃羊臥霜霰。寸步東西豈自由，',40,'御定全唐詩/json/303.json','["男兒婦人帶弓箭，塞馬蕃羊臥霜霰。寸步東西豈自由，", "竟夕無雲月上天，故鄉應得重相見。"]'),
('yuding-17','胡笳十八拍：第八拍','劉商','唐','御定全唐诗','yuding','','[]','憶昔私家恣嬌小，遠取珍禽學馴擾。如今淪棄念故鄉，',40,'御定全唐詩/json/303.json','["憶昔私家恣嬌小，遠取珍禽學馴擾。如今淪棄念故鄉，", "旦夕思歸不得歸，愁心想似籠中鳥。"]'),
('yuding-18','胡笳十八拍：第九拍','劉商','唐','御定全唐诗','yuding','','[]','當日蘇武單于問，道是賓鴻解傳信。學他刺血寫得書，',40,'御定全唐詩/json/303.json','["當日蘇武單于問，道是賓鴻解傳信。學他刺血寫得書，", "遂令邊雁轉怕人，絕域何由達方寸。"]'),
('yuding-19','胡笳十八拍：第十拍','劉商','唐','御定全唐诗','yuding','','[]','恨淩辱兮惡腥膻，憎胡地兮怨胡天。生得胡兒欲棄捐，',40,'御定全唐詩/json/303.json','["恨淩辱兮惡腥膻，憎胡地兮怨胡天。生得胡兒欲棄捐，", "朝朝暮暮在眼前，腹生手養甯不憐。"]'),
('yuding-20','胡笳十八拍：第十一拍','劉商','唐','御定全唐诗','yuding','','[]','日來月往相催遷，迢迢星歲欲周天。無冬無夏臥霜霰，',40,'御定全唐詩/json/303.json','["日來月往相催遷，迢迢星歲欲周天。無冬無夏臥霜霰，", "幾回鴻雁來又去，腸斷蟾蜍虧複圓。"]'),
('yuding-21','胡笳十八拍：第十二拍','劉商','唐','御定全唐诗','yuding','','[]','破瓶落井空永沈，故鄉望斷無歸心。寧知遠使問姓名，',40,'御定全唐詩/json/303.json','["破瓶落井空永沈，故鄉望斷無歸心。寧知遠使問姓名，", "如今果是夢中事，喜過悲來情不任。"]'),
('yuding-22','胡笳十八拍：第十三拍','劉商','唐','御定全唐诗','yuding','','[]','童稚牽衣雙在側，將來不可留又憶。還鄉惜別兩難分，',40,'御定全唐詩/json/303.json','["童稚牽衣雙在側，將來不可留又憶。還鄉惜別兩難分，", "淚痕滿面對殘陽，終日依依向南北。"]'),
('yuding-23','胡笳十八拍：第十四拍','劉商','唐','御定全唐诗','yuding','','[]','莫以胡兒可羞恥，恩情亦各言其子。手中十指有長短，',40,'御定全唐詩/json/303.json','["莫以胡兒可羞恥，恩情亦各言其子。手中十指有長短，", "南風萬里吹我心，心亦隨風度遼水。"]'),
('yuding-24','胡笳十八拍：第十五拍','劉商','唐','御定全唐诗','yuding','','[]','歎息襟懷無定分，當時怨來歸又恨。不知愁怨情若何，',40,'御定全唐詩/json/303.json','["歎息襟懷無定分，當時怨來歸又恨。不知愁怨情若何，", "不緣生得天屬親，豈向仇讎結恩信。"]'),
('yuding-25','胡笳十八拍：第十六拍','劉商','唐','御定全唐诗','yuding','','[]','去時只覺天蒼蒼，歸日始知胡地長。重陰白日落何處，',40,'御定全唐詩/json/303.json','["去時只覺天蒼蒼，歸日始知胡地長。重陰白日落何處，", "征途未盡馬蹄盡，不見行人邊草黃。"]'),
('yuding-26','胡笳十八拍：第十七拍','劉商','唐','御定全唐诗','yuding','','[]','行盡胡天千萬里，唯見黃沙白雲起。馬饑跑雪銜草根，',40,'御定全唐詩/json/303.json','["行盡胡天千萬里，唯見黃沙白雲起。馬饑跑雪銜草根，", "努力前程是帝鄉，生前免向胡中死。"]'),
('yuding-27','胡笳十八拍：第十八拍','劉商','唐','御定全唐诗','yuding','','[]','歸來故鄉見親族，田園半蕪春草綠。明燭重燃煨燼灰，',40,'御定全唐詩/json/303.json','["歸來故鄉見親族，田園半蕪春草綠。明燭重燃煨燼灰，", "出入關山十二年，哀情盡在胡笳曲。"]'),
('yuding-28','雜言同豆盧郎中郭南七裏橋哀悼姚倉曹','劉商','唐','御定全唐诗','yuding','','[]','橋邊足離別，終日為悲辛。登橋因歎逝，卻羨別離人。',68,'御定全唐詩/json/303.json','["橋邊足離別，終日為悲辛。登橋因歎逝，卻羨別離人。", "橋下東流水，芳樹櫻桃蕊。流水與潮回，花落明年開。", "可憐三語掾，長作九泉灰。宿昔歡遊在何處，"]'),
('yuding-29','春日臥病','劉商','唐','御定全唐诗','yuding','','[]','楚客經年病，孤舟人事稀。晚晴江柳變，春暮塞鴻歸。',48,'御定全唐詩/json/303.json','["楚客經年病，孤舟人事稀。晚晴江柳變，春暮塞鴻歸。", "今日方知命，前身自覺非。不能憂歲計，無限故山薇。"]'),
('yuding-30','題禪居廢寺','劉商','唐','御定全唐诗','yuding','','[]','凋殘精舍在，連步訪緇衣。古殿門空掩，楊花雪亂飛。',48,'御定全唐詩/json/303.json','["凋殘精舍在，連步訪緇衣。古殿門空掩，楊花雪亂飛。", "鶴巢松影薄，僧少磬聲稀。青眼能留客，疏鐘逼夜歸。"]'),
('yuding-31','題山寺','劉商','唐','御定全唐诗','yuding','','[]','扁舟水淼淼，曲岸複長塘。古寺春山上，登樓憶故鄉。',48,'御定全唐詩/json/303.json','["扁舟水淼淼，曲岸複長塘。古寺春山上，登樓憶故鄉。", "雲煙橫極浦，花木擁回廊。更有思歸意，晴明陟上方。"]'),
('yuding-32','題楊侍郎新亭','劉商','唐','御定全唐诗','yuding','','[]','毗陵過柱史，簡易在茅茨。芳草如花種，修篁帶筍移。',48,'御定全唐詩/json/303.json','["毗陵過柱史，簡易在茅茨。芳草如花種，修篁帶筍移。", "徑幽人未賞，簷靜燕初窺。野客憐霜壁，青松畫一枝。"]'),
('yuding-33','同徐城季明府遊重光寺題晃師壁','劉商','唐','御定全唐诗','yuding','','[]','野寺僧房遠，陶潛引客來。鳥喧殘果落，蘭敗幾花開。',48,'御定全唐詩/json/303.json','["野寺僧房遠，陶潛引客來。鳥喧殘果落，蘭敗幾花開。", "真性知無住，微言欲望回。竹風清磬晚，歸策步蒼苔。"]'),
('yuding-34','送林袞侍禦東陽秩滿赴上都','劉商','唐','御定全唐诗','yuding','','[]','幾年烏府內，何處逐鳧歸。關吏迷驄馬，銅章累繡衣。',48,'御定全唐詩/json/303.json','["幾年烏府內，何處逐鳧歸。關吏迷驄馬，銅章累繡衣。", "野亭山草綠，客路柳花飛。況複長安遠，音書從此稀。"]'),
('yuding-35','送人之江東','劉商','唐','御定全唐诗','yuding','','[]','含香仍佩玉，宜入鏡中行。盡室隨乘興，扁舟不計程。',48,'御定全唐詩/json/303.json','["含香仍佩玉，宜入鏡中行。盡室隨乘興，扁舟不計程。", "渡江霖雨霽，對月夜潮生。莫慮當炎暑，稽山水木清。"]'),
('yuding-36','送李元規昆季赴舉','劉商','唐','御定全唐诗','yuding','','[]','見誦甘泉賦，心期折桂歸。鳳雛皆五色，鴻漸又雙飛。',48,'御定全唐詩/json/303.json','["見誦甘泉賦，心期折桂歸。鳳雛皆五色，鴻漸又雙飛。", "別思看衰柳，秋風動客衣。明朝問禮處，暫覺雁行稀。"]'),
('yuding-37','送楊閑侍禦拜命赴上都','劉商','唐','御定全唐诗','yuding','','[]','賀客移星使，絲綸出紫微。手中霜作簡，身上繡為衣。',48,'御定全唐詩/json/303.json','["賀客移星使，絲綸出紫微。手中霜作簡，身上繡為衣。", "驄馬朝天疾，台烏向日飛。親朋皆避路，不是送人稀。"]'),
('yuding-38','賦得月下聞蛩送別','劉商','唐','御定全唐诗','yuding','','[]','物候改秋節，炎涼此夕分。暗蟲聲遍草，明月夜無雲。',48,'御定全唐詩/json/303.json','["物候改秋節，炎涼此夕分。暗蟲聲遍草，明月夜無雲。", "清迥簷外見，淒其籬下聞。感時兼惜別，羈思自紛紛。"]'),
('yuding-39','重陽日寄上饒李明府','劉商','唐','御定全唐诗','yuding','','[]','重陽秋雁未銜蘆，始覺他鄉節候殊。旅館但知聞蟋蟀，',40,'御定全唐詩/json/303.json','["重陽秋雁未銜蘆，始覺他鄉節候殊。旅館但知聞蟋蟀，", "來歲公田多種黍，莫教黃菊笑楊朱。"]'),
('yuding-40','同諸子哭張元易','劉商','唐','御定全唐诗','yuding','','[]','盛德高名總是空，神明福善大朦朧。遊魂永永無歸日，',40,'御定全唐詩/json/303.json','["盛德高名總是空，神明福善大朦朧。遊魂永永無歸日，", "伯道共悲無後嗣，孀妻老母斷根蓬。"]'),
('yuding-41','合肥至日愁中寄鄭明府','劉商','唐','御定全唐诗','yuding','','[]','失計為卑吏，三年滯楚鄉。不能隨世俗，應是昧行藏。',120,'御定全唐詩/json/303.json','["失計為卑吏，三年滯楚鄉。不能隨世俗，應是昧行藏。", "白璧空無玷，黃沙只自傷。暮天鄉思亂，曉鏡鬢毛蒼。", "灰管移新律，窮陰變一陽。歲時人共換，幽憤日先長。", "拙宦慚知己，無媒悔自強。迍邅羞薄命，恩惠費餘光。", "眾口誠難稱，長川卻易防。魚竿今尚在，行此掉滄浪。"]'),
('yuding-42','送廬州賈使君拜命','劉商','唐','御定全唐诗','yuding','','[]','考績朝稱貴，時清武用文。二天移外府，三命佐元勳。',96,'御定全唐詩/json/303.json','["考績朝稱貴，時清武用文。二天移外府，三命佐元勳。", "佩玉兼高位，摐金閱上軍。威容冠是鐵，圖畫閣名芸。", "人詠甘棠茂，童謠竹馬群。懸旌風肅肅，臥轍淚紛紛。", "特達恩難報，升沈路易分。侯嬴不得從，心逐信陵君。"]'),
('yuding-0','怨婦','劉商','唐','御定全唐诗','yuding','','[]','淨掃黃金階，飛霜皎如雪。下簾彈箜篌，不忍見秋月。',24,'御定全唐詩/json/304.json','["淨掃黃金階，飛霜皎如雪。下簾彈箜篌，不忍見秋月。"]'),
('yuding-1','綠珠怨','劉商','唐','御定全唐诗','yuding','','[]','從來上臺榭，不敢倚闌幹。零落知成血，高樓直下看。',24,'御定全唐詩/json/304.json','["從來上臺榭，不敢倚闌幹。零落知成血，高樓直下看。"]'),
('yuding-2','古意','劉商','唐','御定全唐诗','yuding','','[]','達曉寢衣冷，開帷霜露凝。風吹昨夜淚，一片枕前冰。',24,'御定全唐詩/json/304.json','["達曉寢衣冷，開帷霜露凝。風吹昨夜淚，一片枕前冰。"]'),
('yuding-3','哭蕭掄','劉商','唐','御定全唐诗','yuding','','[]','何處哭故人，青門水如箭。當時水頭別，從此不相見。',24,'御定全唐詩/json/304.json','["何處哭故人，青門水如箭。當時水頭別，從此不相見。"]'),
('yuding-4','送從弟赴上都','劉商','唐','御定全唐诗','yuding','','[]','車騎秦城遠，囊裝楚客貧。月明思遠道，詩罷訴何人。',24,'御定全唐詩/json/304.json','["車騎秦城遠，囊裝楚客貧。月明思遠道，詩罷訴何人。"]'),
('yuding-5','登相國寺閣','劉商','唐','御定全唐诗','yuding','','[]','晴日登臨好，春風各望家。垂楊夾城路，客思逐楊花。',24,'御定全唐詩/json/304.json','["晴日登臨好，春風各望家。垂楊夾城路，客思逐楊花。"]'),
('yuding-6','酬浚上人采藥見寄','劉商','唐','御定全唐诗','yuding','','[]','玉英期共采，雲嶺獨先過。應得靈芝也，詩情一倍多。',24,'御定全唐詩/json/304.json','["玉英期共采，雲嶺獨先過。應得靈芝也，詩情一倍多。"]'),
('yuding-7','曲水寺枳實','劉商','唐','御定全唐诗','yuding','','[]','枳實繞僧房，攀枝置藥囊。洞庭山上橘，霜落也應黃。',24,'御定全唐詩/json/304.json','["枳實繞僧房，攀枝置藥囊。洞庭山上橘，霜落也應黃。"]'),
('yuding-8','酬問師','劉商','唐','御定全唐诗','yuding','','[]','虛空無處所，仿佛似琉璃。詩境何人到，禪心又過詩。',24,'御定全唐詩/json/304.json','["虛空無處所，仿佛似琉璃。詩境何人到，禪心又過詩。"]'),
('yuding-9','殷秀才求詩','劉商','唐','御定全唐诗','yuding','','[]','傾蓋見芳姿，晴天瓊樹枝。連城猶隱石，唯有卞和知。',24,'御定全唐詩/json/304.json','["傾蓋見芳姿，晴天瓊樹枝。連城猶隱石，唯有卞和知。"]'),
('yuding-10','行營即事','劉商','唐','御定全唐诗','yuding','','[]','萬姓厭干戈，三邊尚未和。將軍誇寶劍，功在殺人多。',24,'御定全唐詩/json/304.json','["萬姓厭干戈，三邊尚未和。將軍誇寶劍，功在殺人多。"]'),
('yuding-11','送劉寰北歸','劉商','唐','御定全唐诗','yuding','','[]','南巢登望縣城孤，半是青山半是湖。',32,'御定全唐詩/json/304.json','["南巢登望縣城孤，半是青山半是湖。", "知爾素多山水興，此回歸去更來無。"]'),
('yuding-12','送王閈歸蘇州','劉商','唐','御定全唐诗','yuding','','[]','深山窮穀沒人來，邂逅相逢眼漸開。',32,'御定全唐詩/json/304.json','["深山窮穀沒人來，邂逅相逢眼漸開。", "雲鶴洞宮君未到，夕陽帆影幾時回。"]'),
('yuding-13','送人往虔州','劉商','唐','御定全唐诗','yuding','','[]','莫歎乘軺道路賒，高樓日日望還家。',32,'御定全唐詩/json/304.json','["莫歎乘軺道路賒，高樓日日望還家。", "人到南康皆下淚，唯君笑向此中花。"]'),
('yuding-14','送僧往湖南','劉商','唐','御定全唐诗','yuding','','[]','閑出東林日影斜，稻苗深淺映袈裟。',32,'御定全唐詩/json/304.json','["閑出東林日影斜，稻苗深淺映袈裟。", "船到南湖風浪靜，可憐秋水照蓮花。"]'),
('yuding-15','送元使君自楚移越','劉商','唐','御定全唐诗','yuding','','[]','露冕行春向若耶，野人懷惠欲移家。',32,'御定全唐詩/json/304.json','["露冕行春向若耶，野人懷惠欲移家。", "東風二月淮陰郡，唯見棠梨一樹花。"]'),
('yuding-16','移居深山謝別親故','劉商','唐','御定全唐诗','yuding','','[]','不食黃精不采薇，葛苗為帶草為衣。',32,'御定全唐詩/json/304.json','["不食黃精不采薇，葛苗為帶草為衣。", "孤雲更入深山去，人絕音書雁自飛。"]'),
('yuding-17','送王永二首','劉商','唐','御定全唐诗','yuding','','[]','君去春山誰共遊，鳥啼花落水空流。',64,'御定全唐詩/json/304.json','["君去春山誰共遊，鳥啼花落水空流。", "如今送別臨溪水，他日相思來水頭。", "綿衣似熱夾衣寒，時景雖和春已闌。", "誠知暫別那惆悵，明日藤花獨自看。"]'),
('yuding-18','送別','劉商','唐','御定全唐诗','yuding','','[]','灞岸青門有弊廬，昨來聞道半丘墟。',32,'御定全唐詩/json/304.json','["灞岸青門有弊廬，昨來聞道半丘墟。", "陌頭空送長安使，舊裏無人可寄書。"]'),
('yuding-19','送王貞','劉商','唐','御定全唐诗','yuding','','[]','清陽玉潤複多才，邂逅佳期過早梅。',32,'御定全唐詩/json/304.json','["清陽玉潤複多才，邂逅佳期過早梅。", "槿花亦可浮杯上，莫待東籬黃菊開。"]'),
('yuding-20','送薛六暫游揚州','劉商','唐','御定全唐诗','yuding','','[]','志在乘軒鳴玉珂，心期未快隱青蘿。',32,'御定全唐詩/json/304.json','["志在乘軒鳴玉珂，心期未快隱青蘿。", "廣陵行路風塵合，城郭新秋砧杵多。"]'),
('yuding-21','送楊行元赴舉','劉商','唐','御定全唐诗','yuding','','[]','晚渡邗溝惜別離，漸看烽火馬行遲。',32,'御定全唐詩/json/304.json','["晚渡邗溝惜別離，漸看烽火馬行遲。", "千鈞何處穿楊葉，二月長安折桂枝。"]'),
('yuding-22','行營送人','劉商','唐','御定全唐诗','yuding','','[]','鞞鼓喧喧對古城，獨尋歸鳥馬蹄輕。',32,'御定全唐詩/json/304.json','["鞞鼓喧喧對古城，獨尋歸鳥馬蹄輕。", "回來看覓鶯飛處，即是將軍細柳營。"]'),
('yuding-23','滑州送人先歸','劉商','唐','御定全唐诗','yuding','','[]','河水冰消雁北飛，寒衣未足又春衣。',32,'御定全唐詩/json/304.json','["河水冰消雁北飛，寒衣未足又春衣。", "自憐漂蕩經年客，送別千回獨未歸。"]'),
('yuding-24','送浚上人','劉商','唐','御定全唐诗','yuding','','[]','木落前山霜露多，手持寒錫遠頭陀。',32,'御定全唐詩/json/304.json','["木落前山霜露多，手持寒錫遠頭陀。", "眼看庭樹梅花發，不見詩人獨詠歌。"]'),
('yuding-25','高郵送弟遇北游','劉商','唐','御定全唐诗','yuding','','[]','門臨楚國舟船路，易見行人易別離。',32,'御定全唐詩/json/304.json','["門臨楚國舟船路，易見行人易別離。", "今日送君心最恨，孤帆水下又風吹。"]'),
('yuding-26','送豆盧郎赴海陵','劉商','唐','御定全唐诗','yuding','','[]','煙波極目已沾襟，路出東塘水更深。',32,'御定全唐詩/json/304.json','["煙波極目已沾襟，路出東塘水更深。", "看取海頭秋草色，一如江上別離心。"]'),
('yuding-27','送女子','劉商','唐','御定全唐诗','yuding','','[]','青娥宛宛聚為裳，烏鵲橋成別恨長。',32,'御定全唐詩/json/304.json','["青娥宛宛聚為裳，烏鵲橋成別恨長。", "惆悵梧桐非舊影，不悲鴻雁暫隨陽。"]'),
('yuding-28','酬道芬寄畫松','劉商','唐','御定全唐诗','yuding','','[]','聞道鉛華學沈寧，寒枝淅瀝葉青青。',32,'御定全唐詩/json/304.json','["聞道鉛華學沈寧，寒枝淅瀝葉青青。", "一株將比囊中樹，若個年多有茯苓。"]'),
('yuding-29','山翁持酒相訪以畫松酬之','劉商','唐','御定全唐诗','yuding','','[]','白社風霜驚暮年，銅瓶桑落慰秋天。',32,'御定全唐詩/json/304.json','["白社風霜驚暮年，銅瓶桑落慰秋天。", "憐君意厚留新畫，不著松枝當酒錢。"]'),
('yuding-30','題潘師房','劉商','唐','御定全唐诗','yuding','','[]','渡水傍山尋石壁，白雲飛處洞門開。',32,'御定全唐詩/json/304.json','["渡水傍山尋石壁，白雲飛處洞門開。", "仙人來往行無跡，石徑春風長綠苔。"]'),
('yuding-31','謝自然卻還舊居','劉商','唐','御定全唐诗','yuding','','[]','仙侶招邀自有期，九天升降五雲隨。',32,'御定全唐詩/json/304.json','["仙侶招邀自有期，九天升降五雲隨。", "不知辭罷虛皇日，更向人間住幾時。"]'),
('yuding-32','寄李俌','劉商','唐','御定全唐诗','yuding','','[]','掛卻衣冠披薜荔，世人應是笑狂愚。',32,'御定全唐詩/json/304.json','["掛卻衣冠披薜荔，世人應是笑狂愚。", "年來漸覺髭須黑，欲寄松花君用無。"]'),
('yuding-33','贈頭陀師','劉商','唐','御定全唐诗','yuding','','[]','少壯從戎馬上飛，雪山童子未緇衣。',32,'御定全唐詩/json/304.json','["少壯從戎馬上飛，雪山童子未緇衣。", "秋山年長頭陀處，說我軍前射虎歸。"]'),
('yuding-34','贈嚴四草屨','劉商','唐','御定全唐诗','yuding','','[]','輕微菅蒯將何用，容足偷安事頗同。',32,'御定全唐詩/json/304.json','["輕微菅蒯將何用，容足偷安事頗同。", "日入信陵賓館靜，贈君閒步月明中。"]'),
('yuding-35','題劉偃莊','劉商','唐','御定全唐诗','yuding','','[]','何事退耕滄海畔，閑看富貴白雲飛。',32,'御定全唐詩/json/304.json','["何事退耕滄海畔，閑看富貴白雲飛。", "門前種稻三回熟，縣裏官人四考歸。"]'),
('yuding-36','題黃陂夫人祠','劉商','唐','御定全唐诗','yuding','','[]','蒼山雲雨逐明神，唯有香名萬歲春。',32,'御定全唐詩/json/304.json','["蒼山雲雨逐明神，唯有香名萬歲春。", "東風三月黃陂水，只見桃花不見人。"]'),
('yuding-37','題道濟上人房','劉商','唐','御定全唐诗','yuding','','[]','何處營求出世間，心中無事即身閑。',32,'御定全唐詩/json/304.json','["何處營求出世間，心中無事即身閑。", "門外水流風葉落，唯將定性對前山。"]'),
('yuding-38','梨樹陰','劉商','唐','御定全唐诗','yuding','','[]','福庭人靜少攀援，雨露偏滋影易繁。',32,'御定全唐詩/json/304.json','["福庭人靜少攀援，雨露偏滋影易繁。", "磊落紫香香亞樹，清陰滿地晝當軒。"]'),
('yuding-39','秋蟬聲','劉商','唐','御定全唐诗','yuding','','[]','蕭條旅舍客心驚，斷續僧房靜又清。',32,'御定全唐詩/json/304.json','["蕭條旅舍客心驚，斷續僧房靜又清。", "借問蟬聲何所為，人家古寺兩般聲。"]'),
('yuding-40','歸山留別子侄二首','劉商','唐','御定全唐诗','yuding','','[]','車馬驅馳人在世，東西南北鶴隨雲。',64,'御定全唐詩/json/304.json','["車馬驅馳人在世，東西南北鶴隨雲。", "莫言貧病無留別，百代簪纓將付君。", "不逐浮雲不羨魚，杏花茅屋向陽居。", "鶴鳴華表應傳語，雁度霜天懶寄書。"]'),
('yuding-41','與湛上人院畫松','劉商','唐','御定全唐诗','yuding','','[]','水墨乍成岩下樹，摧殘半隱洞中雲。',32,'御定全唐詩/json/304.json','["水墨乍成岩下樹，摧殘半隱洞中雲。", "猷公曾住天臺寺，陰雨猿聲何處聞。"]'),
('yuding-42','白沙宿竇常宅觀妓','劉商','唐','御定全唐诗','yuding','','[]','揚子澄江映晚霞，柳條垂岸一千家。',32,'御定全唐詩/json/304.json','["揚子澄江映晚霞，柳條垂岸一千家。", "主人留客江邊宿，十月繁霜見杏花。"]'),
('yuding-43','上巳日兩縣寮友會集時主郵不遂馳赴輒題以寄方寸','劉商','唐','御定全唐诗','yuding','','[]','踏青看竹共佳期，春水晴山祓禊詞。',32,'御定全唐詩/json/304.json','["踏青看竹共佳期，春水晴山祓禊詞。", "獨坐郵亭心欲醉，櫻桃落盡暮愁時。"]'),
('yuding-44','懷張璪','劉商','唐','御定全唐诗','yuding','','[]','苔石蒼蒼臨澗水，陰風嫋嫋動松枝。',32,'御定全唐詩/json/304.json','["苔石蒼蒼臨澗水，陰風嫋嫋動松枝。", "世間唯有張通會，流向衡陽那得知。"]'),
('yuding-45','與於中丞','劉商','唐','御定全唐诗','yuding','','[]','萬頃荒林不敢看，買山容足擬求安。',32,'御定全唐詩/json/304.json','["萬頃荒林不敢看，買山容足擬求安。", "田園失計全蕪沒，何處春風種蕙蘭。"]'),
('yuding-46','袁十五遠訪山門','劉商','唐','御定全唐诗','yuding','','[]','僻居謀道不謀身，避病桃源不避秦。',32,'御定全唐詩/json/304.json','["僻居謀道不謀身，避病桃源不避秦。", "遠入青山何所見，寒花滿徑白頭人。"]'),
('yuding-47','行營病中','劉商','唐','御定全唐诗','yuding','','[]','心許征南破虜歸，可言羸病臥戎衣。',32,'御定全唐詩/json/304.json','["心許征南破虜歸，可言羸病臥戎衣。", "遲遲不見憐弓箭，惆悵秋鴻敢近飛。"]'),
('yuding-48','合溪水漲寄敬山人','劉商','唐','御定全唐诗','yuding','','[]','共愛碧溪臨水住，相思來往踐莓苔。',32,'御定全唐詩/json/304.json','["共愛碧溪臨水住，相思來往踐莓苔。", "而今卻欲嫌溪水，雨漲春流隔往來。"]'),
('yuding-49','不羨花','劉商','唐','御定全唐诗','yuding','','[]','惆悵朝陽午又斜，剩栽桃李學仙家。',32,'御定全唐詩/json/304.json','["惆悵朝陽午又斜，剩栽桃李學仙家。", "花開花落人如舊，誰道容顏不及花。"]'),
('yuding-50','醉後','劉商','唐','御定全唐诗','yuding','','[]','春草秋風老此身，一瓢長醉任家貧。',32,'御定全唐詩/json/304.json','["春草秋風老此身，一瓢長醉任家貧。", "醒來還愛浮萍草，漂寄官河不屬人。"]'),
('yuding-51','題水洞二首','劉商','唐','御定全唐诗','yuding','','[]','桃花流出武陵洞，夢想仙家雲樹春。',64,'御定全唐詩/json/304.json','["桃花流出武陵洞，夢想仙家雲樹春。", "今看水入洞中去，卻是桃花源裏人。", "長看岩穴泉流出，忽聽懸泉入洞聲。", "莫摘山花拋水上，花浮出洞世人驚。"]'),
('yuding-52','代人村中悼亡二首','劉商','唐','御定全唐诗','yuding','','[]','花落茅簷轉寂寥，魂隨暮雨此中銷。',64,'御定全唐詩/json/304.json','["花落茅簷轉寂寥，魂隨暮雨此中銷。", "邇來庭柳無人折，長得垂枝一萬條。", "虛室無人乳燕飛，蒼苔滿地履痕稀。", "庭前唯有薔薇在，花似殘妝葉似衣。"]'),
('yuding-53','觀獵三首','劉商','唐','御定全唐诗','yuding','','[]','夢非熊虎數年間，驅盡豺狼宇宙閑。',96,'御定全唐詩/json/304.json','["夢非熊虎數年間，驅盡豺狼宇宙閑。", "傳道單于聞校獵，相期不敢過陰山。", "日隱寒山獵未歸，鳴弦落羽雪霏霏。", "梁園射盡南飛雁，淮楚人驚陽鳥啼。", "松月東軒許獨遊，深恩未報復淹留。", "梁園日暮從公獵，每過青山不舉頭。"]'),
('yuding-54','畫石','劉商','唐','御定全唐诗','yuding','','[]','蒼蘚千年粉繪傳，堅貞一片色猶全。',32,'御定全唐詩/json/304.json','["蒼蘚千年粉繪傳，堅貞一片色猶全。", "那知忽遇非常用，不把分銖補上天。"]'),
('yuding-55','詠雙開蓮花','劉商','唐','御定全唐诗','yuding','','[]','菡萏新花曉並開，濃妝美笑面相隈。',32,'御定全唐詩/json/304.json','["菡萏新花曉並開，濃妝美笑面相隈。", "西方采畫迦陵鳥，早晚雙飛池上來。"]'),
('yuding-56','夜聞鄰管','劉商','唐','御定全唐诗','yuding','','[]','何事霜天月滿空，鸝雛百囀向春風。',32,'御定全唐詩/json/304.json','["何事霜天月滿空，鸝雛百囀向春風。", "鄰家思婦更長短，楊柳如絲在管中。"]'),
('yuding-57','山中寄元二侍禦二首','劉商','唐','御定全唐诗','yuding','','[]','心期汗漫臥雲扃，家計漂零水上萍。',64,'御定全唐詩/json/304.json','["心期汗漫臥雲扃，家計漂零水上萍。", "桃李向秋凋落盡，一枝松色獨青青。", "拖紫鏘金濟世才，知君倚玉望三台。", "深山窮谷無人到，唯有狂愚獨自來。"]'),
('yuding-58','上崔十五老丈','劉商','唐','御定全唐诗','yuding','','[]','天漢乘槎可問津，寂寥深景到無因。',32,'御定全唐詩/json/304.json','["天漢乘槎可問津，寂寥深景到無因。", "看花獨往尋詩客，不為經時謁丈人。"]'),
('yuding-59','袁德師求畫松','劉商','唐','御定全唐诗','yuding','','[]','柏偃松俯勢自分，森梢古意出浮雲。',32,'御定全唐詩/json/304.json','["柏偃松俯勢自分，森梢古意出浮雲。", "如今眼暗畫不得，舊有三株持贈君。"]'),
('yuding-60','早夏月夜問王開','劉商','唐','御定全唐诗','yuding','','[]','清風首夏夜猶寒，嫩筍侵階竹數竿。',32,'御定全唐詩/json/304.json','["清風首夏夜猶寒，嫩筍侵階竹數竿。", "君向蘇台長見月，不知何事此中看。"]'),
('yuding-61','裴十六廳即事','劉商','唐','御定全唐诗','yuding','','[]','主人能政訟庭閑，帆影雲峰戶牖間。',32,'御定全唐詩/json/304.json','["主人能政訟庭閑，帆影雲峰戶牖間。", "每到夕陽嵐翠近，只言籬障倚前山。"]'),
('yuding-62','春日行營即事','劉商','唐','御定全唐诗','yuding','','[]','風引雙旌馬首齊，曹南戰勝日平西。',32,'御定全唐詩/json/304.json','["風引雙旌馬首齊，曹南戰勝日平西。", "為儒不解從戎事，花落春深聞鼓鼙。"]'),
('yuding-63','畫樹後呈浚師','劉商','唐','御定全唐诗','yuding','','[]','翔鳳邊風十月寒，蒼山古木更摧殘。',32,'御定全唐詩/json/304.json','["翔鳳邊風十月寒，蒼山古木更摧殘。", "為君壁上畫松柏，勁雪嚴霜君試看。"]'),
('yuding-64','吊從甥','劉商','唐','御定全唐诗','yuding','','[]','日晚河邊訪煢獨，衰柳寒蕪繞茅屋。',32,'御定全唐詩/json/304.json','["日晚河邊訪煢獨，衰柳寒蕪繞茅屋。", "兒童驚走報人來，孀婦開門一聲哭。"]'),
('yuding-65','句','劉商','唐','御定全唐诗','yuding','','[]','郵筒不解獻茱萸。。',26,'御定全唐詩/json/304.json','["郵筒不解獻茱萸。。", "趙侯首帶鹿耳巾，規模出自陶弘景。", "。"]'),
('yuding-0','登城樓作','陳翊','唐','御定全唐诗','yuding','','[]','井邑白雲間，嚴城遠帶山。沙墟陰欲暮，郊色淡方閑。',48,'御定全唐詩/json/305.json','["井邑白雲間，嚴城遠帶山。沙墟陰欲暮，郊色淡方閑。", "孤徑回榕岸，層巒破枳關。寥寥分遠望，暫得一開顏。"]'),
('yuding-1','宴柏台','陳翊','唐','御定全唐诗','yuding','','[]','華台陳桂席，密榭宴清真。柏葉猶霜氣，桃花似漢津。',48,'御定全唐詩/json/305.json','["華台陳桂席，密榭宴清真。柏葉猶霜氣，桃花似漢津。", "青尊照深夕，綠綺映芳春。欲憶相逢後，無言嶺海人。"]'),
('yuding-2','過馬侍中亭','陳翊','唐','御定全唐诗','yuding','','[]','草色照雙扉，軒車到客稀。苔衣香屐跡，花綬少塵飛。',48,'御定全唐詩/json/305.json','["草色照雙扉，軒車到客稀。苔衣香屐跡，花綬少塵飛。", "薄望憐池淨，開畦愛雨肥。相過忘日昃，坐待白雲歸。"]'),
('yuding-3','寄邵校書楚萇','陳翊','唐','御定全唐诗','yuding','','[]','愛酒時稱僻，高情自不凡。向人方白眼，違俗有青岩。',48,'御定全唐詩/json/305.json','["愛酒時稱僻，高情自不凡。向人方白眼，違俗有青岩。", "雲際開三徑，煙中掛一帆。相期同歲晚，閑興與松杉。"]'),
('yuding-4','龍池春草','陳翊','唐','御定全唐诗','yuding','','[]','青春光鳳苑，細草遍龍池。曲渚交蘋葉，回塘惹柳枝。',72,'御定全唐詩/json/305.json','["青春光鳳苑，細草遍龍池。曲渚交蘋葉，回塘惹柳枝。", "因風初苒苒，覆岸欲離離。色帶金堤靜，陰連玉樹移。", "日光浮靃靡，波影動參差。豈比生幽遠，芳馨眾不知。"]'),
('yuding-5','郊行示友人','陳翊','唐','御定全唐诗','yuding','','[]','水開長鏡引諸巒，春洞花深落翠寒。',32,'御定全唐詩/json/305.json','["水開長鏡引諸巒，春洞花深落翠寒。", "醉向絲蘿驚自醒，與君清耳聽松湍。"]'),
('yuding-6','送別蕭二','陳翊','唐','御定全唐诗','yuding','','[]','橘花香覆白蘋洲，江引輕帆入遠遊。',32,'御定全唐詩/json/305.json','["橘花香覆白蘋洲，江引輕帆入遠遊。", "千里雲天風雨夕，憶君不敢再登樓。"]'),
('yuding-7','游仙','劉複','唐','御定全唐诗','yuding','','[]','稅駕倚扶桑，逍遙望九州。二老佐軒轅，移戈戮蚩尤。',120,'御定全唐詩/json/305.json','["稅駕倚扶桑，逍遙望九州。二老佐軒轅，移戈戮蚩尤。", "功成棄之去，乘龍上天遊。天上見玉皇，壽與天地休。", "俯視昆侖宮，五城十二樓。王母何窈眇，玉質清且柔。", "揚袂折瓊枝，寄我天東頭。相思千萬歲，大運浩悠悠。", "安用知吾道，日月不能周。寄音青鳥翼，謝爾碧海流。"]'),
('yuding-8','寺居清晨','劉複','唐','御定全唐诗','yuding','','[]','高枕對曉月，衣巾清且涼。露華朝未晞，滴瀝含虛光。',72,'御定全唐詩/json/305.json','["高枕對曉月，衣巾清且涼。露華朝未晞，滴瀝含虛光。", "隔竹聞汲井，開扉見焚香。幽心感衰病，結念依法王。", "青冥早雲飛，杳靄空鳥翔。此情皆有釋，悠然知所忘。"]'),
('yuding-9','出東城','劉複','唐','御定全唐诗','yuding','','[]','步出東城門，獨行已彷徨。伊洛泛清流，密林含朝陽。',96,'御定全唐詩/json/305.json','["步出東城門，獨行已彷徨。伊洛泛清流，密林含朝陽。", "芳景雖可矚，憂懷在中腸。人生幾何時，苒苒隨流光。", "願得心所親，尊酒坐高堂。一為浮沉隔，會合殊未央。", "雙戲水中鳧，和鳴自翱翔。我無此羽翼，安可以比方。"]'),
('yuding-10','經禁城','劉複','唐','御定全唐诗','yuding','','[]','日沒路且長，遊子欲涕零。荒城無人路，秋草飛寒螢。',108,'御定全唐詩/json/305.json','["日沒路且長，遊子欲涕零。荒城無人路，秋草飛寒螢。", "東南古丘墟，莽蒼馳郊坰。黃雲晦斷岸，枯井臨崩亭。", "昔人竟何之，窮泉獨冥冥。蒼苔沒碑版，朽骨無精靈。", "俯仰寄世間，忽如流波萍。金石非汝壽，浮生等臊腥。", "不如學神仙，服食求丹經。"]'),
('yuding-11','出三城留別幕中三判官','劉複','唐','御定全唐诗','yuding','','[]','翔禽托高柯，倦客念主人。恩義有所知，四海同一身。',120,'御定全唐詩/json/305.json','["翔禽托高柯，倦客念主人。恩義有所知，四海同一身。", "況皆曠大姿，翰音見良辰。陳規佐武略，高視據要津。", "常願投素誠，今果得所申。金罍列四座，廣廈無氛塵。", "留連徂暑中，觀望歷數旬。河山險以固，士卒勇且仁。", "飭裝去未歸，相追越城闉。愧無青玉案，緘佩永不泯。"]'),
('yuding-12','送劉秀才南歸','劉複','唐','御定全唐诗','yuding','','[]','鳥啼楊柳垂，此別千萬里。古路入商山，春風生灞水。',48,'御定全唐詩/json/305.json','["鳥啼楊柳垂，此別千萬里。古路入商山，春風生灞水。", "停車落日在，罷酒離人起。蓬戶寄龍沙，送歸情詎已。"]'),
('yuding-13','送王倫','劉複','唐','御定全唐诗','yuding','','[]','春江日未曛，楚客酣送君。翩翩孤黃鶴，萬里滄洲雲。',72,'御定全唐詩/json/305.json','["春江日未曛，楚客酣送君。翩翩孤黃鶴，萬里滄洲雲。", "四方各有志，豈得常顧群。山連巴湘遠，水與荊吳分。", "清光日修阻，尺素安可論。相思寄夢寐，瑤草空氛氳。"]'),
('yuding-14','長相思','劉複','唐','御定全唐诗','yuding','','[]','長相思，在桂林，蒼梧山遠瀟湘深。秋堂零淚倚金瑟，',48,'御定全唐詩/json/305.json','["長相思，在桂林，蒼梧山遠瀟湘深。秋堂零淚倚金瑟，", "甯知一水不可渡，況複萬山修且阻。彩絲織綺文雙鴛，"]'),
('yuding-15','長歌行','劉複','唐','御定全唐诗','yuding','','[]','淮南木落秋雲飛，楚宮商歌今正悲。青春白日不與我，',83,'御定全唐詩/json/305.json','["淮南木落秋雲飛，楚宮商歌今正悲。青春白日不與我，", "三山海底無見期，百齡世間莫虛棄。", "君不見金城帝業漢家有，東制諸侯欲長久。", "奸雄竊命風塵昏，函谷重關不能守。龍蛇出沒經兩朝，"]'),
('yuding-16','春遊曲','劉複','唐','御定全唐诗','yuding','','[]','春風戲狹斜，相見莫愁家。細酌蒲桃酒，嬌歌玉樹花。',48,'御定全唐詩/json/305.json','["春風戲狹斜，相見莫愁家。細酌蒲桃酒，嬌歌玉樹花。", "裁衫催白紵，迎客走朱車。不覺重城暮，爭棲柳上鴉。"]'),
('yuding-17','雜曲','劉複','唐','御定全唐诗','yuding','','[]','寶劍飾文犀，當風似切泥。逢君感意氣，貰酒杜陵西。',48,'御定全唐詩/json/305.json','["寶劍飾文犀，當風似切泥。逢君感意氣，貰酒杜陵西。", "趙女顏雖少，宛駒齒正齊。嬌多不肯別，更待夜烏啼。"]'),
('yuding-18','春雨','劉複','唐','御定全唐诗','yuding','','[]','細雨度深閨，鶯愁欲懶啼。如煙飛漠漠，似露濕淒淒。',48,'御定全唐詩/json/305.json','["細雨度深閨，鶯愁欲懶啼。如煙飛漠漠，似露濕淒淒。", "草色行看靡，花枝暮欲低。曉聽鐘鼓動，早送錦障泥。"]'),
('yuding-19','夕次襄邑','劉複','唐','御定全唐诗','yuding','','[]','何處成吾道，經年遠路中。客心猶向北，河水自歸東。',48,'御定全唐詩/json/305.json','["何處成吾道，經年遠路中。客心猶向北，河水自歸東。", "古戍飄殘角，疏林振夕風。輕舟難載月，那與故人同。"]'),
('yuding-20','夏日','劉複','唐','御定全唐诗','yuding','','[]','映日紗窗深且閑，含桃紅日石榴殷。銀瓶綆轉桐花井，',40,'御定全唐詩/json/305.json','["映日紗窗深且閑，含桃紅日石榴殷。銀瓶綆轉桐花井，", "明朝戲去誰相伴，年少相逢狹路間。"]'),
('yuding-21','送黃曄明府岳州湘陰赴任','劉複','唐','御定全唐诗','yuding','','[]','擬占名場第一科，龍門十上困風波。三年護塞從戎遠，',40,'御定全唐詩/json/305.json','["擬占名場第一科，龍門十上困風波。三年護塞從戎遠，", "遙知布惠蘇民後，應向祠堂吊汨羅。"]'),
('yuding-22','禪門寺暮鐘','劉複','唐','御定全唐诗','yuding','','[]','簨簴高懸于闐鐘，黃昏發地殷龍宮。',32,'御定全唐詩/json/305.json','["簨簴高懸于闐鐘，黃昏發地殷龍宮。", "遊人憶到嵩山夜，疊閣連樓滿太空。"]'),
('yuding-23','同張深秀才游華嚴寺','冷朝陽','唐','御定全唐诗','yuding','','[]','同遊雲外寺，渡水入禪關。立掃窗前石，坐看池上山。',48,'御定全唐詩/json/305.json','["同遊雲外寺，渡水入禪關。立掃窗前石，坐看池上山。", "有僧飛錫到，留客話松間。不是緣名利，好來長伴閑。"]'),
('yuding-24','中秋與空上人同宿華嚴寺','冷朝陽','唐','御定全唐诗','yuding','','[]','掃榻相逢宿，論詩舊梵宮。磬聲迎鼓盡，月色過山窮。',48,'御定全唐詩/json/305.json','["掃榻相逢宿，論詩舊梵宮。磬聲迎鼓盡，月色過山窮。", "庭簇安禪草，窗飛帶火蟲。一宵何惜別，回首隔秋風。"]'),
('yuding-25','宿柏岩寺','冷朝陽','唐','御定全唐诗','yuding','','[]','幽寺在岩中，行唯一徑通。客吟孤嶠月，蟬噪數枝風。',48,'御定全唐詩/json/305.json','["幽寺在岩中，行唯一徑通。客吟孤嶠月，蟬噪數枝風。", "秋色生苔砌，泉聲入梵宮。吾師修道處，不與世間同。"]'),
('yuding-26','登靈善寺塔','冷朝陽','唐','御定全唐诗','yuding','','[]','飛閣青霞裏，先秋獨早涼。天花映窗近，月桂拂簷香。',48,'御定全唐詩/json/305.json','["飛閣青霞裏，先秋獨早涼。天花映窗近，月桂拂簷香。", "華嶽三峰小，黃河一帶長。空聞指歸路，煙處有垂楊。"]'),
('yuding-27','瀑布泉','冷朝陽','唐','御定全唐诗','yuding','','[]','潺湲半空裏，霖落石房邊。風激珠光碎，山欹練影偏。',48,'御定全唐詩/json/305.json','["潺湲半空裏，霖落石房邊。風激珠光碎，山欹練影偏。", "急流難起浪，迸沫只如煙。自古惟今日，淒涼一片泉。"]'),
('yuding-28','冬日逢馮法曹話懷','冷朝陽','唐','御定全唐诗','yuding','','[]','分襟二年內，多少事相干。禮樂風全變，塵埃路漸難。',48,'御定全唐詩/json/305.json','["分襟二年內，多少事相干。禮樂風全變，塵埃路漸難。", "秋林新葉落，霜月滿庭寒。雖喜逢知己，他鄉歲又闌。"]'),
('yuding-29','送唐六赴舉','冷朝陽','唐','御定全唐诗','yuding','','[]','秋色生邊思，送君西入關。草衰空大野，葉落露青山。',48,'御定全唐詩/json/305.json','["秋色生邊思，送君西入關。草衰空大野，葉落露青山。", "故國煙霞外，新安道路間。碧霄知己在，香桂月中攀。"]'),
('yuding-30','送遠上人歸京','冷朝陽','唐','御定全唐诗','yuding','','[]','夏臘歲方深，思歸徹曙吟。未離銷雪院，已有過雲心。',48,'御定全唐詩/json/305.json','["夏臘歲方深，思歸徹曙吟。未離銷雪院，已有過雲心。", "寒磬清函谷，孤鐘宿華陰。別京遊舊寺，月色似雙林。"]'),
('yuding-31','別郎上人','冷朝陽','唐','御定全唐诗','yuding','','[]','過雲尋釋子，話別更依依。靜室開來久，遊人到自稀。',48,'御定全唐詩/json/305.json','["過雲尋釋子，話別更依依。靜室開來久，遊人到自稀。", "觸風香氣盡，隔水磬聲微。獨傍孤松立，塵中多是非。"]'),
('yuding-32','立春','冷朝陽','唐','御定全唐诗','yuding','','[]','玉律傳佳節，青陽應此辰。土牛呈歲稔，彩燕表年春。',72,'御定全唐詩/json/305.json','["玉律傳佳節，青陽應此辰。土牛呈歲稔，彩燕表年春。", "臘盡星回次，寒餘月建寅。風光行處好，雲物望中新。", "流水初銷凍，潛魚欲振鱗。梅花將柳色，偏思越鄉人。"]'),
('yuding-33','送紅線','冷朝陽','唐','御定全唐诗','yuding','','[]','采菱歌怨木蘭舟，送客魂銷百尺樓。',32,'御定全唐詩/json/305.json','["采菱歌怨木蘭舟，送客魂銷百尺樓。", "還似洛妃乘霧去，碧天無際水空流。"]'),
('yuding-34','南至日太史登臺書雲物','于尹躬','唐','御定全唐诗','yuding','','[]','至日行時令，登臺約禮文。官稱伯趙氏，色辨五方雲。',72,'御定全唐詩/json/305.json','["至日行時令，登臺約禮文。官稱伯趙氏，色辨五方雲。", "晝漏聽初發，陽光望漸分。司天為歲備，持簡出人群。", "惠愛周微物，生靈荷聖君。長當有嘉瑞，鬱鬱複紛紛。"]'),
('yuding-35','贈別二首','柳郴','唐','御定全唐诗','yuding','','[]','江浦程千里，離尊淚數行。無論吳與楚，俱是客他鄉。',48,'御定全唐詩/json/305.json','["江浦程千里，離尊淚數行。無論吳與楚，俱是客他鄉。", "何處最悲辛，長亭臨古津。往來舟楫路，前後別離人。"]'),
('yuding-36','句','柳郴','唐','御定全唐诗','yuding','','[]','他鄉生白髮，舊國有青山。',13,'御定全唐詩/json/305.json','["他鄉生白髮，舊國有青山。", "。"]'),
('yuding-37','望終南春雪','李子卿','唐','御定全唐诗','yuding','','[]','山勢抱西秦，初年瑞雪頻。色搖鶉野霽，影落鳳城春。',72,'御定全唐詩/json/305.json','["山勢抱西秦，初年瑞雪頻。色搖鶉野霽，影落鳳城春。", "輝耀銀峰逼，晶明玉樹親。尚寒由氣勁，不夜為光新。", "荊岫全疑近，昆丘宛合鄰。餘輝倘可借，回照讀書人。"]'),
('yuding-0','九日登青山','朱灣','唐','御定全唐诗','yuding','','[]','昔人惆悵處，系馬又登臨。舊地煙霞在，多時草木深。',48,'御定全唐詩/json/306.json','["昔人惆悵處，系馬又登臨。舊地煙霞在，多時草木深。", "水將空合色，雲與我無心。想見龍山會，良辰亦似今。"]'),
('yuding-1','秋夜宴王郎中宅賦得露中菊','朱灣','唐','御定全唐诗','yuding','','[]','眾芳春競發，寒菊露偏滋。受氣何曾異，開花獨自遲。',48,'御定全唐詩/json/306.json','["眾芳春競發，寒菊露偏滋。受氣何曾異，開花獨自遲。", "晚成猶待賞，欲采未過時。忍棄東籬下，看隨秋草衰。"]'),
('yuding-2','奉使設宴戲擲籠籌','朱灣','唐','御定全唐诗','yuding','','[]','今日陪樽俎，良籌複在茲。獻酬君有禮，賞罰我無私。',48,'御定全唐詩/json/306.json','["今日陪樽俎，良籌複在茲。獻酬君有禮，賞罰我無私。", "莫怪斜相向，還將正自持。一朝權入手，看取令行時。"]'),
('yuding-3','詠雙陸骰子','朱灣','唐','御定全唐诗','yuding','','[]','采采應緣白，鑽心不為名。掌中猶可重，手下莫言輕。',48,'御定全唐詩/json/306.json','["采采應緣白，鑽心不為名。掌中猶可重，手下莫言輕。", "有對唯求敵，無私直任爭。君看一擲後，當取擅場聲。"]'),
('yuding-4','詠壁上酒瓢呈蕭明府','朱灣','唐','御定全唐诗','yuding','','[]','不是難提挈，行藏固有期。安身未得所，開口欲從誰。',48,'御定全唐詩/json/306.json','["不是難提挈，行藏固有期。安身未得所，開口欲從誰。", "應物心無倦，當壚柄會持。莫將成廢器，還有對樽時。"]'),
('yuding-5','詠玉','朱灣','唐','御定全唐诗','yuding','','[]','歌玉屢招疑，終朝省複思。既哀黃鳥興，還複白圭詩。',48,'御定全唐詩/json/306.json','["歌玉屢招疑，終朝省複思。既哀黃鳥興，還複白圭詩。", "請益先求友，將行必擇師。誰知不鳴者，獨下董生帷。"]'),
('yuding-6','送陳偃賦得白鳥翔翠微','朱灣','唐','御定全唐诗','yuding','','[]','不知鷗與鶴，天畔弄晴暉。背日分明見，臨川相映微。',48,'御定全唐詩/json/306.json','["不知鷗與鶴，天畔弄晴暉。背日分明見，臨川相映微。", "淨中雲一點，回處雪孤飛。正好南枝住，翩翩何所歸。"]'),
('yuding-7','題段上人院壁畫古松','朱灣','唐','御定全唐诗','yuding','','[]','石上盤古根，謂言天生有。安知草木性，變在畫師手。',68,'御定全唐詩/json/306.json','["石上盤古根，謂言天生有。安知草木性，變在畫師手。", "陰深方丈間，直趣幽且閑。木紋離披勢搓捽，", "莓苔濃淡色不同，一面死皮生蠹蟲。風霜未必來到此，"]'),
('yuding-8','逼寒節寄崔七','朱灣','唐','御定全唐诗','yuding','','[]','閒庭只是長莓苔，三徑曾無車馬來。旅館尚愁寒食火，',40,'御定全唐詩/json/306.json','["閒庭只是長莓苔，三徑曾無車馬來。旅館尚愁寒食火，", "他日趨庭應問禮，須言陋巷有顏回。"]'),
('yuding-9','長安喜雪','朱灣','唐','御定全唐诗','yuding','','[]','千門萬戶雪花浮，點點無聲落瓦溝。全似玉塵消更積，',40,'御定全唐詩/json/306.json','["千門萬戶雪花浮，點點無聲落瓦溝。全似玉塵消更積，", "平地已沾盈尺潤，年豐須荷富人侯。"]'),
('yuding-10','宴楊駙馬山亭','朱灣','唐','御定全唐诗','yuding','','[]','垂楊拂岸草茸茸，繡戶窗前花影重。鱠下玉盤紅縷細，',40,'御定全唐詩/json/306.json','["垂楊拂岸草茸茸，繡戶窗前花影重。鱠下玉盤紅縷細，", "落日泛舟同醉處，回潭百丈映千峰。"]'),
('yuding-11','過宣上人湖上蘭若','朱灣','唐','御定全唐诗','yuding','','[]','十年湖上結幽期，偏向東林遇遠師。未道姓名童子識，',40,'御定全唐詩/json/306.json','["十年湖上結幽期，偏向東林遇遠師。未道姓名童子識，", "問我別來何所得，解將無事當無為。"]'),
('yuding-12','同達奚宰游竇子明仙壇','朱灣','唐','御定全唐诗','yuding','','[]','松檜陰深一徑微，中峰石室到人稀。仙官不住青山在，',40,'御定全唐詩/json/306.json','["松檜陰深一徑微，中峰石室到人稀。仙官不住青山在，", "今朝茂宰尋真處，暫駐雙鳧且莫歸。"]'),
('yuding-13','平陵寓居再逢寒食','朱灣','唐','御定全唐诗','yuding','','[]','幾回江上泣途窮，每遇良辰歎轉蓬。火燧知從新節變，',40,'御定全唐詩/json/306.json','["幾回江上泣途窮，每遇良辰歎轉蓬。火燧知從新節變，", "貧病固應無撓事，但將懷抱醉春風。"]'),
('yuding-14','尋隱者韋九山人於東溪草堂','朱灣','唐','御定全唐诗','yuding','','[]','尋得仙源訪隱淪，漸來深處漸無塵。初行竹裏唯通馬，',40,'御定全唐詩/json/306.json','["尋得仙源訪隱淪，漸來深處漸無塵。初行竹裏唯通馬，", "路傍樵客何須問，朝市如今不是秦。"]'),
('yuding-15','假攝池州留別東溪隱居','朱灣','唐','御定全唐诗','yuding','','[]','一官仍是假，豈願數離群。愁鬢看如雪，浮名認是雲。',48,'御定全唐詩/json/306.json','["一官仍是假，豈願數離群。愁鬢看如雪，浮名認是雲。", "暫辭南國隱，莫勒北山文。今後松溪月，還應夢見君。"]'),
('yuding-16','詠柏板','朱灣','唐','御定全唐诗','yuding','','[]','赴節心長在，從繩道可觀。須知片木用，莫向散材看。',48,'御定全唐詩/json/306.json','["赴節心長在，從繩道可觀。須知片木用，莫向散材看。", "空為歌偏苦，仍愁和即難。既能親掌握，願得接同歡。"]'),
('yuding-17','箏柱子','朱灣','唐','御定全唐诗','yuding','','[]','散木今何幸，良工不棄捐。力微慚一柱，材薄仰群弦。',48,'御定全唐詩/json/306.json','["散木今何幸，良工不棄捐。力微慚一柱，材薄仰群弦。", "且喜聲相應，寧辭跡屢遷。知音如見賞，雅調為君傳。"]'),
('yuding-18','送李司直歸浙東幕兼寄鮑行軍持節大夫初拜東平郡王','朱灣','唐','御定全唐诗','yuding','','[]','翩翩書記早曾聞，二十年來願見君。今日相逢悲白髮，',40,'御定全唐詩/json/306.json','["翩翩書記早曾聞，二十年來願見君。今日相逢悲白髮，", "會作王門曳裾客，為余前謝鮑參軍。"]'),
('yuding-19','七賢廟','朱灣','唐','御定全唐诗','yuding','','[]','常慕晉高士，放心日沈冥。湛然對一壺，土木為我形。',72,'御定全唐詩/json/306.json','["常慕晉高士，放心日沈冥。湛然對一壺，土木為我形。", "下馬訪陳跡，披榛詣荒庭。相看兩不言，猶謂醉未醒。", "長嘯或可擬，幽琴難再聽。同心不共世，空見蘚門青。"]'),
('yuding-20','同清江師月夜聽堅正二上人為懷州轉法華經歌','朱灣','唐','御定全唐诗','yuding','','[]','若耶溪畔雲門僧，夜閑燕坐聽真乘。蓮花秘偈藥草喻，',72,'御定全唐詩/json/306.json','["若耶溪畔雲門僧，夜閑燕坐聽真乘。蓮花秘偈藥草喻，", "前心後心皆此心，梵音妙音柔軟音。清泠霜磬有時動，", "風翻亂葉林有聲，雪映閒庭月無色。玄關密跡難可思，"]'),
('yuding-21','寒城晚角','朱灣','唐','御定全唐诗','yuding','','[]','高臺高高畫角雄，五更初發寒城中。寒城北臨大河水，',116,'御定全唐詩/json/306.json','["高臺高高畫角雄，五更初發寒城中。寒城北臨大河水，", "羈人此夜寐不成，萬里邊情枕上生。乍似隴頭戍，", "忽憶嫖姚北征伐，空山宿兵寒對月。一聲老將起，", "二十年來天下兵，到處不曾無此聲。洛陽陌，長安路。", "角聲朝朝兼暮暮，平居聞之尚難度。何況天山征戍兒，"]'),
('yuding-22','重陽日陪韋卿宴','朱灣','唐','御定全唐诗','yuding','','[]','何必龍山好，南亭賞不暌。清規陳侯事，雅興謝公題。',48,'御定全唐詩/json/306.json','["何必龍山好，南亭賞不暌。清規陳侯事，雅興謝公題。", "入座青峰近，當軒遠樹齊。仙家自有月，莫歎夕陽西。"]'),
('yuding-0','憶長安：四月','丘丹','唐','御定全唐诗','yuding','','[]','憶長安，四月時，南郊萬乘旌旗。嘗酎玉卮更獻，',43,'御定全唐詩/json/307.json','["憶長安，四月時，南郊萬乘旌旗。嘗酎玉卮更獻，", "含桃絲籠交馳。芳草落花無限，金張許史相隨。"]'),
('yuding-1','狀江南：季冬','丘丹','唐','御定全唐诗','yuding','','[]','江南季冬月，紅蟹大如l4。湖水龍為鏡，爐峰氣作煙。',25,'御定全唐詩/json/307.json','["江南季冬月，紅蟹大如l4。湖水龍為鏡，爐峰氣作煙。"]'),
('yuding-2','和韋使君秋夜見寄','丘丹','唐','御定全唐诗','yuding','','[]','露滴梧葉鳴，秋風桂花發。中有學仙侶，吹簫弄山月。',24,'御定全唐詩/json/307.json','["露滴梧葉鳴，秋風桂花發。中有學仙侶，吹簫弄山月。"]'),
('yuding-3','奉酬韋蘇州使君','丘丹','唐','御定全唐诗','yuding','','[]','久作煙霞侶，暫將簪組親。還同褚伯玉，入館忝州人。',24,'御定全唐詩/json/307.json','["久作煙霞侶，暫將簪組親。還同褚伯玉，入館忝州人。"]'),
('yuding-4','和韋使君聽江笛送陳侍禦','丘丹','唐','御定全唐诗','yuding','','[]','離樽聞夜笛，寥亮入寒城。月落車馬散，淒惻主人情。',24,'御定全唐詩/json/307.json','["離樽聞夜笛，寥亮入寒城。月落車馬散，淒惻主人情。"]'),
('yuding-5','奉酬韋使君送歸山之作','丘丹','唐','御定全唐诗','yuding','','[]','側聞郡守至，偶乘黃犢出。不別桃源人，一見經累日。',84,'御定全唐詩/json/307.json','["側聞郡守至，偶乘黃犢出。不別桃源人，一見經累日。", "蟬鳴念秋稼，蘭酌動離瑟。臨水降麾幢，野艇才容膝。", "參差碧山路，目送江帆疾。涉海得驪珠，棲梧慚鳳質。", "愧非鄭公里，歸掃蒙籠室。"]'),
('yuding-6','奉酬重送歸山','丘丹','唐','御定全唐诗','yuding','','[]','賣藥有時至，自知來往疏。遽辭池上酌，新得山中書。',48,'御定全唐詩/json/307.json','["賣藥有時至，自知來往疏。遽辭池上酌，新得山中書。", "步出芙蓉府，歸乘觳觫車。猥蒙招隱作，豈愧班生廬。"]'),
('yuding-7','經湛長史草堂','丘丹','唐','御定全唐诗','yuding','','[]','身退謝名累，道存嘉止足。設醴降華幡，掛冠守空穀。',72,'御定全唐詩/json/307.json','["身退謝名累，道存嘉止足。設醴降華幡，掛冠守空穀。", "偶尋野外寺，仰慕賢者躅。不見昔簪裾，猶有舊松竹。", "煙霞雖異世，風韻如在矚。余即江海上，歸轍青山曲。"]'),
('yuding-8','蕭山祗園寺','丘丹','唐','御定全唐诗','yuding','','[]','東晉許征君，西方彥上人。生時猶定見，悟後了前因。',72,'御定全唐詩/json/307.json','["東晉許征君，西方彥上人。生時猶定見，悟後了前因。", "靈塔多年古，高僧苦行頻。碑存才記日，藤老豈知春。", "車騎歸蕭詧，雲林識許詢。千秋不相見，悟定是吾身。"]'),
('yuding-9','奉使過石門觀瀑','丘丹','唐','御定全唐诗','yuding','','[]','溪上望懸泉，耿耿雲中見。披榛上岩岫，峭壁正東面。',133,'御定全唐詩/json/307.json','["溪上望懸泉，耿耿雲中見。披榛上岩岫，峭壁正東面。", "千仞瀉聯珠，一潭噴飛霰。嵯rU滿山響，坐覺炎氛變。", "照日類虹霓，從風似綃練。靈奇既天造，惜處窮海甸。", "吾祖昔登臨，謝公亦遊衍。王程懼淹泊，下磴空延眷。", "千里雷尚聞，巒回樹蔥蒨。此來共賤役，探討愧前彥。", "永欲洗塵纓，終當愜此願。"]'),
('yuding-10','秋夕宿石門館','丘丹','唐','御定全唐诗','yuding','','[]','暝從石門宿，搖落四岩空。潭月漾山足，天河瀉澗中。',48,'御定全唐詩/json/307.json','["暝從石門宿，搖落四岩空。潭月漾山足，天河瀉澗中。", "杉松寒似雨，猿鳥夕驚風。獨臥不成寢，蒼然想謝公。"]'),
('yuding-11','狀江南：孟夏','賈弇','唐','御定全唐诗','yuding','','[]','江南孟夏天，慈竹筍如編。蜃氣為樓閣，蛙聲作管弦。',24,'御定全唐詩/json/307.json','["江南孟夏天，慈竹筍如編。蜃氣為樓閣，蛙聲作管弦。"]'),
('yuding-12','狀江南：仲秋','沈仲昌','唐','御定全唐诗','yuding','','[]','江南仲秋天，驔鼻大如船。雷是樟亭浪，苔為界石錢。',24,'御定全唐詩/json/307.json','["江南仲秋天，驔鼻大如船。雷是樟亭浪，苔為界石錢。"]'),
('yuding-13','憶長安：正月','謝良輔','唐','御定全唐诗','yuding','','[]','憶長安，正月時，和風喜氣相隨。獻壽彤庭萬國，',43,'御定全唐詩/json/307.json','["憶長安，正月時，和風喜氣相隨。獻壽彤庭萬國，", "燒燈青玉五枝。終南往往殘雪，渭水處處流澌。"]'),
('yuding-14','憶長安：十二月','謝良輔','唐','御定全唐诗','yuding','','[]','憶長安，臘月時，溫泉彩仗新移。瑞氣遙迎鳳輦，',43,'御定全唐詩/json/307.json','["憶長安，臘月時，溫泉彩仗新移。瑞氣遙迎鳳輦，", "日光先暖龍池。取酒蝦蟆陵下，家家守歲傳卮。"]'),
('yuding-15','狀江南：仲春','謝良輔','唐','御定全唐诗','yuding','','[]','江南仲春天，細雨色如煙。絲為武昌柳，布作石門泉。',24,'御定全唐詩/json/307.json','["江南仲春天，細雨色如煙。絲為武昌柳，布作石門泉。"]'),
('yuding-16','狀江南：孟冬','謝良輔','唐','御定全唐诗','yuding','','[]','江南孟冬天，荻穗軟如綿。綠絹芭蕉裂，黃金橘柚懸。',24,'御定全唐詩/json/307.json','["江南孟冬天，荻穗軟如綿。綠絹芭蕉裂，黃金橘柚懸。"]'),
('yuding-17','憶長安：二月','鮑防','唐','御定全唐诗','yuding','','[]','憶長安，二月時，玄鳥初至禖祠。百囀宮鶯繡羽，',43,'御定全唐詩/json/307.json','["憶長安，二月時，玄鳥初至禖祠。百囀宮鶯繡羽，", "千條禦柳黃絲。更有曲江勝地，此來寒食佳期。"]'),
('yuding-18','狀江南：孟春','鮑防','唐','御定全唐诗','yuding','','[]','江南孟春天，荇葉大如錢。白雪裝梅樹，青袍似葑田。',24,'御定全唐詩/json/307.json','["江南孟春天，荇葉大如錢。白雪裝梅樹，青袍似葑田。"]'),
('yuding-19','雜感','鮑防','唐','御定全唐诗','yuding','','[]','漢家海內承平久，萬國戎王皆稽首。天馬常銜苜蓿花，',96,'御定全唐詩/json/307.json','["漢家海內承平久，萬國戎王皆稽首。天馬常銜苜蓿花，", "胡人歲獻葡萄酒。五月荔枝初破顏，朝離象郡夕函關。", "雁飛不到桂陽嶺，馬走先過林邑山。甘泉禦果垂仙閣，", "日暮無人香自落。遠物皆重近皆輕，雞雖有德不如鶴。"]'),
('yuding-20','送薛補闕入朝','鮑防','唐','御定全唐诗','yuding','','[]','平原門下十餘人，獨受恩多未殺身。每歎陸家兄弟少，',64,'御定全唐詩/json/307.json','["平原門下十餘人，獨受恩多未殺身。每歎陸家兄弟少，", "更憐楊氏子孫貧。柴門豈斷施行馬，魯酒那堪醉近臣。", "賴有軍中遺令在，猶將談笑對風塵。"]'),
('yuding-21','人日陪宣州范中丞傳正與范侍御傳真宴東峰亭','鮑防','唐','御定全唐诗','yuding','','[]','人日春風綻早梅，謝家兄弟看花來。吳姬對酒歌千曲，',64,'御定全唐詩/json/307.json','["人日春風綻早梅，謝家兄弟看花來。吳姬對酒歌千曲，", "秦女留人酒百杯。絲柳向空輕婉轉，玉山看日漸裴回。", "流光易去歡難得，莫厭頻頻上此台。"]'),
('yuding-22','上巳寄孟中丞','鮑防','唐','御定全唐诗','yuding','','[]','世間禊事風流處，鏡裏雲山若畫屏。',32,'御定全唐詩/json/307.json','["世間禊事風流處，鏡裏雲山若畫屏。", "今日會稽王內史，好將賓客醉蘭亭。"]'),
('yuding-23','秋暮憶中秋夜與王璠侍禦賞月，因愴遠離聊以奉寄','鮑防','唐','御定全唐诗','yuding','','[]','前月月明夜，美人同遠光。清塵一以間，今夕坐相忘。',36,'御定全唐詩/json/307.json','["前月月明夜，美人同遠光。清塵一以間，今夕坐相忘。", "風落芙蓉露，疑餘繡被香。"]'),
('yuding-24','元日早朝行','鮑防','唐','御定全唐诗','yuding','','[]','幹元發生春為宗，盛德在木鬥建東。東方歲星大明宮，',144,'御定全唐詩/json/307.json','["幹元發生春為宗，盛德在木鬥建東。東方歲星大明宮，", "南山喜氣搖晴空。望雲五等舞萬玉，獻壽一聲出千峰。", "文昌隨彩禮樂正，太平下直旌旗紅。師曠應律調黃鐘，", "王良運策調時龍。玄冥無事歸朔土，青帝放身入朱宮。", "九韶九變五聲裏，四方四友一身中。天何言哉樂無窮，", "廣成彭祖為三公。野臣潛隨擊壤老，日下鼓腹歌可封。"]'),
('yuding-25','憶長安：三月','杜奕','唐','御定全唐诗','yuding','','[]','憶長安，三月時，上苑遍是花枝。青門幾場送客，',43,'御定全唐詩/json/307.json','["憶長安，三月時，上苑遍是花枝。青門幾場送客，", "曲水竟日題詩。駿馬金鞭無數，良辰美景追隨。"]'),
('yuding-26','憶長安：六月','鄭概','唐','御定全唐诗','yuding','','[]','憶長安，六月時，風台水榭逶迤。朱果雕籠香透，',43,'御定全唐詩/json/307.json','["憶長安，六月時，風台水榭逶迤。朱果雕籠香透，", "分明紫禁寒隨。塵驚九衢客散，赭珂滴瀝青驪。"]'),
('yuding-27','狀江南：孟秋','鄭概','唐','御定全唐诗','yuding','','[]','江南孟秋天，稻花白如氈。素腕慚新藕，殘妝妒晚蓮。',24,'御定全唐詩/json/307.json','["江南孟秋天，稻花白如氈。素腕慚新藕，殘妝妒晚蓮。"]'),
('yuding-28','憶長安：七月','陳元初','唐','御定全唐诗','yuding','','[]','憶長安，七月時，槐花點散罘罳。七夕針樓競出，',43,'御定全唐詩/json/307.json','["憶長安，七月時，槐花點散罘罳。七夕針樓競出，", "中元香供初移。繡轂金鞍無限，遊人處處歸遲。"]'),
('yuding-29','憶長安：八月','呂渭','唐','御定全唐诗','yuding','','[]','憶長安，八月時，闕下天高舊儀。衣冠共頒金鏡，',43,'御定全唐詩/json/307.json','["憶長安，八月時，闕下天高舊儀。衣冠共頒金鏡，", "犀象對舞丹墀。更愛終南灞上，可憐秋草碧滋。"]'),
('yuding-30','狀江南：仲冬','呂渭','唐','御定全唐诗','yuding','','[]','江南仲冬天，紫蔗節如鞭。海將鹽作雪，出用火耕田。',24,'御定全唐詩/json/307.json','["江南仲冬天，紫蔗節如鞭。海將鹽作雪，出用火耕田。"]'),
('yuding-31','貞元十一年知貢舉撓閣不能定去留寄詩前主司','呂渭','唐','御定全唐诗','yuding','','[]','獨坐貢闈裏，愁多芳草生。仙翁昨日事，應見此時情。',24,'御定全唐詩/json/307.json','["獨坐貢闈裏，愁多芳草生。仙翁昨日事，應見此時情。"]'),
('yuding-32','皇帝移晦日為中和節','呂渭','唐','御定全唐诗','yuding','','[]','皇心不向晦，改節號中和。淑氣同風景，嘉名別詠歌。',72,'御定全唐詩/json/307.json','["皇心不向晦，改節號中和。淑氣同風景，嘉名別詠歌。", "湔裙移舊俗，賜尺下新科。曆象千年正，酺醵四海多。", "花隨春令發，鴻度歲陽過。天地齊休慶，歡聲欲蕩波。"]'),
('yuding-33','經湛長史草堂','呂渭','唐','御定全唐诗','yuding','','[]','岩居舊風景，人世今成昔。木落古山空，猿啼秋月白。',72,'御定全唐詩/json/307.json','["岩居舊風景，人世今成昔。木落古山空，猿啼秋月白。", "誰同西府僚，幾謝南平客。摧殘松桂老，蕭散煙雲夕。", "跡留異代遠，境入空門寂。惟有草堂僧，陳詩在石壁。"]'),
('yuding-34','憶長安：九月','範燈','唐','御定全唐诗','yuding','','[]','憶長安，九月時，登高望見昆池。上苑初開露菊，',43,'御定全唐詩/json/307.json','["憶長安，九月時，登高望見昆池。上苑初開露菊，", "芳林正獻霜梨。更想千門萬戶，月明砧杵參差。"]'),
('yuding-35','狀江南：季夏','範燈','唐','御定全唐诗','yuding','','[]','江南季夏天，身熱汗如泉。蚊蚋成雷澤，袈裟作水田。',24,'御定全唐詩/json/307.json','["江南季夏天，身熱汗如泉。蚊蚋成雷澤，袈裟作水田。"]'),
('yuding-36','憶長安：十月','樊珣','唐','御定全唐诗','yuding','','[]','憶長安，十月時，華清士馬相馳。萬國來朝漢闕，',43,'御定全唐詩/json/307.json','["憶長安，十月時，華清士馬相馳。萬國來朝漢闕，", "五陵共獵秦祠。晝夜歌鐘不歇，山河四塞京師。"]'),
('yuding-37','狀江南：仲夏','樊珣','唐','御定全唐诗','yuding','','[]','江南仲夏天，時雨下如川。盧橘垂金彈，甘蕉吐白蓮。',24,'御定全唐詩/json/307.json','["江南仲夏天，時雨下如川。盧橘垂金彈，甘蕉吐白蓮。"]'),
('yuding-38','憶長安：十一月','劉蕃','唐','御定全唐诗','yuding','','[]','憶長安，子月時，千官賀至丹墀。御苑雪開瓊樹，',43,'御定全唐詩/json/307.json','["憶長安，子月時，千官賀至丹墀。御苑雪開瓊樹，", "龍堂冰作瑤池。獸炭氈爐正好，貂裘狐白相宜。"]'),
('yuding-39','狀江南：季秋','劉蕃','唐','御定全唐诗','yuding','','[]','江南季秋天，栗熟大如拳。楓葉紅霞舉，蒼蘆白浪川。',24,'御定全唐詩/json/307.json','["江南季秋天，栗熟大如拳。楓葉紅霞舉，蒼蘆白浪川。"]'),
('yuding-0','太寥歌','張志和','唐','御定全唐诗','yuding','','[]','化元靈哉，碧虛清哉，紅霞明哉。冥哉茫哉，',20,'御定全唐詩/json/308.json','["化元靈哉，碧虛清哉，紅霞明哉。冥哉茫哉，"]'),
('yuding-1','空洞歌','張志和','唐','御定全唐诗','yuding','','[]','無自而然，自然之元；無造而化，造化之端。廓然愨然，',25,'御定全唐詩/json/308.json','["無自而然，自然之元；無造而化，造化之端。廓然愨然，"]'),
('yuding-2','漁父歌','張志和','唐','御定全唐诗','yuding','','[]','西塞山前白鷺飛，桃花流水鱖魚肥。青箬笠，綠蓑衣，',120,'御定全唐詩/json/308.json','["西塞山前白鷺飛，桃花流水鱖魚肥。青箬笠，綠蓑衣，", "釣台漁父褐為裘，兩兩三三舴艋舟。能縱棹，慣乘流，", "霅溪灣裏釣漁翁，舴艋為家西複東。江上雪，浦邊風，", "松江蟹舍主人歡，菰飯蓴羹亦共餐。楓葉落，荻花幹，", "青草湖中月正圓，巴陵漁父棹歌連。釣車子，橛頭船，"]'),
('yuding-3','上巳日憶江南禊事','張志和','唐','御定全唐诗','yuding','','[]','黃河西繞郡城流，上巳應無祓禊遊。',32,'御定全唐詩/json/308.json','["黃河西繞郡城流，上巳應無祓禊遊。", "為憶淥江春水色，更隨宵夢向吳洲。"]'),
('yuding-4','漁父','張志和','唐','御定全唐诗','yuding','','[]','八月九月蘆花飛，南溪老人重釣歸。秋山入簾翠滴滴，',40,'御定全唐詩/json/308.json','["八月九月蘆花飛，南溪老人重釣歸。秋山入簾翠滴滴，", "翻嫌四皓曾多事，出為儲皇定是非。"]'),
('yuding-5','和答弟志和漁父歌','張松齡','唐','御定全唐诗','yuding','','[]','樂是風波釣是閑，草堂松徑已勝攀。太湖水，洞庭山，',24,'御定全唐詩/json/308.json','["樂是風波釣是閑，草堂松徑已勝攀。太湖水，洞庭山，"]'),
('yuding-6','歌','陸羽','唐','御定全唐诗','yuding','','[]','不羨黃金罍，不羨白玉杯；不羨朝入省，不羨暮入台；',38,'御定全唐詩/json/308.json','["不羨黃金罍，不羨白玉杯；不羨朝入省，不羨暮入台；", "惟羨西江水，曾向金陵城下來。"]'),
('yuding-7','會稽東小山','陸羽','唐','御定全唐诗','yuding','','[]','月色寒潮入剡溪，青猿叫斷綠林西。',32,'御定全唐詩/json/308.json','["月色寒潮入剡溪，青猿叫斷綠林西。", "昔人已逐東流去，空見年年江草齊。"]'),
('yuding-8','句','陸羽','唐','御定全唐诗','yuding','','[]','辟疆舊林間，怪石紛相向。',36,'御定全唐詩/json/308.json','["辟疆舊林間，怪石紛相向。", "絕澗方險尋，亂岩亦危造。", "瀉從千仞石，寄逐九江船。"]'),
('yuding-0','寒食寄李補闕','郭鄖','唐','御定全唐诗','yuding','','[]','蘭陵士女滿晴川，郊外紛紛拜古埏。萬井閭閻皆禁火，',40,'御定全唐詩/json/309.json','["蘭陵士女滿晴川，郊外紛紛拜古埏。萬井閭閻皆禁火，", "介子終知祿不及，王孫誰肯一相憐。"]'),
('yuding-1','仲月賞花','韋同則','唐','御定全唐诗','yuding','','[]','梅花似雪柳含煙，南地風光臘月前。',32,'御定全唐詩/json/309.json','["梅花似雪柳含煙，南地風光臘月前。", "把酒且須拚卻醉，風流何必待歌筵。"]'),
('yuding-2','西亭暇日書懷十二韻獻上相公','李夷簡','唐','御定全唐诗','yuding','','[]','勝賞不在遠，憮然念玄搜。茲亭有殊致，經始富人侯。',144,'御定全唐詩/json/309.json','["勝賞不在遠，憮然念玄搜。茲亭有殊致，經始富人侯。", "澄澹分沼沚，縈回間林丘。荷香奪芳麝，石溜當鳴球。", "撫俗來康濟，經邦去咨謀。寬明洽時論，惠愛聞甿謳。", "代斫豈容易，守成獲優遊。文翁舊學校，子產昔田疇。", "琬琰富佳什，池台想舊遊。誰言矜改作，曾是日增修。", "憲省忝陪屬，岷峨嗣徽猷。提攜當有路，勿使滯刀州。"]'),
('yuding-3','城南訪裴氏昆季','李約','唐','御定全唐诗','yuding','','[]','相思起中夜，夙駕訪柴荊。早霧桑柘隱，曉光溪澗明。',120,'御定全唐詩/json/309.json','["相思起中夜，夙駕訪柴荊。早霧桑柘隱，曉光溪澗明。", "村蹊蒿棘間，往往斷新耕。貧野煙火微，晝無烏鳶聲。", "田頭逢餉人，道君南山行。南山千里峰，儘是相思情。", "野老無拜揖，村童多裸形。相呼看車馬，顏色喜相驚。", "荒圃雞豚樂，雨牆禾莠生。欲君知我來，壁上空書名。"]'),
('yuding-4','歲日感懷','李約','唐','御定全唐诗','yuding','','[]','曙氣變東風，蟾壺夜漏窮。新春幾人老，舊曆四時空。',48,'御定全唐詩/json/309.json','["曙氣變東風，蟾壺夜漏窮。新春幾人老，舊曆四時空。", "身賤悲添歲，家貧喜過冬。稱觴惟有感，歡慶在兒童。"]'),
('yuding-5','從軍行三首','李約','唐','御定全唐诗','yuding','','[]','看圖閑教陣，畫地靜論邊。烏壘天西戍，鷹姿塞上川。',144,'御定全唐詩/json/309.json','["看圖閑教陣，畫地靜論邊。烏壘天西戍，鷹姿塞上川。", "路長唯算月，書遠每題年。無複生還望，翻思未別前。", "柵壕三面鬥，箭盡舉烽頻。營柳和煙暮，關榆帶雪春。", "邊城多老將，磧路少歸人。殺盡金河卒，年年添塞塵。", "候火起雕城，塵沙擁戰聲。游軍藏漢幟，降騎說蕃情。", "霜落滹沱淺，秋深太白明。嫖姚方虎視，不覺說添兵。"]'),
('yuding-6','贈韋況','李約','唐','御定全唐诗','yuding','','[]','我有心中事，不與韋三說。秋夜洛陽城，明月照張八。',24,'御定全唐詩/json/309.json','["我有心中事，不與韋三說。秋夜洛陽城，明月照張八。"]'),
('yuding-7','觀祈雨','李約','唐','御定全唐诗','yuding','','[]','桑條無葉土生煙，簫管迎龍水廟前。',32,'御定全唐詩/json/309.json','["桑條無葉土生煙，簫管迎龍水廟前。", "朱門幾處看歌舞，猶恐春陰咽管弦。"]'),
('yuding-8','江南春','李約','唐','御定全唐诗','yuding','','[]','池塘春暖水紋開，堤柳垂絲間野梅。',32,'御定全唐詩/json/309.json','["池塘春暖水紋開，堤柳垂絲間野梅。", "江上年年芳意早，蓬瀛春色逐潮來。"]'),
('yuding-9','過華清宮','李約','唐','御定全唐诗','yuding','','[]','君王遊樂萬機輕，一曲霓裳四海兵。',32,'御定全唐詩/json/309.json','["君王遊樂萬機輕，一曲霓裳四海兵。", "玉輦升天人已盡，故宮猶有樹長生。"]'),
('yuding-10','病中宿宜陽館聞雨','李約','唐','御定全唐诗','yuding','','[]','難眠夏夜抵秋賒，簾幔深垂窗燭斜。',32,'御定全唐詩/json/309.json','["難眠夏夜抵秋賒，簾幔深垂窗燭斜。", "風吹桐竹更無雨，白發病人心到家。"]'),
('yuding-0','江南曲','於鵠','唐','御定全唐诗','yuding','','[]','偶向江邊采白蘋，還隨女伴賽江神。',32,'御定全唐詩/json/310.json','["偶向江邊采白蘋，還隨女伴賽江神。", "眾中不敢分明語，暗擲金錢蔔遠人。"]'),
('yuding-1','山中寄樊僕射','於鵠','唐','御定全唐诗','yuding','','[]','卻憶東溪日，同年事魯儒。僧房閑共宿，酒肆醉相扶。',48,'御定全唐詩/json/310.json','["卻憶東溪日，同年事魯儒。僧房閑共宿，酒肆醉相扶。", "天畔雙旌貴，山中病客孤。無謀還有計，春谷種桑榆。"]'),
('yuding-2','題宇文裔山寺讀書院','於鵠','唐','御定全唐诗','yuding','','[]','讀書林下寺，不出動經年。草閣連僧院，山廚共石泉。',48,'御定全唐詩/json/310.json','["讀書林下寺，不出動經年。草閣連僧院，山廚共石泉。", "雲庭無履跡，龕壁有燈煙。年少今頭白，刪詩到幾篇。"]'),
('yuding-3','贈蘭若僧','於鵠','唐','御定全唐诗','yuding','','[]','一身禪誦苦，灑掃古花宮。靜室門常閉，深蘿月不通。',48,'御定全唐詩/json/310.json','["一身禪誦苦，灑掃古花宮。靜室門常閉，深蘿月不通。", "懸燈喬木上，鳴磬亂幡中。附入高僧傳，長稱二遠公。"]'),
('yuding-4','題鄰居','于鵠','唐','御定全唐诗','yuding','','[]','僻巷鄰家少，茅簷喜並居。蒸梨常共灶，澆薤亦同渠。',48,'御定全唐詩/json/310.json','["僻巷鄰家少，茅簷喜並居。蒸梨常共灶，澆薤亦同渠。", "傳屐朝尋藥，分燈夜讀書。雖然在城市，還得似樵漁。"]'),
('yuding-5','山中自述','於鵠','唐','御定全唐诗','yuding','','[]','三十無名客，空山獨臥秋。病多知藥性，年長信人愁。',48,'御定全唐詩/json/310.json','["三十無名客，空山獨臥秋。病多知藥性，年長信人愁。", "螢影竹窗下，松聲茅屋頭。近來心更靜，不夢世間遊。"]'),
('yuding-6','山中寄韋鉦','於鵠','唐','御定全唐诗','yuding','','[]','懶成身病日，因醉臥多時。送客出溪少，讀書終卷遲。',48,'御定全唐詩/json/310.json','["懶成身病日，因醉臥多時。送客出溪少，讀書終卷遲。", "幽窗聞墜葉，晴景見遊絲。早晚來收藥，門前有紫芝。"]'),
('yuding-7','南溪書齋','於鵠','唐','御定全唐诗','yuding','','[]','茅屋往來久，山深不置門。草生垂井口，花落擁籬根。',48,'御定全唐詩/json/310.json','["茅屋往來久，山深不置門。草生垂井口，花落擁籬根。", "入院將雛鳥，尋蘿抱子猿。曾逢異人說，風景似桃源。"]'),
('yuding-8','夜會李太守宅','於鵠','唐','御定全唐诗','yuding','','[]','郡齋常夜掃，不臥獨吟詩。把燭近幽客，升堂戴接z5。',49,'御定全唐詩/json/310.json','["郡齋常夜掃，不臥獨吟詩。把燭近幽客，升堂戴接z5。", "微風吹凍葉，餘雪落寒枝。明日逢山伴，須令隱者知。"]'),
('yuding-9','題柏臺山僧','於鵠','唐','御定全唐诗','yuding','','[]','上方唯一室，禪定對山容。行道臨孤壁，持齋聽遠鐘。',48,'御定全唐詩/json/310.json','["上方唯一室，禪定對山容。行道臨孤壁，持齋聽遠鐘。", "枯藤離舊樹，朽石落高峰。不向雲間見，還應夢裏逢。"]'),
('yuding-10','寄續尊師','於鵠','唐','御定全唐诗','yuding','','[]','得道任發白，亦逢城市遊。新經天上取，稀藥洞中收。',48,'御定全唐詩/json/310.json','["得道任發白，亦逢城市遊。新經天上取，稀藥洞中收。", "春木帶枯葉，新蒲生漫流。年年望靈鶴，常在此山頭。"]'),
('yuding-11','題南峰褚道士','于鵠','唐','御定全唐诗','yuding','','[]','得道南山久，曾教四皓棋。閉門醫病鶴，倒篋養神龜。',48,'御定全唐詩/json/310.json','["得道南山久，曾教四皓棋。閉門醫病鶴，倒篋養神龜。", "松際風長在，泉中草不衰。誰知茅屋裏，有路向峨嵋。"]'),
('yuding-12','贈不食姑','于鵠','唐','御定全唐诗','yuding','','[]','不食非關藥，天生是女仙。見人還起拜，留伴亦開田。',48,'御定全唐詩/json/310.json','["不食非關藥，天生是女仙。見人還起拜，留伴亦開田。", "無窟尋溪宿，兼衣掃葉眠。不知何代女，猶帶剪刀錢。"]'),
('yuding-13','送李明府歸別業','於鵠','唐','御定全唐诗','yuding','','[]','寄家丹水邊，歸去種春田。白髮無知己，空山又一年。',48,'御定全唐詩/json/310.json','["寄家丹水邊，歸去種春田。白髮無知己，空山又一年。", "鹿裘長酒氣，茅屋有茶煙。亦擬辭人世，何溪有瀑泉。"]'),
('yuding-14','題樹下禪師','于鵠','唐','御定全唐诗','yuding','','[]','久行多不定，樹下是禪床。寂寂心無住，年年日自長。',48,'御定全唐詩/json/310.json','["久行多不定，樹下是禪床。寂寂心無住，年年日自長。", "蟲蛇同宿澗，草木共經霜。已見南人說，天臺有舊房。"]'),
('yuding-15','宿王尊師隱居','於鵠','唐','御定全唐诗','yuding','','[]','夜愛雲林好，寒天月裏行。青牛眠樹影，白犬吠猿聲。',48,'御定全唐詩/json/310.json','["夜愛雲林好，寒天月裏行。青牛眠樹影，白犬吠猿聲。", "一磬山院靜，千燈溪路明。從來此峰客，幾個得長生。"]'),
('yuding-16','題服柏先生','于鵠','唐','御定全唐诗','yuding','','[]','服柏不飛煉，閑眠閉草堂。有泉唯盥漱，留火為焚香。',48,'御定全唐詩/json/310.json','["服柏不飛煉，閑眠閉草堂。有泉唯盥漱，留火為焚香。", "新雨閑門靜，孤松滿院涼。仍聞枕中術，曾授漢淮王。"]'),
('yuding-17','哭淩霄山光上人','於鵠','唐','御定全唐诗','yuding','','[]','身沒碧峰裏，門人改葬期。買山尋主遠，壘塔化人遲。',48,'御定全唐詩/json/310.json','["身沒碧峰裏，門人改葬期。買山尋主遠，壘塔化人遲。", "鬼火穿空院，秋螢入素帷。黃昏溪路上，聞哭竺幹師。"]'),
('yuding-18','途中寄楊涉','於鵠','唐','御定全唐诗','yuding','','[]','蕭蕭盧荻晚，一徑入荒陂。日色雲收處，蛙聲雨歇時。',49,'御定全唐詩/json/310.json','["蕭蕭盧荻晚，一徑入荒陂。日色雲收處，蛙聲雨歇時。", "前村見來久，羸馬自行遲。聞作王門客，應閑白接z5。"]'),
('yuding-19','送韋判官歸薊門','于鵠','唐','御定全唐诗','yuding','','[]','桑幹歸路遠，聞說亦愁人。有雪常經夏，無花空到春。',48,'御定全唐詩/json/310.json','["桑幹歸路遠，聞說亦愁人。有雪常經夏，無花空到春。", "下營雲外火，收馬月中塵。白首從戎客，青衫未離身。"]'),
('yuding-20','出塞','於鵠','唐','御定全唐诗','yuding','','[]','蔥嶺秋塵起，全軍取月支。山川引行陣，蕃漢列旌旗。',144,'御定全唐詩/json/310.json','["蔥嶺秋塵起，全軍取月支。山川引行陣，蕃漢列旌旗。", "轉戰疲兵少，孤城外救遲。邊人逢聖代，不見偃戈時。", "微雪軍將出，吹笳天未明。觀兵登古戍，斬將對雙旌。", "分陣瞻山勢，潛兵制馬鳴。如今青史上，已有滅胡名。", "單于驕愛獵，放火到軍城。乘月調新馬，防秋置遠營。", "空山朱戟影，寒磧鐵衣聲。度水逢胡說，沙陰有伏兵。"]'),
('yuding-21','贈李太守','于鵠','唐','御定全唐诗','yuding','','[]','幾年為郡守，家似布衣貧。沽酒迎幽客，無金與近臣。',48,'御定全唐詩/json/310.json','["幾年為郡守，家似布衣貧。沽酒迎幽客，無金與近臣。", "搗茶書院靜，講易藥堂春。歸闕功成後，隨車有野人。"]'),
('yuding-22','送張司直入單于','於鵠','唐','御定全唐诗','yuding','','[]','若過並州北，誰人不憶家。寒深無伴侶，路盡有平沙。',48,'御定全唐詩/json/310.json','["若過並州北，誰人不憶家。寒深無伴侶，路盡有平沙。", "磧冷唯逢雁，天春不見花。莫隨征將意，垂老事輕車。"]'),
('yuding-23','惜花','於鵠','唐','御定全唐诗','yuding','','[]','夜來花欲盡，始惜兩三枝。早起尋稀處，閑眠記落時。',48,'御定全唐詩/json/310.json','["夜來花欲盡，始惜兩三枝。早起尋稀處，閑眠記落時。", "蕊焦蜂自散，蒂折蝶還移。攀著殷勤別，明年更有期。"]'),
('yuding-24','春山居','於鵠','唐','御定全唐诗','yuding','','[]','獨來多任性，惟與白雲期。深處花開盡，遲眠人不知。',48,'御定全唐詩/json/310.json','["獨來多任性，惟與白雲期。深處花開盡，遲眠人不知。", "水流山暗處，風起月明時。望見南峰近，年年懶更移。"]'),
('yuding-25','遊瀑泉寺','於鵠','唐','御定全唐诗','yuding','','[]','日夕尋未遍，古木寺高低。粉壁猶遮嶺，朱樓尚隔溪。',48,'御定全唐詩/json/310.json','["日夕尋未遍，古木寺高低。粉壁猶遮嶺，朱樓尚隔溪。", "廚窗通澗鼠，殿跡立山雞。更有無人處，明朝獨向西。"]'),
('yuding-26','送宮人入道歸山','於鵠','唐','御定全唐诗','yuding','','[]','十歲吹簫入漢宮，看修水殿種芙蓉。自傷白髮辭金屋，',40,'御定全唐詩/json/310.json','["十歲吹簫入漢宮，看修水殿種芙蓉。自傷白髮辭金屋，", "定知別後宮中伴，應聽緱山半夜鐘。"]');
